-- Poems batch 452
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-80','赴連州途經洛陽諸公置酒相送張員外賈以詩見贈率爾酬之','劉禹錫','唐','御定全唐诗','yuding','','[]','謫在三湘最遠州，邊鴻不到水南流。',32,'御定全唐詩/json/365.json','["謫在三湘最遠州，邊鴻不到水南流。", "如今暫寄樽前笑，明日辭君步步愁。"]'),
('yuding-81','贈元九侍禦文石枕以詩獎之','劉禹錫','唐','御定全唐诗','yuding','','[]','文章似錦氣如虹，宜薦華簪綠殿中。',32,'御定全唐詩/json/365.json','["文章似錦氣如虹，宜薦華簪綠殿中。", "縱使涼飆生旦夕，猶堪拂拭愈頭風。"]'),
('yuding-82','酬元九院長自江陵見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','無事尋花至仙境，等閒栽樹比封君。',32,'御定全唐詩/json/365.json','["無事尋花至仙境，等閒栽樹比封君。", "金門通籍真多士，黃紙除書每日聞。"]'),
('yuding-83','酬楊侍郎憑見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','翔鸞闕底謝皇恩，纓上滄浪舊水痕。',32,'御定全唐詩/json/365.json','["翔鸞闕底謝皇恩，纓上滄浪舊水痕。", "疏傅揮金忽相憶，遠擎長句與招魂。"]'),
('yuding-84','酬馬大夫登洭口戍見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','新辭將印拂朝纓，臨水登山四體輕。',32,'御定全唐詩/json/365.json','["新辭將印拂朝纓，臨水登山四體輕。", "猶念天涯未歸客，瘴雲深處守孤城。"]'),
('yuding-85','答楊八敬之絕句','劉禹錫','唐','御定全唐诗','yuding','','[]','飽霜孤竹聲偏切，帶火焦桐韻本悲。',32,'御定全唐詩/json/365.json','["飽霜孤竹聲偏切，帶火焦桐韻本悲。", "今日知音一留聽，是君心事不平時。"]'),
('yuding-86','重寄表臣二首','劉禹錫','唐','御定全唐诗','yuding','','[]','對酒臨流奈別何，君今已醉我蹉跎。',64,'御定全唐詩/json/365.json','["對酒臨流奈別何，君今已醉我蹉跎。", "分明記取星星鬢，他日相逢應更多。", "世間人事有何窮，過後思量儘是空。", "早晚同歸洛陽陌，卜鄰須近祝雞翁。"]'),
('yuding-87','重寄絕句','劉禹錫','唐','御定全唐诗','yuding','','[]','淮西既是平安地，鴉路今無羽檄飛。',32,'御定全唐詩/json/365.json','["淮西既是平安地，鴉路今無羽檄飛。", "聞道唐州最清靜，戰場耕盡野花稀。"]'),
('yuding-88','酬楊八副使將赴湖南途中見寄一絕','劉禹錫','唐','御定全唐诗','yuding','','[]','知逐征南冠楚材，遠勞書信到陽臺。',32,'御定全唐詩/json/365.json','["知逐征南冠楚材，遠勞書信到陽臺。", "明朝若上君山上，一道巴江自此來。"]'),
('yuding-89','遙和韓睦州元相公二君子','劉禹錫','唐','御定全唐诗','yuding','','[]','玉人紫綬相輝映，卻要霜須一兩莖。',32,'御定全唐詩/json/365.json','["玉人紫綬相輝映，卻要霜須一兩莖。", "其奈無成空老去，每臨明鏡若為情。"]'),
('yuding-90','吳興敬郎中見惠斑竹杖兼示一絕聊以謝之','劉禹錫','唐','御定全唐诗','yuding','','[]','一莖炯炯琅玕色，數節重重玳瑁文。',32,'御定全唐詩/json/365.json','["一莖炯炯琅玕色，數節重重玳瑁文。", "拄到高山未登處，青雲路上願逢君。"]'),
('yuding-91','奉和裴令公夜宴','劉禹錫','唐','御定全唐诗','yuding','','[]','天下蒼生望不休，東山雖有但時遊。',32,'御定全唐詩/json/365.json','["天下蒼生望不休，東山雖有但時遊。", "從來海上仙桃樹，肯逐人間風露秋。"]'),
('yuding-92','秋夜安國觀聞笙','劉禹錫','唐','御定全唐诗','yuding','','[]','織女分明銀漢秋，桂枝梧葉共颼飀。月露滿庭人寂寂，霓裳一曲在高樓。',32,'御定全唐詩/json/365.json','["織女分明銀漢秋，桂枝梧葉共颼飀。月露滿庭人寂寂，霓裳一曲在高樓。"]'),
('yuding-93','酬僕射牛相公晉國池上別後至甘棠館忽夢同遊因成口號見寄','劉禹錫','唐','御定全唐诗','yuding','','[]','已嗟池上別魂驚，忽報夢中攜手行。',32,'御定全唐詩/json/365.json','["已嗟池上別魂驚，忽報夢中攜手行。", "此夜獨歸還乞夢，老人無睡到天明。"]'),
('yuding-94','裴侍郎大尹雪中遺酒一壺兼示喜眼疾平一絕有閒行把酒之句斐然仰酬','劉禹錫','唐','御定全唐诗','yuding','','[]','卷盡輕雲月更明，金篦不用且閑行。',32,'御定全唐詩/json/365.json','["卷盡輕雲月更明，金篦不用且閑行。", "若傾家釀招來客，何必池塘春草生。"]'),
('yuding-95','和滑州李尚書上巳憶江南禊事','劉禹錫','唐','御定全唐诗','yuding','','[]','白馬津頭春日遲，沙州歸雁拂旌旗。',32,'御定全唐詩/json/365.json','["白馬津頭春日遲，沙州歸雁拂旌旗。", "柳營唯有軍中戲，不似江南三月時。"]'),
('yuding-96','酬柳柳州家雞之贈','劉禹錫','唐','御定全唐诗','yuding','','[]','日日臨池弄小雛，還思寫論付官奴。',32,'御定全唐詩/json/365.json','["日日臨池弄小雛，還思寫論付官奴。", "柳家新樣元和腳，且盡薑芽斂手徒。"]'),
('yuding-97','答前篇','劉禹錫','唐','御定全唐诗','yuding','','[]','小兒弄筆不能嗔，涴壁書窗且當勤。',32,'御定全唐詩/json/365.json','["小兒弄筆不能嗔，涴壁書窗且當勤。", "聞彼夢熊猶未兆，女中誰是衛夫人。"]'),
('yuding-98','答後篇','劉禹錫','唐','御定全唐诗','yuding','','[]','昔日慵工記姓名，遠勞辛苦寫西京。',32,'御定全唐詩/json/365.json','["昔日慵工記姓名，遠勞辛苦寫西京。", "近來漸有臨池興，為報元常欲抗行。"]'),
('yuding-99','重答柳柳州','劉禹錫','唐','御定全唐诗','yuding','','[]','弱冠同懷長者憂，臨岐回想盡悠悠。',32,'御定全唐詩/json/365.json','["弱冠同懷長者憂，臨岐回想盡悠悠。", "耦耕若便遺身老，黃發相看萬事休。"]'),
('yuding-100','登清暉樓','劉禹錫','唐','御定全唐诗','yuding','','[]','潯陽江色潮添滿，彭蠡秋聲雁送來。',32,'御定全唐詩/json/365.json','["潯陽江色潮添滿，彭蠡秋聲雁送來。", "南望廬山千萬仞，共誇新出棟樑材。"]'),
('yuding-101','赴和州于武昌縣再遇毛仙翁十八兄因成一絕','劉禹錫','唐','御定全唐诗','yuding','','[]','武昌山下蜀江東，重向仙舟見葛洪。',32,'御定全唐詩/json/365.json','["武昌山下蜀江東，重向仙舟見葛洪。", "又得案前親禮拜，大羅天訣玉函封。"]'),
('yuding-102','寄毗陵楊給事三首','劉禹錫','唐','御定全唐诗','yuding','','[]','揮毫起制來東省，躡足修名謁外台。',96,'御定全唐詩/json/365.json','["揮毫起制來東省，躡足修名謁外台。", "好著櫜鞬莫惆悵，出文入武是全才。", "曾主魚書輕刺史，今朝自請左魚來。", "青雲直上無多地，卻要斜飛取勢回。", "東城南陌昔同遊，坐上無人第二流。", "屈指如今已零落，且須歡喜作鄰州。"]'),
('yuding-103','陪崔大尚書及諸閣老宴杏園','劉禹錫','唐','御定全唐诗','yuding','','[]','更將何面上春台，百事無成老又催。',32,'御定全唐詩/json/365.json','["更將何面上春台，百事無成老又催。", "唯有落花無俗態，不嫌憔悴滿頭來。"]'),
('yuding-104','曹剛','劉禹錫','唐','御定全唐诗','yuding','','[]','大弦嘈囋小弦清，噴雪含風意思生。',32,'御定全唐詩/json/365.json','["大弦嘈囋小弦清，噴雪含風意思生。", "一聽曹剛彈薄媚，人生不合出京城。"]'),
('yuding-105','寄湖州韓中丞','劉禹錫','唐','御定全唐诗','yuding','','[]','老郎日日憂蒼鬢，遠守年年厭白蘋。終日相思不相見，長頻相見是何人。',32,'御定全唐詩/json/365.json','["老郎日日憂蒼鬢，遠守年年厭白蘋。終日相思不相見，長頻相見是何人。"]'),
('yuding-106','楊柳枝','劉禹錫','唐','御定全唐诗','yuding','','[]','楊子江頭煙景迷，隋家宮樹拂金堤。',32,'御定全唐詩/json/365.json','["楊子江頭煙景迷，隋家宮樹拂金堤。", "嵯峨猶有當時色，半蘸波中水鳥棲。"]'),
('yuding-107','田順郎歌','劉禹錫','唐','御定全唐诗','yuding','','[]','清歌不是世間音，玉殿嘗聞稱主心。',32,'御定全唐詩/json/365.json','["清歌不是世間音，玉殿嘗聞稱主心。", "唯有順郎全學得，一聲飛出九重深。"]'),
('yuding-108','夜聞商人船中箏','劉禹錫','唐','御定全唐诗','yuding','','[]','大艑高帆一百尺，新聲促柱十三弦。',32,'御定全唐詩/json/365.json','["大艑高帆一百尺，新聲促柱十三弦。", "揚州市里商人女，來占江西明月天。"]'),
('yuding-109','聞道士彈思歸引','劉禹錫','唐','御定全唐诗','yuding','','[]','仙公一奏思歸引，逐客初聞自泫然。',32,'御定全唐詩/json/365.json','["仙公一奏思歸引，逐客初聞自泫然。", "莫怪殷勤悲此曲，越聲長苦已三年。"]'),
('yuding-110','喜康將軍見訪','劉禹錫','唐','御定全唐诗','yuding','','[]','謫居愁寂似幽棲，百草當門茅舍低。',32,'御定全唐詩/json/365.json','["謫居愁寂似幽棲，百草當門茅舍低。", "夜獵將軍忽相訪，鷓鴣驚起繞籬啼。"]'),
('yuding-111','贈劉景擢第','劉禹錫','唐','御定全唐诗','yuding','','[]','湘中才子是劉郎，望在長沙住桂陽。',32,'御定全唐詩/json/365.json','["湘中才子是劉郎，望在長沙住桂陽。", "昨日鴻都新上第，五陵年少讓清光。"]'),
('yuding-112','赴連山途次德宗山陵寄張員外','劉禹錫','唐','御定全唐诗','yuding','','[]','常時並冕奉天顏，委佩低簪彩仗間。',32,'御定全唐詩/json/365.json','["常時並冕奉天顏，委佩低簪彩仗間。", "今日獨來張樂地，萬重雲水望橋山。"]'),
('yuding-113','嘗茶','劉禹錫','唐','御定全唐诗','yuding','','[]','生拍芳叢鷹觜芽，老郎封寄謫仙家。',32,'御定全唐詩/json/365.json','["生拍芳叢鷹觜芽，老郎封寄謫仙家。", "今宵更有湘江月，照出菲菲滿碗花。"]'),
('yuding-114','梁國祠','劉禹錫','唐','御定全唐诗','yuding','','[]','梁國三郎威德尊，女巫簫鼓走鄉村。',32,'御定全唐詩/json/365.json','["梁國三郎威德尊，女巫簫鼓走鄉村。", "萬家長見空山上，雨氣蒼茫生廟門。"]'),
('yuding-115','望洞庭','劉禹錫','唐','御定全唐诗','yuding','','[]','湖光秋月兩相和，潭面無風鏡未磨。',32,'御定全唐詩/json/365.json','["湖光秋月兩相和，潭面無風鏡未磨。", "遙望洞庭山水翠，白銀盤裏一青螺。"]'),
('yuding-116','楊柳枝','劉禹錫','唐','御定全唐诗','yuding','','[]','春江一曲柳千條，二十年前舊板橋。',32,'御定全唐詩/json/365.json','["春江一曲柳千條，二十年前舊板橋。", "曾與美人橋上別，恨無消息到今朝。"]'),
('yuding-117','樓上','劉禹錫','唐','御定全唐诗','yuding','','[]','江上樓高二十梯，梯梯登遍與雲齊。',32,'御定全唐詩/json/365.json','["江上樓高二十梯，梯梯登遍與雲齊。", "人從別浦經年去，天向平蕪盡處低。"]'),
('yuding-118','洛濱病臥戶部李侍郎見惠藥物謔以文星之句斐然仰謝','劉禹錫','唐','御定全唐诗','yuding','','[]','隱幾支頤對落暉，故人書信到柴扉。',32,'御定全唐詩/json/365.json','["隱幾支頤對落暉，故人書信到柴扉。", "周南留滯商山老，星象如今屬少微。"]'),
('yuding-119','故洛城古牆','劉禹錫','唐','御定全唐诗','yuding','','[]','粉落椒飛知幾春，風吹雨灑旋成塵。',32,'御定全唐詩/json/365.json','["粉落椒飛知幾春，風吹雨灑旋成塵。", "莫言一片危基在，猶過無窮來往人。"]'),
('yuding-120','句','劉禹錫','唐','御定全唐诗','yuding','','[]','湖上收宿雨。',49,'御定全唐詩/json/365.json','["湖上收宿雨。", "故國思如此，若為天外心。", "東屯滄海闊，南讓洞庭寬。", "翠粒照晴露。。", "銀花垂院榜，翠羽撼絛鈴。"]'),
('yuding-0','山亭懷古','張弘靖','唐','御定全唐诗','yuding','','[]','叢石依古城，懸泉灑清池。高低袤丈內，衡霍相蔽虧。',48,'御定全唐詩/json/366.json','["叢石依古城，懸泉灑清池。高低袤丈內，衡霍相蔽虧。", "歸田竟何因，為郡豈所宜。誰能辨人野，寄適聊在斯。"]'),
('yuding-1','和張相公太原山亭懷古詩','韓察','唐','御定全唐诗','yuding','','[]','公府政多暇，思與仁智全。為山想岩穴，引水聽潺湲。',48,'御定全唐詩/json/366.json','["公府政多暇，思與仁智全。為山想岩穴，引水聽潺湲。", "軒冕跡自逸，塵俗無由牽。蒼生方矚望，詎得賦歸田。"]'),
('yuding-2','和張相公太原山亭懷古詩','崔恭','唐','御定全唐诗','yuding','','[]','高情樂閑放，寄跡山水中。朝霞鋪座右，虛白貯清風。',48,'御定全唐詩/json/366.json','["高情樂閑放，寄跡山水中。朝霞鋪座右，虛白貯清風。", "潛竇激飛泉，石路躋且崇。步武有勝概，不與俗情同。"]'),
('yuding-3','和張相公太原山亭懷古詩','陸瀍','唐','御定全唐诗','yuding','','[]','激水瀉飛瀑，寄懷良在茲。如何謝安石，要結東山期。',48,'御定全唐詩/json/366.json','["激水瀉飛瀑，寄懷良在茲。如何謝安石，要結東山期。", "入座蘭蕙馥，當軒松桂滋。於焉悟幽道，境寂心自怡。"]'),
('yuding-4','和張相公太原亭懷古詩','胡證','唐','御定全唐诗','yuding','','[]','飛泉天臺狀，峭石蓬萊姿。潺湲與青翠，咫尺當幽奇。',48,'御定全唐詩/json/366.json','["飛泉天臺狀，峭石蓬萊姿。潺湲與青翠，咫尺當幽奇。", "居然盡精道，得以書妍詞。豈無他山勝，懿此清軒墀。"]'),
('yuding-5','句','胡證','唐','御定全唐诗','yuding','','[]','詩書入京國，旌旆過鄉關。（《因話錄》雲：證拜振武節',47,'御定全唐詩/json/366.json','["詩書入京國，旌旆過鄉關。（《因話錄》雲：證拜振武節", "度使，道河中。時趙宗儒為帥，證備桑梓禮入謁，"]'),
('yuding-6','和太原山亭懷古詩','張賈','唐','御定全唐诗','yuding','','[]','中庭起崖谷，漱玉下漣漪。丹丘誰雲遠，寓象得心期。',48,'御定全唐詩/json/366.json','["中庭起崖谷，漱玉下漣漪。丹丘誰雲遠，寓象得心期。", "豈不貴鐘鼎，至懷在希夷。唯當蓬萊閣，靈鳳複來儀。"]'),
('yuding-7','和裴司空答張秘書贈馬詩','張賈','唐','御定全唐诗','yuding','','[]','閣下從容舊客卿，寄來駿馬賞高情。任追煙景騎仍醉，',40,'御定全唐詩/json/366.json','["閣下從容舊客卿，寄來駿馬賞高情。任追煙景騎仍醉，", "須知上宰吹噓意，送入天門上路行。"]'),
('yuding-8','句','張賈','唐','御定全唐诗','yuding','','[]','夫子生知者，相期妙理中。。',13,'御定全唐詩/json/366.json','["夫子生知者，相期妙理中。。"]'),
('yuding-9','吳興三絕','張文規','唐','御定全唐诗','yuding','','[]','蘋洲須覺池沼俗，苧布直勝羅紈輕。清風樓下草初出，',24,'御定全唐詩/json/366.json','["蘋洲須覺池沼俗，苧布直勝羅紈輕。清風樓下草初出，"]'),
('yuding-10','湖州貢焙新茶','張文規','唐','御定全唐诗','yuding','','[]','鳳輦尋春半醉回，仙娥進水禦簾開。',32,'御定全唐詩/json/366.json','["鳳輦尋春半醉回，仙娥進水禦簾開。", "牡丹花笑金鈿動，傳奏吳興紫筍來。"]'),
('yuding-11','句','張文規','唐','御定全唐诗','yuding','','[]','誰雲隼旟吏，長對虎頭岩。。',13,'御定全唐詩/json/366.json','["誰雲隼旟吏，長對虎頭岩。。"]'),
('yuding-0','緱山鶴','張仲素','唐','御定全唐诗','yuding','','[]','羽客驂仙鶴，將飛駐碧山。映松殘雪在，度嶺片雲還。',72,'御定全唐詩/json/367.json','["羽客驂仙鶴，將飛駐碧山。映松殘雪在，度嶺片雲還。", "清唳因風遠，高姿對水閑。笙歌憶天上，城郭歎人間。", "幾變霜毛潔，方殊藻質斑。迢迢煙路逸，奮翮詎能攀。"]'),
('yuding-1','夜聞洛濱吹笙','張仲素','唐','御定全唐诗','yuding','','[]','王子千年後，笙音五夜聞。逶迤繞清洛，斷續下仙雲。',72,'御定全唐詩/json/367.json','["王子千年後，笙音五夜聞。逶迤繞清洛，斷續下仙雲。", "泄泄飄難定，啾啾曲未分。松風助幽律，波月動輕文。", "鳳管聽何遠，鸞聲若在群。暗空思羽蓋，餘氣自氛氳。"]'),
('yuding-2','上元日聽太清宮步虛','張仲素','唐','御定全唐诗','yuding','','[]','仙客開金籙，元辰會玉京。靈歌賓紫府，雅韻出層城。',72,'御定全唐詩/json/367.json','["仙客開金籙，元辰會玉京。靈歌賓紫府，雅韻出層城。", "磬雜音徐徹，風飄響更清。紆餘空外盡，斷續聽中生。", "舞鶴紛將集，流雲住未行。誰知九陌上，塵俗仰遺聲。"]'),
('yuding-3','玉繩低建章','張仲素','唐','御定全唐诗','yuding','','[]','迢迢玉繩下，芒彩正闌幹。稍複臨鳷鵲，方疑近露寒。',72,'御定全唐詩/json/367.json','["迢迢玉繩下，芒彩正闌幹。稍複臨鳷鵲，方疑近露寒。", "微明連粉堞，的皪映仙盤。橫接河流照，低將夜色殘。", "天榆隨影沒，宮樹與光攢。遐想西垣客，長吟欲罷難。"]'),
('yuding-4','寒雲輕重色','張仲素','唐','御定全唐诗','yuding','','[]','佳期當可許，托思望雲端。鱗影朝猶落，繁陰暮自寒。',72,'御定全唐詩/json/367.json','["佳期當可許，托思望雲端。鱗影朝猶落，繁陰暮自寒。", "因風方嫋嫋，間石已漫漫。隱映看鴻度，霏微覺樹攢。", "凝空多似黛，引素乍如紈。每向愁中覽，含毫欲狀難。"]'),
('yuding-5','聖明樂','張仲素','唐','御定全唐诗','yuding','','[]','九陌祥煙合，千春瑞月明。宮花將苑柳，先發鳳凰城。',24,'御定全唐詩/json/367.json','["九陌祥煙合，千春瑞月明。宮花將苑柳，先發鳳凰城。"]'),
('yuding-6','獻壽詞','張仲素','唐','御定全唐诗','yuding','','[]','玉帛殊方至，歌鐘比屋聞。華夷今一貫，同賀聖朝君。',24,'御定全唐詩/json/367.json','["玉帛殊方至，歌鐘比屋聞。華夷今一貫，同賀聖朝君。"]'),
('yuding-7','宮中樂五首','張仲素','唐','御定全唐诗','yuding','','[]','網戶交如綺，紗窗薄似煙。樂吹天上曲，人是月中仙。',120,'御定全唐詩/json/367.json','["網戶交如綺，紗窗薄似煙。樂吹天上曲，人是月中仙。", "翠匣開寒鏡，珠釵掛步搖。妝成隻畏曉，更漏促春宵。", "紅果瑤池實，金盤露井冰。甘泉將避暑，台殿曉光凝。", "月采浮鸞殿，砧聲隔鳳樓。笙歌臨水檻，紅燭乍迎秋。", "奇樹留寒翠，神池結夕波。黃山一夜雪，渭水瀉聲多。"]'),
('yuding-8','春遊曲三首','張仲素','唐','御定全唐诗','yuding','','[]','煙柳飛輕絮，風榆落小錢。濛濛百花裏，羅綺競秋千。',72,'御定全唐詩/json/367.json','["煙柳飛輕絮，風榆落小錢。濛濛百花裏，羅綺競秋千。", "騁望登香閣，爭高下砌台。林間踏青去，席上寄箋來。", "行樂三春節，林花百和香。當年重意氣，先占鬥雞場。"]'),
('yuding-9','春閨思','張仲素','唐','御定全唐诗','yuding','','[]','嫋嫋城邊柳，青青陌上桑。提籠忘采葉，昨夜夢漁陽。',24,'御定全唐詩/json/367.json','["嫋嫋城邊柳，青青陌上桑。提籠忘采葉，昨夜夢漁陽。"]'),
('yuding-10','春江曲二首','張仲素','唐','御定全唐诗','yuding','','[]','家寄征河岸，征人幾歲遊。不如潮水信，每日到沙頭。',48,'御定全唐詩/json/367.json','["家寄征河岸，征人幾歲遊。不如潮水信，每日到沙頭。", "乘曉南湖去，參差疊浪橫。前洲在何處，霜裏雁嚶嚶。"]'),
('yuding-11','太平詞','張仲素','唐','御定全唐诗','yuding','','[]','聖德超千古，皇威靜四方。蒼生今息戰，無事覺時良。',24,'御定全唐詩/json/367.json','["聖德超千古，皇威靜四方。蒼生今息戰，無事覺時良。"]'),
('yuding-12','隴上行','張仲素','唐','御定全唐诗','yuding','','[]','行到黃雲隴，唯聞羌戍鼙。不如山下水，猶得任東西。',24,'御定全唐詩/json/367.json','["行到黃雲隴，唯聞羌戍鼙。不如山下水，猶得任東西。"]'),
('yuding-13','思君恩','張仲素','唐','御定全唐诗','yuding','','[]','紫禁香如霧，青天月似霜。雲韶何處奏，只是在朝陽。',24,'御定全唐詩/json/367.json','["紫禁香如霧，青天月似霜。雲韶何處奏，只是在朝陽。"]'),
('yuding-14','王昭君','張仲素','唐','御定全唐诗','yuding','','[]','仙娥今下嫁，驕子自同和。劍戟歸田盡，牛羊繞塞多。',24,'御定全唐詩/json/367.json','["仙娥今下嫁，驕子自同和。劍戟歸田盡，牛羊繞塞多。"]'),
('yuding-15','秋夜曲','張仲素','唐','御定全唐诗','yuding','','[]','丁丁漏水夜何長，漫漫輕雲露月光。',32,'御定全唐詩/json/367.json','["丁丁漏水夜何長，漫漫輕雲露月光。", "秋逼暗蟲通夕響，征衣未寄莫飛霜。"]'),
('yuding-16','秋思贈遠','張仲素','唐','御定全唐诗','yuding','','[]','博山沉燎絕餘香，蘭燼金檠怨夜長。',32,'御定全唐詩/json/367.json','["博山沉燎絕餘香，蘭燼金檠怨夜長。", "為問青青河畔草，幾回經雨複經霜。"]'),
('yuding-17','塞上曲','張仲素','唐','御定全唐诗','yuding','','[]','卷旆生風喜氣新，早持龍節靜邊塵。',32,'御定全唐詩/json/367.json','["卷旆生風喜氣新，早持龍節靜邊塵。", "漢家天子圖麟閣，身是當今第一人。"]'),
('yuding-18','塞下曲五首','張仲素','唐','御定全唐诗','yuding','','[]','三戍漁陽再渡遼，騂弓在臂劍橫腰。',160,'御定全唐詩/json/367.json','["三戍漁陽再渡遼，騂弓在臂劍橫腰。", "匈奴似若知名姓，休傍陰山更射雕。", "獵馬千行雁幾雙，燕然山下碧油幢。", "傳聲漠北單于破，火照旌旗夜受降。", "朔雪飄飄開雁門，平沙曆亂卷蓬根。", "功名恥計擒生數，直斬樓蘭報國恩。", "隴水潺湲隴樹秋，征人到此淚雙流。", "鄉關萬里無因見，西戍河源早晚休。", "陰磧茫茫塞草肥，桔槔烽上暮雲飛。", "交河北望天連海，蘇武曾將漢節歸。"]'),
('yuding-19','秋思二首','張仲素','唐','御定全唐诗','yuding','','[]','碧窗斜日藹深暉，愁聽寒螿淚濕衣。',64,'御定全唐詩/json/367.json','["碧窗斜日藹深暉，愁聽寒螿淚濕衣。", "夢裏分明見關塞，不知何路向金微。", "秋天一夜靜無雲，斷續鴻聲到曉聞。", "欲寄征衣問消息，居延城外又移軍。"]'),
('yuding-20','漢苑行二首','張仲素','唐','御定全唐诗','yuding','','[]','回雁高飛太液池，新花低發上林枝。',64,'御定全唐詩/json/367.json','["回雁高飛太液池，新花低發上林枝。", "年光到處皆堪賞，春色人間總不知。", "春風淡蕩景悠悠，鶯囀高枝燕入樓。", "千步回廊聞鳳吹，珠簾處處上銀鉤。"]'),
('yuding-21','天馬辭二首','張仲素','唐','御定全唐诗','yuding','','[]','天馬初從渥水來，郊歌曾唱得龍媒。',64,'御定全唐詩/json/367.json','["天馬初從渥水來，郊歌曾唱得龍媒。", "不知玉塞沙中路，苜蓿殘花幾處開。", "躞蹀宛駒齒未齊，摐金噴玉向風嘶。", "來時欲盡金河道，獵獵輕風在碧蹄。"]'),
('yuding-22','燕子樓詩三首','張仲素','唐','御定全唐诗','yuding','','[]','樓上殘燈伴曉霜，獨眠人起合歡床。',96,'御定全唐詩/json/367.json','["樓上殘燈伴曉霜，獨眠人起合歡床。", "相思一夜情多少，地角天涯不是長。", "北邙松柏鎖愁煙，燕子樓人思悄然。", "自埋劍履歌塵散，紅袖香消已十年。", "適看鴻雁岳陽回，又睹玄禽逼社來。", "瑤瑟玉簫無意緒，任從蛛網任從灰。"]'),
('yuding-0','賦得冬日可愛','庾承宣','唐','御定全唐诗','yuding','','[]','宿霧開天霽，寒郊見初日。林疏照逾遠，冰輕影微出。',72,'御定全唐詩/json/368.json','["宿霧開天霽，寒郊見初日。林疏照逾遠，冰輕影微出。", "豈假陽和氣，暫忘玄冬律。愁抱望自寬，羈情就如失。", "欣欣事幾許，曈曈狀非一。傾心倘知期，良願自茲畢。"]'),
('yuding-1','贈毛仙翁','鄭澣','唐','御定全唐诗','yuding','','[]','至道無名，至人長生。爰觀繪事，似挹真形。方口渥丹，',100,'御定全唐詩/json/368.json','["至道無名，至人長生。爰觀繪事，似挹真形。方口渥丹，", "紅肌絲發，外彰華精。色如含芳，貌若和光。胚渾造化，", "猗歟真人，得非後身。寫此仙骨，久而不磷。皎皎明眸，", "通天臺上，有見常人。俗士觀瞻，方悟幽塵。君子圖之，"]'),
('yuding-2','和李德裕游漢州房公湖二首','鄭澣','唐','御定全唐诗','yuding','','[]','太尉留琴地，時移重可尋。徽弦一掩抑，風月助登臨。',96,'御定全唐詩/json/368.json','["太尉留琴地，時移重可尋。徽弦一掩抑，風月助登臨。", "榮駐青油騎，高張白雪音。祗言酬唱美，良史記王箴。", "靜對煙波夕，猶思棟宇清。臥龍空有處，馴鳥獨忘情。", "顧步襟期遠，參差物象橫。自宜雕樂石，爽氣際青城。"]'),
('yuding-3','中書相公任兵部侍郎日後閣植四松逾數年澣忝此官因獻拙什','鄭澣','唐','御定全唐诗','yuding','','[]','丞相當時植，幽襟對此開。人知舟楫器，天假棟樑材。',120,'御定全唐詩/json/368.json','["丞相當時植，幽襟對此開。人知舟楫器，天假棟樑材。", "錯落龍鱗出，褵褷鶴翅回。重陰羅武庫，細響靜山台。", "得地公堂裏，移根澗水隈。吳臣夢寐遠，秦嶽歲年摧。", "轉覺飛纓繆，何因繼組來。幾尋珠履跡，願比角弓培。", "柏悅猶依社，星高久照台。後凋應共操，無複問良媒。"]'),
('yuding-4','和李德裕房公舊竹亭聞琴','鄭澣','唐','御定全唐诗','yuding','','[]','石室寒飆騖，孫枝雅器裁。坐來山水操，弦斷吊遺埃。',24,'御定全唐詩/json/368.json','["石室寒飆騖，孫枝雅器裁。坐來山水操，弦斷吊遺埃。"]'),
('yuding-5','句','鄭澣','唐','御定全唐诗','yuding','','[]','但慮彩色汙，無虞臂胛肥。（段成式記，長安菩薩寺',55,'御定全唐詩/json/368.json','["但慮彩色汙，無虞臂胛肥。（段成式記，長安菩薩寺", "有畫維摩變，為俗講僧文淑裝之，筆跡盡矣，故興元", "鄭尚書題句云云）。"]'),
('yuding-6','遊棲霞寺','張匯','唐','御定全唐诗','yuding','','[]','躋險入幽林，翠微含竹殿。泉聲無休歇，山色時隱見。',48,'御定全唐詩/json/368.json','["躋險入幽林，翠微含竹殿。泉聲無休歇，山色時隱見。", "潮來雜風雨，梅落成霜霰。一從方外遊，頓覺塵心變。"]'),
('yuding-7','春風扇微和','張匯','唐','御定全唐诗','yuding','','[]','木德生和氣，微微入曙風。暗催南向葉，漸翥北歸鴻。',72,'御定全唐詩/json/368.json','["木德生和氣，微微入曙風。暗催南向葉，漸翥北歸鴻。", "澹蕩侵冰谷，悠揚轉蕙叢。拂塵回廣路，泛籟過遙空。", "暖上煙光際，雲移律候中。扶搖如可借，從此戾蒼穹。"]'),
('yuding-8','觀藏冰','張匯','唐','御定全唐诗','yuding','','[]','寒氣方窮律，陰精正結冰。體堅風帶壯，影素月臨凝。',72,'御定全唐詩/json/368.json','["寒氣方窮律，陰精正結冰。體堅風帶壯，影素月臨凝。", "冬賦淩人掌，春期命婦升。鑿來壺色徹，納處鏡光澄。", "魯史曾留問，豳詩舊見稱。同觀裏射享，王道頌還興。"]'),
('yuding-9','賦得春風扇微和','陳通方','唐','御定全唐诗','yuding','','[]','習習和風扇，悠悠淑氣微。陽升知候改，律應喜春歸。',72,'御定全唐詩/json/368.json','["習習和風扇，悠悠淑氣微。陽升知候改，律應喜春歸。", "池柳晴初拆，林鶯暖欲飛。川原浮彩翠，台館動光輝。", "泛豔搖丹闕，揚芳入粉闈。發生當有分，枯朽幸因依。"]'),
('yuding-10','金谷園懷古','陳通方','唐','御定全唐诗','yuding','','[]','緩步洛城下，軫懷金穀園。昔人隨水逝，舊樹逐春繁。',72,'御定全唐詩/json/368.json','["緩步洛城下，軫懷金穀園。昔人隨水逝，舊樹逐春繁。", "冉冉搖風弱，菲菲裛露翻。歌台豈易見，舞袖乍如存。", "戲蝶香中起，流鶯暗處喧。徒聞施錦帳，此地擁行軒。"]'),
('yuding-11','句','陳通方','唐','御定全唐诗','yuding','','[]','應念路傍憔悴翼，昔年喬木幸同遷。（《紀事》雲：通方',97,'御定全唐詩/json/368.json','["應念路傍憔悴翼，昔年喬木幸同遷。（《紀事》雲：通方", "登第，與王播同年。播年五十六，通方甚少。因期集，", "也，播恨之。後通方丁家艱，辛苦萬狀。播為正郎，判", "鹽鐵。通方窮悴，求之，即不甚給。時李虛中為副使，"]'),
('yuding-12','立春日曉望三素雲','李應','唐','御定全唐诗','yuding','','[]','玄鳥初來日，靈仙望裏分。冰容朝上界，玉輦擁朝雲。',72,'御定全唐詩/json/368.json','["玄鳥初來日，靈仙望裏分。冰容朝上界，玉輦擁朝雲。", "碧落流輕豔，紅霓間彩文。帶煙時縹緲，向鬥更氤氳。", "仿佛隨風馭，迢遙出曉雰。茲辰三見後，希得從元君。"]'),
('yuding-13','立春日曉望三素雲','陳師穆','唐','御定全唐诗','yuding','','[]','晴曉初春日，高心望素雲。彩光浮玉輦，紫氣隱元君。',72,'御定全唐詩/json/368.json','["晴曉初春日，高心望素雲。彩光浮玉輦，紫氣隱元君。", "縹緲中天去，逍遙上界分。鸞驂攀不及，仙吹遠難聞。", "禮候於斯睹，明循在解紛。人歸懸想處，霞色自氛氳。"]'),
('yuding-14','立春日曉望三素雲','李季何','唐','御定全唐诗','yuding','','[]','靄靄青春曙，飛仙駕五雲。浮輪初縹緲，承蓋下氤氳。',72,'御定全唐詩/json/368.json','["靄靄青春曙，飛仙駕五雲。浮輪初縹緲，承蓋下氤氳。", "薄影隨風度，殊容向日分。羽毛紛共遠，環佩杳猶聞。", "靜合煙霞色，遙將鸞鶴群。年年瞻此節，應許從元君。"]'),
('yuding-15','春台晴望','李程','唐','御定全唐诗','yuding','','[]','曲台送春目，景物麗新晴。靄靄煙收翠，忻忻木向榮。',72,'御定全唐詩/json/368.json','["曲台送春目，景物麗新晴。靄靄煙收翠，忻忻木向榮。", "靜看遲日上，閑愛野雲平。風慢遊絲轉，天開遠水明。", "登高塵慮息，觀徼道心清。更有遷喬意，翩翩出穀鶯。"]'),
('yuding-16','玉壺冰','李程','唐','御定全唐诗','yuding','','[]','琢玉性惟堅，成壺體更圓。虛心含眾象，應物受寒泉。',96,'御定全唐詩/json/368.json','["琢玉性惟堅，成壺體更圓。虛心含眾象，應物受寒泉。", "溫潤資天質，清貞稟自然。日融光乍散，雪照色逾鮮。", "至鑒功寧宰，無私照豈偏。明將水鏡對，白與粉闈連。", "拂拭終為美，提攜佇見傳。勿令毫髮累，遺恨鮑公篇。"]'),
('yuding-17','賦得竹箭有筠','李程','唐','御定全唐诗','yuding','','[]','常愛淩寒竹，堅貞可喻人。能將先進禮，義與後凋鄰。',72,'御定全唐詩/json/368.json','["常愛淩寒竹，堅貞可喻人。能將先進禮，義與後凋鄰。", "冉冉猶全節，青青尚有筠。陶鈞二儀內，柯葉四時春。", "待鳳花仍吐，停霜色更新。方持不易操，對此欲觀身。"]'),
('yuding-18','觀慶雲圖','李程','唐','御定全唐诗','yuding','','[]','五雲從表瑞，藻繪宛成圖。柯葉何時改，丹青此不渝。',72,'御定全唐詩/json/368.json','["五雲從表瑞，藻繪宛成圖。柯葉何時改，丹青此不渝。", "非煙色尚麗，似蓋狀應殊。渥彩看猶在，輕陰望已無。", "方將遇翠幄，那羨起蒼梧。欲識從龍處，今逢聖合符。"]'),
('yuding-19','贈毛仙翁','李程','唐','御定全唐诗','yuding','','[]','茫茫塵累愧腥膻，強把蜉蝣望列仙。閑指紫霄峰下路，',40,'御定全唐詩/json/368.json','["茫茫塵累愧腥膻，強把蜉蝣望列仙。閑指紫霄峰下路，", "他日更來人世看，又應東海變桑田。"]'),
('yuding-20','省試春台晴望','高弁','唐','御定全唐诗','yuding','','[]','層台聊一望，遍賞帝城春。風暖聞啼鳥，冰開見躍鱗。',72,'御定全唐詩/json/368.json','["層台聊一望，遍賞帝城春。風暖聞啼鳥，冰開見躍鱗。", "晴山煙外翠，香蕊日邊新。已變青門柳，初銷紫陌塵。", "金湯千里國，車騎萬方人。此處雲霄近，憑高願致身。"]'),
('yuding-21','霜菊','席夔','唐','御定全唐诗','yuding','','[]','時令忽已變，行看被霜菊。可憐後時秀，當此凜風肅。',72,'御定全唐詩/json/368.json','["時令忽已變，行看被霜菊。可憐後時秀，當此凜風肅。", "淅瀝翠枝翻，淒清金蕊馥。凝姿節堪重，澄豔景非淑。", "寧祛青女威，願盈君子掬。持來泛樽酒，永以照幽獨。"]'),
('yuding-22','賦得竹箭有筠','席夔','唐','御定全唐诗','yuding','','[]','共愛東南美，青青歎有筠。貞姿眾木異，秀色四時均。',72,'御定全唐詩/json/368.json','["共愛東南美，青青歎有筠。貞姿眾木異，秀色四時均。", "枝葉當無改，風霜豈憚頻。虛心如待物，勁節自留春。", "鮮潤期棲鳳，嬋娟可並人。可憐初籜卷，粉澤更宜新。"]'),
('yuding-23','省試觀慶雲圖','李行敏','唐','御定全唐诗','yuding','','[]','縑素傳休祉，丹青狀慶雲。非煙凝漠漠，似蓋乍紛紛。',72,'御定全唐詩/json/368.json','["縑素傳休祉，丹青狀慶雲。非煙凝漠漠，似蓋乍紛紛。", "尚駐從龍意，全舒捧日文。光因五色起，影向九霄分。", "裂素觀嘉瑞，披圖賀聖君。甯同窺汗漫，方此睹氛氳。"]'),
('yuding-24','賦得冬日可愛','陳諷','唐','御定全唐诗','yuding','','[]','寒日臨清晝，寥天一望時。未消埋徑雪，先暖讀書帷。',72,'御定全唐詩/json/368.json','["寒日臨清晝，寥天一望時。未消埋徑雪，先暖讀書帷。", "屬思光難駐，舒情影若遺。晉臣曾比德，謝客昔言詩。", "散彩寧偏照，流陰信不追。餘輝如可就，回燭幸無私。"]'),
('yuding-25','郡齋三月下旬作','崔護','唐','御定全唐诗','yuding','','[]','春事日已歇，池塘曠幽尋。殘紅披獨墜，嫩綠間淺深。',48,'御定全唐詩/json/368.json','["春事日已歇，池塘曠幽尋。殘紅披獨墜，嫩綠間淺深。", "偃仰卷芳褥，顧步愛新陰。謀春未及竟，夏初遽見侵。"]'),
('yuding-26','五月水邊柳','崔護','唐','御定全唐诗','yuding','','[]','結根挺涯涘，垂影覆清淺。睡臉寒未開，懶腰晴更軟。',72,'御定全唐詩/json/368.json','["結根挺涯涘，垂影覆清淺。睡臉寒未開，懶腰晴更軟。", "搖空條已重，拂水帶方展。似醉煙景凝，如愁月露泫。", "絲長魚誤恐，枝弱禽驚踐。長別幾多情，含春任攀搴。"]'),
('yuding-27','三月五日陪裴大夫泛長沙東湖','崔護','唐','御定全唐诗','yuding','','[]','上巳餘風景，芳辰集遠坰。彩舟浮泛蕩，繡轂下娉婷。',72,'御定全唐詩/json/368.json','["上巳餘風景，芳辰集遠坰。彩舟浮泛蕩，繡轂下娉婷。", "林樹回蔥蒨，笙歌入杳冥。湖光迷翡翠，草色醉蜻蜓。", "鳥弄桐花日，魚翻穀雨萍。從今留勝會，誰看畫蘭亭。"]'),
('yuding-28','山雞舞石鏡','崔護','唐','御定全唐诗','yuding','','[]','廬峰開石鏡，人說舞山雞。物象纖無隱，禽情只自迷。',72,'御定全唐詩/json/368.json','["廬峰開石鏡，人說舞山雞。物象纖無隱，禽情只自迷。", "景當煙霧歇，心喜錦翎齊。宛轉烏呈彩，婆娑鳳欲棲。", "何言資羽族，在地得天倪。應笑翰音者，終朝飲敗醯。"]'),
('yuding-29','題都城南莊','崔護','唐','御定全唐诗','yuding','','[]','去年今日此門中，人面桃花相映紅。',32,'御定全唐詩/json/368.json','["去年今日此門中，人面桃花相映紅。", "人面不知何處在，桃花依舊笑春風。"]'),
('yuding-30','晚雞','崔護','唐','御定全唐诗','yuding','','[]','黯黯嚴城罷鼓鼙，數聲相續出寒棲。',32,'御定全唐詩/json/368.json','["黯黯嚴城罷鼓鼙，數聲相續出寒棲。", "不嫌驚破紗窗夢，卻恐為奴半夜啼。"]'),
('yuding-0','贈藥山高僧惟儼二首','李翱','唐','御定全唐诗','yuding','','[]','練得身形似鶴形，千株松下兩函經。',64,'御定全唐詩/json/369.json','["練得身形似鶴形，千株松下兩函經。", "我來問道無餘說，雲在青霄水在瓶。", "選得幽居愜野情，終年無送亦無迎。", "有時直上孤峰頂，月下披雲嘯一聲。"]'),
('yuding-1','贈毛仙翁','李翱','唐','御定全唐诗','yuding','','[]','紫霄仙客下三山，因救生靈到世間。龜鶴計年承甲子，',40,'御定全唐詩/json/369.json','["紫霄仙客下三山，因救生靈到世間。龜鶴計年承甲子，", "從此便教塵骨貴，九霄雲路願追攀。"]'),
('yuding-2','拜禹歌','李翱','唐','御定全唐诗','yuding','','[]','惟天地之無窮兮，哀生人之常勤。往者吾弗及兮，',22,'御定全唐詩/json/369.json','["惟天地之無窮兮，哀生人之常勤。往者吾弗及兮，"]'),
('yuding-3','廣慶寺','李翱','唐','御定全唐诗','yuding','','[]','傳者不足信，見景勝如聞。一水遠赴海，兩山高入雲。',48,'御定全唐詩/json/369.json','["傳者不足信，見景勝如聞。一水遠赴海，兩山高入雲。", "魚龍晴自戲，猿狖晚成群。醉酒斜陽下，離心草自熏。"]'),
('yuding-4','奉酬劉言史宴光風亭','李翱','唐','御定全唐诗','yuding','','[]','閏餘春早景沉沉，禊飲風亭恣賞心。',32,'御定全唐詩/json/369.json','["閏餘春早景沉沉，禊飲風亭恣賞心。", "紅袖青娥留永夕，漢陰寧肯羨山陰。"]'),
('yuding-5','戲贈詩','李翱','唐','御定全唐诗','yuding','','[]','縣君好磚渠，繞水恣行遊。鄙性樂疏野，鑿地便成溝。',60,'御定全唐詩/json/369.json','["縣君好磚渠，繞水恣行遊。鄙性樂疏野，鑿地便成溝。", "兩岸值芳草，中央漾清流。所尚既不同，磚鑿可自修。", "從他後人見，境趣誰為幽。"]'),
('yuding-6','題浯溪石','皇甫湜','唐','御定全唐诗','yuding','','[]','次山有文章，可惋只在碎。然長於指敘，約潔有餘態。',144,'御定全唐詩/json/369.json','["次山有文章，可惋只在碎。然長於指敘，約潔有餘態。", "心語適相應，出句多分外。于諸作者間，拔戟成一隊。", "中行雖富劇，粹美若可蓋。子昂感遇佳，未若君雅裁。", "退之全而神，上與千載對。李杜才海翻，高下非可概。", "文與一氣間，為物莫與大。先王路不荒，豈不仰吾輩。", "石屏立衙衙，溪口揚素瀨。我思何人知，徙倚如有待。"]'),
('yuding-7','石佛穀','皇甫湜','唐','御定全唐诗','yuding','','[]','澶漫太行北，千里一塊石。平腹有壑谷，深廣數百尺。',143,'御定全唐詩/json/369.json','["澶漫太行北，千里一塊石。平腹有壑谷，深廣數百尺。", "土僧何為者，老草毛髮白。寢處容身龕，足膝隱成跡。", "金仙琢靈象，相好倚北壁。花座五雲扶，玉毫六虛射。", "文人留紀述，時事可辨析。鳥跡巧均分，龍骸極臒瘠。", "枯松間槎枿，猛獸恣騰擲。蛣蟲食縱，懸垂露凝滴。", "精藝貫古今，窮岩誰愛惜。托師禪誦餘，勿使塵埃積。"]'),
('yuding-8','出世篇','皇甫湜','唐','御定全唐诗','yuding','','[]','生當為大丈夫，斷羈羅，出泥塗。四散號呶，俶擾無隅。',188,'御定全唐詩/json/369.json','["生當為大丈夫，斷羈羅，出泥塗。四散號呶，俶擾無隅。", "埋之深淵，飄然上浮。騎龍披青雲，泛覽游八區。", "經太山，絕大海，一長籲。西摩月鏡，東弄日珠。", "上括天之門，直指帝所居。群仙來迎塞天衢，", "食之不飫飫不盡，使人不陋複不愚。旦旦狎玉皇，", "俄而散漫，斐然虛無。翕然複摶，摶久而蘇。", "精神如太陽，霍然照清都。四肢為琅玕，五臟為璠璵。", "顏如芙蓉，頂為醍醐。與天地相終始，浩漫為歡娛。", "下顧人間，溷糞蠅蛆。"]'),
('yuding-9','蜀綿州越王樓詩','樊宗師','唐','御定全唐诗','yuding','','[]','危樓倚天門，如m6星辰宮。榱薄龍虎怪，洄洄繞雷風。',121,'御定全唐詩/json/369.json','["危樓倚天門，如m6星辰宮。榱薄龍虎怪，洄洄繞雷風。", "徂秋試登臨，大靄屯喬空。不見西北路，考懷益雕窮。", "石瀨薄濺濺，上山杳穹穹。昔人創為逝，所適酡顏紅。", "今我茲之來，猶校成歲功。輟田植科畝，遊圃歌芳叢。", "地財無叢厚，人室安取豐。既乏富庶能，千萬慚文翁。"]'),
('yuding-10','催妝','盧儲','唐','御定全唐诗','yuding','','[]','昔年將去玉京游，第一仙人許狀頭。',32,'御定全唐詩/json/369.json','["昔年將去玉京游，第一仙人許狀頭。", "今日幸為秦晉會，早教鸞鳳下妝樓。"]'),
('yuding-11','官舍迎內子有庭花開','盧儲','唐','御定全唐诗','yuding','','[]','芍藥斬新栽，當庭數朵開。東風與拘束，留待細君來。',24,'御定全唐詩/json/369.json','["芍藥斬新栽，當庭數朵開。東風與拘束，留待細君來。"]'),
('yuding-12','古松感興','皇甫松','唐','御定全唐诗','yuding','','[]','皇天后土力，使我向此生。貴賤不我均，若為天地情。',72,'御定全唐詩/json/369.json','["皇天后土力，使我向此生。貴賤不我均，若為天地情。", "我家世道德，旨意匡文明。家集四百卷，獨立天地經。", "寄言青松姿，豈羨朱槿榮。昭昭大化光，共此遺芳馨。"]'),
('yuding-13','怨回紇歌','皇甫松','唐','御定全唐诗','yuding','','[]','白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡蘆河。',48,'御定全唐詩/json/369.json','["白首南朝女，愁聽異域歌。收兵頡利國，飲馬胡蘆河。", "毳布腥膻久，穹廬歲月多。雕巢城上宿，吹笛淚滂沱。"]'),
('yuding-14','江上送別','皇甫松','唐','御定全唐诗','yuding','','[]','祖席駐征棹，開帆候信潮。隔筵桃葉泣，吹管杏花飄。',48,'御定全唐詩/json/369.json','["祖席駐征棹，開帆候信潮。隔筵桃葉泣，吹管杏花飄。", "船去鷗飛閣，人歸塵上橋。別離惆悵淚，江路濕紅蕉。"]'),
('yuding-15','採蓮子二首','皇甫松','唐','御定全唐诗','yuding','','[]','菡萏香連十頃陂，小姑貪戲採蓮遲。',64,'御定全唐詩/json/369.json','["菡萏香連十頃陂，小姑貪戲採蓮遲。", "晚來弄水船頭濕，更脫紅裙裹鴨兒。", "船動湖光灩灩秋，貪看年少信船流。", "無端隔水拋蓮子，遙被人知半日羞。"]'),
('yuding-16','拋球樂','皇甫松','唐','御定全唐诗','yuding','','[]','紅撥一聲飄，輕球墜越綃。帶翻金孔雀，香滿繡蜂腰。',72,'御定全唐詩/json/369.json','["紅撥一聲飄，輕球墜越綃。帶翻金孔雀，香滿繡蜂腰。", "少少拋分數，花枝正索饒。", "金蹙花球小，真珠繡帶垂。幾回沖蠟燭，千度入春懷。", "上客終須醉，觥杯自亂排。"]'),
('yuding-17','勸僧酒','皇甫松','唐','御定全唐诗','yuding','','[]','勸僧一杯酒，共看青青山。酣然萬象滅，不動心印閑。',24,'御定全唐詩/json/369.json','["勸僧一杯酒，共看青青山。酣然萬象滅，不動心印閑。"]'),
('yuding-18','登郭隗台','皇甫松','唐','御定全唐诗','yuding','','[]','燕相謀在茲，積金黃巍巍。上者欲何顏，使我千載悲。',24,'御定全唐詩/json/369.json','["燕相謀在茲，積金黃巍巍。上者欲何顏，使我千載悲。"]'),
('yuding-19','楊柳枝詞二首','皇甫松','唐','御定全唐诗','yuding','','[]','爛漫春歸水國時，吳王宮殿柳絲垂。',64,'御定全唐詩/json/369.json','["爛漫春歸水國時，吳王宮殿柳絲垂。", "黃鶯長叫空閨畔，西子無因更得知。", "春入行宮映翠微，玄宗侍女舞煙絲。", "如今柳向空城綠，玉笛何人更把吹。"]'),
('yuding-20','浪淘沙二首','皇甫松','唐','御定全唐诗','yuding','','[]','灘頭細草接疏林，浪惡罾船半欲沉。',64,'御定全唐詩/json/369.json','["灘頭細草接疏林，浪惡罾船半欲沉。", "宿鷺眠洲非舊浦，去年沙觜是江心。", "蠻歌豆蔻北人愁，松雨蒲風野艇秋。", "浪起鵁鶄眠不得，寒沙細細入江流。"]'),
('yuding-21','句','皇甫松','唐','御定全唐诗','yuding','','[]','夜入真珠室，朝游玳瑁宮。（《紀事》載：松為牛僧孺表',51,'御定全唐詩/json/369.json','["夜入真珠室，朝游玳瑁宮。（《紀事》載：松為牛僧孺表", "甥，不相薦舉。因襄陽大水，極言誹謗。真珠乃牛愛姬也）"]'),
('yuding-22','送皇甫湜赴舉','馬異','唐','御定全唐诗','yuding','','[]','馬蹄聲特特，去入天子國。借問去是誰，秀才皇甫湜。',72,'御定全唐詩/json/369.json','["馬蹄聲特特，去入天子國。借問去是誰，秀才皇甫湜。", "吞吐一腹文，八音兼五色。主文有崔李，鬱鬱為朝德。", "青銅鏡必明，朱絲繩必直。稱意太平年，願子長相憶。"]'),
('yuding-23','貞元旱歲','馬異','唐','御定全唐诗','yuding','','[]','赤地炎都寸草無，百川水沸煮蟲魚。',32,'御定全唐詩/json/369.json','["赤地炎都寸草無，百川水沸煮蟲魚。", "定應焦爛無人救，淚落三篇古尚書。"]'),
('yuding-24','暮春醉中寄李幹秀才','馬異','唐','御定全唐诗','yuding','','[]','歡異且交親，酒生開甕春。不須愁犯卯，且乞醉過申。',48,'御定全唐詩/json/369.json','["歡異且交親，酒生開甕春。不須愁犯卯，且乞醉過申。", "折草為籌箸，鋪花作錦裀。嬌鶯解言語，留客也殷勤。"]'),
('yuding-25','答盧仝結交詩','馬異','唐','御定全唐诗','yuding','','[]','有鳥自南翔，口銜一書紮，達我山之維。',206,'御定全唐詩/json/369.json','["有鳥自南翔，口銜一書紮，達我山之維。", "開緘金玉煥陸離，乃是盧仝結交詩。此詩峭絕天邊格，", "莫嗟獨笑無往還，月中芳桂難追攀。況值亂邦不平年，", "上天不識察，仰我為遼天失所，將吾劍兮切淤泥，", "抱鋤劚地芸芝朮，偃蓋參天舊有松，術與松兮保身世。", "臥居居兮起于於，漱潺潺兮聆嘒嘒。道在其中可終歲，", "鋼刀剉骨不辭去，卑躬君子今明明。俯首辭山心慘惻，", "為報覃懷心結交，死生富貴存後凋。我心不畏朱公叔，", "河水悠悠山之間，無由把袂攄懷抱。憶仝吟能文，"]'),
('yuding-0','白雲起封中詩','呂溫','唐','御定全唐诗','yuding','','[]','封開白雲起，漢帝坐齋宮。望在泥金上，疑生秘玉中。',72,'御定全唐詩/json/370.json','["封開白雲起，漢帝坐齋宮。望在泥金上，疑生秘玉中。", "攢柯初繚繞，布葉漸蒙籠。日觀祥光合，天門瑞氣通。", "無心已出岫，有勢欲淩風。倘遣成膏澤，從茲遍大空。"]'),
('yuding-1','終南精舍月中聞磬聲詩','呂溫','唐','御定全唐诗','yuding','','[]','月峰禪室掩，幽磬靜昏氛。思入空門妙，聲從覺路聞。',72,'御定全唐詩/json/370.json','["月峰禪室掩，幽磬靜昏氛。思入空門妙，聲從覺路聞。", "泠泠滿虛壑，杳杳出寒雲。天籟疑難辨，霜鐘誰可分。", "偶來遊法界，便欲謝人群。竟夕聽真響，塵心自解紛。"]'),
('yuding-2','青出藍詩','呂溫','唐','御定全唐诗','yuding','','[]','物有無窮好，藍青又出青。朱研未比德，白受始成形。',48,'御定全唐詩/json/370.json','["物有無窮好，藍青又出青。朱研未比德，白受始成形。", "袍襲宜從政，衿垂可問經。當時不採擷，作色幾飄零。"]'),
('yuding-3','奉和李相公早朝於中書候傳點偶書所懷奉呈門下武相公中書鄭相公','呂溫','唐','御定全唐诗','yuding','','[]','禁門留騎吹，內省正衣冠。稍辨旗常色，尚聞鐘漏殘。',120,'御定全唐詩/json/370.json','["禁門留騎吹，內省正衣冠。稍辨旗常色，尚聞鐘漏殘。", "九天爐氣暖，六月玉聲寒。宿霧開霞觀，晨光泛露盤。", "致君期反朴，求友得如蘭。政自同歸理，言成共不刊。", "準繩臨百度，領袖映千官。臥鼓流沙靜，飛航漲海安。", "盡規酬主意，偕賦代交歡。雅韻人間滿，多慚竊和難。"]'),
('yuding-4','奉和武中丞秋日台中寄懷簡諸僚友','呂溫','唐','御定全唐诗','yuding','','[]','聖朝思紀律，憲府得中賢。指顧風行地，儀形月麗天。',96,'御定全唐詩/json/370.json','["聖朝思紀律，憲府得中賢。指顧風行地，儀形月麗天。", "不仁恒自遠，為政複何先。虛室唯生白，閒情卻草玄。", "迎霜紅葉早，過雨碧苔鮮。魚樂翻秋水，烏聲隔暮煙。", "舊游多絕席，感物遂成篇。更許窮荒穀，追歌白雪前。"]'),
('yuding-5','吐蕃別館和周十一郎中楊七錄事望白水山作','呂溫','唐','御定全唐诗','yuding','','[]','純精結奇狀，皎皎天一涯。玉嶂擁清氣，蓮峰開白花。',96,'御定全唐詩/json/370.json','["純精結奇狀，皎皎天一涯。玉嶂擁清氣，蓮峰開白花。", "半岩晦雲雪，高頂澄煙霞。朝昏對賓館，隱映如仙家。", "夙聞蘊孤尚，終欲窮幽遐。暫因行役暇，偶得志所嘉。", "明時無外戶，勝境即中華。況今舅甥國，誰道隔流沙。"]'),
('yuding-6','奉和張舍人閣中直夜思聞雅琴因書事通簡僚友','呂溫','唐','御定全唐诗','yuding','','[]','迢遞天上直，寂寞丘中琴。憶爾山水韻，起予仁智心。',72,'御定全唐詩/json/370.json','["迢遞天上直，寂寞丘中琴。憶爾山水韻，起予仁智心。", "凝情在正始，超想疏煩襟。涼生子夜後，月照禁垣深。", "遠風靄蘭氣，微露清桐陰。方襲緇衣慶，永奉南熏吟。"]'),
('yuding-7','和舍弟惜花絕句','呂溫','唐','御定全唐诗','yuding','','[]','去年無花看，今年未看花。更聞飄落盡，走馬向誰家。',24,'御定全唐詩/json/370.json','["去年無花看，今年未看花。更聞飄落盡，走馬向誰家。"]'),
('yuding-8','和恭聽曉籠中山鵲','呂溫','唐','御定全唐诗','yuding','','[]','掩抑中天意，悽愴觸籠音。驚曉一聞處，傷春千里心。',24,'御定全唐詩/json/370.json','["掩抑中天意，悽愴觸籠音。驚曉一聞處，傷春千里心。"]'),
('yuding-9','和舍弟讓籠中鷹','呂溫','唐','御定全唐诗','yuding','','[]','未用且求安，無猜也不殘。九天飛勢在，六月目睛寒。',48,'御定全唐詩/json/370.json','["未用且求安，無猜也不殘。九天飛勢在，六月目睛寒。", "動觸樊籠倦，閑消肉食難。主人憎惡鳥，試待一呼看。"]'),
('yuding-10','同恭夏日題尋真觀李寬中秀才書院','呂溫','唐','御定全唐诗','yuding','','[]','閉院開軒笑語闌，江山併入一壺寬。微風但覺杉香滿，',40,'御定全唐詩/json/370.json','["閉院開軒笑語闌，江山併入一壺寬。微風但覺杉香滿，", "願君此地攻文字，如煉仙家九轉丹。"]'),
('yuding-11','同舍弟恭歲暮寄晉州李六協律三十韻','呂溫','唐','御定全唐诗','yuding','','[]','古人猶悲秋，況複歲暮時。急景迫流念，窮陰結長悲。',360,'御定全唐詩/json/370.json','["古人猶悲秋，況複歲暮時。急景迫流念，窮陰結長悲。", "陽烏下西嶺，月鵲驚南枝。攬衣步霜砌，倚杖臨冰池。", "怳怳若有失，悄悄良不怡。忽聞晨起吟，宛是同所思。", "有美壯感激，無何遠棲遲。摧藏變化用，掩抑扶搖姿。", "時傑豈虛出，天道信可欺。巨川望汔濟，寒穀待潛吹。", "劍匣益精利，玉韜寧磷緇。戒哉輕沽諸，行矣自寵之。", "伊我抱微尚，仲氏即心期。討論自少小，形影相差池。", "比來胸中氣，欲耀天下奇。雲雨沛蕭艾，煙閣雙萎蕤。", "幾年困方枘，一旦迷多岐。道因窮理悟，命以盡性知。", "事去類絕弦，時來如轉規。伊呂偶然得，孔墨徒爾為。", "早行多露悔，強進觸藩羸。功名豈身利，仁義非吾私。", "萬物自身化，一夫何驅馳。不如任行止，委命安所宜。", "勸君休感歎，與予陶希夷。明年郊天后，慶澤歲華滋。", "曲水杏花雪，香街青柳絲。良時且暫歡，樽酒聊共持。", "閑過漆園叟，醉看五陵兒。寄言思隱處，不久來相追。"]'),
('yuding-12','青海西寄竇三端公','呂溫','唐','御定全唐诗','yuding','','[]','時同事弗同，窮節厲陰風。我役流沙外，君朝紫禁中。',48,'御定全唐詩/json/370.json','["時同事弗同，窮節厲陰風。我役流沙外，君朝紫禁中。", "從容非所羨，辛苦竟何功。但示酬恩路，浮生任轉蓬。"]'),
('yuding-13','蕃中拘留歲餘回至隴石先寄城中親故','呂溫','唐','御定全唐诗','yuding','','[]','蓬轉星霜改，蘭陔色養違。窮泉百死別，絕域再生歸。',48,'御定全唐詩/json/370.json','["蓬轉星霜改，蘭陔色養違。窮泉百死別，絕域再生歸。", "鏡數成絲發，囊收抆血衣。酬恩有何力，只棄一毛微。"]'),
('yuding-14','吐蕃別館臥病寄朝中諸友','呂溫','唐','御定全唐诗','yuding','','[]','星漢縱橫車馬喧，風搖玉佩燭花繁。',32,'御定全唐詩/json/370.json','["星漢縱橫車馬喧，風搖玉佩燭花繁。", "豈知羸臥窮荒外，日滿深山猶閉門。"]'),
('yuding-15','吐蕃別館中和日寄朝中僚舊','呂溫','唐','御定全唐诗','yuding','','[]','清時令節千官會，絕域窮山一病夫。',32,'御定全唐詩/json/370.json','["清時令節千官會，絕域窮山一病夫。", "遙想滿堂歡笑處，幾人緣我向西隅。"]'),
('yuding-16','及第後答潼關主人','呂溫','唐','御定全唐诗','yuding','','[]','本欲雲雨化，卻隨波浪翻。一沾太常第，十過潼關門。',48,'御定全唐詩/json/370.json','["本欲雲雨化，卻隨波浪翻。一沾太常第，十過潼關門。", "志力且虛棄，功名誰複論。主人故相問，慚笑不能言。"]'),
('yuding-17','河中城南姚家浴後題贈主人','呂溫','唐','御定全唐诗','yuding','','[]','新浴振輕衣，滿堂寒月色。主人有美酒，況是曾相識。',24,'御定全唐詩/json/370.json','["新浴振輕衣，滿堂寒月色。主人有美酒，況是曾相識。"]'),
('yuding-18','看渾中丞山桃花初有他客不通晚方得入因有戲贈','呂溫','唐','御定全唐诗','yuding','','[]','朝來駐馬香街裏，風度遙聞語笑聲。',32,'御定全唐詩/json/370.json','["朝來駐馬香街裏，風度遙聞語笑聲。", "無事閉門教日晚，山桃落盡不勝情。"]'),
('yuding-19','贈友人','呂溫','唐','御定全唐诗','yuding','','[]','南山雙喬松，擢本皆千尋。夕流膏露津，朝被青雲陰。',72,'御定全唐詩/json/370.json','["南山雙喬松，擢本皆千尋。夕流膏露津，朝被青雲陰。", "負雪出深澗，搖風倚高岑。明堂久不構，雲幹何森森。", "匠意方雕巧，時情正誇淫。生材會有用，天地豈無心。"]'),
('yuding-20','道州夏日郡內北橋新亭書懷贈何元二處士','呂溫','唐','御定全唐诗','yuding','','[]','結構池梁上，登臨日幾回。晴空交密葉，陰岸積蒼苔。',120,'御定全唐詩/json/370.json','["結構池梁上，登臨日幾回。晴空交密葉，陰岸積蒼苔。", "爽氣中央滿，清風四面來。振衣生羽翰，高枕出塵埃。", "齊物魚何樂，忘機鳥不猜。閑銷炎晝靜，選勝火雲開。", "僻遠宜孱性，優遊賴廢材。願為長泛梗，莫作重然灰。", "守道窮非過，先時動是災。寄言徐孺子，賓榻且徘徊。"]'),
('yuding-21','道州弘道縣主簿知縣三年頗著廉慎秩滿縣闕申使請留將赴衡州題其廳事','呂溫','唐','御定全唐诗','yuding','','[]','為理賴同力，陟明非所任。廢田方墾草，新柘未成陰。',48,'御定全唐詩/json/370.json','["為理賴同力，陟明非所任。廢田方墾草，新柘未成陰。", "術淺功難就，人疲感易深。煩君駐歸棹，與慰不欺心。"]'),
('yuding-22','道州將赴衡州酬別江華毛令','呂溫','唐','御定全唐诗','yuding','','[]','布帛精粗任土宜，疲人識信每先期。',32,'御定全唐詩/json/370.json','["布帛精粗任土宜，疲人識信每先期。", "明朝別後無他囑，雖是蒲鞭也莫施。"]'),
('yuding-23','道州夏日早訪荀參軍林園敬酬見贈','呂溫','唐','御定全唐诗','yuding','','[]','高眠日出始開門，竹徑旁通到後園。陶亮橫琴空有意，',40,'御定全唐詩/json/370.json','["高眠日出始開門，竹徑旁通到後園。陶亮橫琴空有意，", "山郡本來車馬少，更容相訪莫辭喧。"]'),
('yuding-24','道州敬酬何處士懷郡樓月夜之作','呂溫','唐','御定全唐诗','yuding','','[]','清質悠悠素彩融，長川迥陸合為空。',32,'御定全唐詩/json/370.json','["清質悠悠素彩融，長川迥陸合為空。", "佳人甚近山城閉，夏夜相望水鏡中。"]'),
('yuding-25','道州敬酬何處士書情見贈','呂溫','唐','御定全唐诗','yuding','','[]','意氣曾傾四國豪，偶來幽寺息塵勞。嚴陵釣處江初滿，',40,'御定全唐詩/json/370.json','["意氣曾傾四國豪，偶來幽寺息塵勞。嚴陵釣處江初滿，", "期君自致青雲上，不用傷心歎二毛。"]'),
('yuding-26','戲贈靈澈上人','呂溫','唐','御定全唐诗','yuding','','[]','僧家亦有芳春興，自是禪心無滯境。',32,'御定全唐詩/json/370.json','["僧家亦有芳春興，自是禪心無滯境。", "君看池水湛然時，何曾不受花枝影。"]'),
('yuding-27','二月一日是貞元舊節有感絕句寄黔南竇三洛陽盧七','呂溫','唐','御定全唐诗','yuding','','[]','同事先皇立玉墀，中和舊節又支離。',32,'御定全唐詩/json/370.json','["同事先皇立玉墀，中和舊節又支離。", "今朝各自看花處，萬里遙知掩淚時。"]'),
('yuding-28','初發道州答崔三連州題海陽亭見寄絕句','呂溫','唐','御定全唐诗','yuding','','[]','吏中習隱好躋攀，不擾疲人便自閑。',32,'御定全唐詩/json/370.json','["吏中習隱好躋攀，不擾疲人便自閑。", "聞說殷勤海陽事，令人轉憶舜祠山。"]'),
('yuding-29','答段秀才','呂溫','唐','御定全唐诗','yuding','','[]','盡日看花君不來，江城半夜與君開。',32,'御定全唐詩/json/370.json','["盡日看花君不來，江城半夜與君開。", "樓中共指南園火，紅燼隨花落碧苔。"]'),
('yuding-30','宗禮欲往桂州，苦雨因以戲贈','呂溫','唐','御定全唐诗','yuding','','[]','農人辛苦綠苗齊，正愛梅天水滿堤。',32,'御定全唐詩/json/370.json','["農人辛苦綠苗齊，正愛梅天水滿堤。", "知汝使車行意速，但令驄馬著鄣泥。"]'),
('yuding-31','道州奉寄襄陽裴相公','呂溫','唐','御定全唐诗','yuding','','[]','悠悠世路自浮沉，豈問仁賢待物心。',32,'御定全唐詩/json/370.json','["悠悠世路自浮沉，豈問仁賢待物心。", "最憶過時留宴處，豔歌催酒後亭深。"]'),
('yuding-0','吐蕃別館月夜','呂溫','唐','御定全唐诗','yuding','','[]','三五窮荒月，還應照北堂。回身向暗臥，不忍見圓光。',24,'御定全唐詩/json/371.json','["三五窮荒月，還應照北堂。回身向暗臥，不忍見圓光。"]'),
('yuding-1','望思台作','呂溫','唐','御定全唐诗','yuding','','[]','浸潤成宮蠱，蒼黃弄父兵。人情疑始變，天性感還生。',48,'御定全唐詩/json/371.json','["浸潤成宮蠱，蒼黃弄父兵。人情疑始變，天性感還生。", "宇縣猶能洽，閨門詎不平。空令千載後，悽愴望思名。"]'),
('yuding-2','孟冬蒲津關河亭作','呂溫','唐','御定全唐诗','yuding','','[]','息駕非窮途，未濟豈迷津。獨立大河上，北風來吹人。',48,'御定全唐詩/json/371.json','["息駕非窮途，未濟豈迷津。獨立大河上，北風來吹人。", "雪霜自茲始，草木當更新。嚴冬不肅殺，何以見陽春。"]'),
('yuding-3','鞏路感懷','呂溫','唐','御定全唐诗','yuding','','[]','馬嘶白日暮，劍鳴秋氣來。我心浩無際，河上空徘徊。',24,'御定全唐詩/json/371.json','["馬嘶白日暮，劍鳴秋氣來。我心浩無際，河上空徘徊。"]'),
('yuding-4','題梁宣帝陵二首','呂溫','唐','御定全唐诗','yuding','','[]','即讎終自翦，覆國豈為雄。假號孤城裏，何殊在甬東。',48,'御定全唐詩/json/371.json','["即讎終自翦，覆國豈為雄。假號孤城裏，何殊在甬東。", "祀夏功何薄，尊周義不成。淒涼庾信賦，千載共傷情。"]'),
('yuding-5','岳陽懷古','呂溫','唐','御定全唐诗','yuding','','[]','晨飆發荊州，落日到巴丘。方知刳剡利，可接鬼神遊。',120,'御定全唐詩/json/371.json','["晨飆發荊州，落日到巴丘。方知刳剡利，可接鬼神遊。", "二湖豁南浸，九派駛東流。襟帶三千里，盡在岳陽樓。", "憶昔鬥群雄，此焉爭上游。吳昌屯虎旅，晉盛騖龍舟。", "宋齊紛禍難，梁陳成寇讎。鐘鼓長震耀，魚龍不得休。", "風雪一蕭散，功業忽如浮。今日時無事，空江滿白鷗。"]'),
('yuding-6','道州途中即事','呂溫','唐','御定全唐诗','yuding','','[]','零桂佳山水，滎陽舊自同。經途看不暇，遇境說難窮。',144,'御定全唐詩/json/371.json','["零桂佳山水，滎陽舊自同。經途看不暇，遇境說難窮。", "疊嶂青時合，澄湘漫處空。舟移明鏡裏，路入畫屏中。", "岩壑千家接，松蘿一徑通。漁煙生縹緲，犬吠隔籠蔥。", "戲鳥留餘翠，幽花吝晚紅。光翻沙瀨日，香散橘園風。", "信美非吾土，分憂屬賤躬。守愚資地僻，恤隱望年豐。", "且保心能靜，那求政必工。課終如免戾，歸養洛城東。"]'),
('yuding-7','登少陵原望秦中諸川太原王至德妙用有水術因用感歎','呂溫','唐','御定全唐诗','yuding','','[]','少陵最高處，曠望極秋空。君山噴清源，脈散秦川中。',144,'御定全唐詩/json/371.json','["少陵最高處，曠望極秋空。君山噴清源，脈散秦川中。", "荷鍤自成雨，由來非鬼工。如何盛明代，委棄傷豳風。", "涇灞徒絡繹，漆沮虛會同。東流滔滔去，沃野飛秋蓬。", "大禹平水土，吾人得其宗。發機回地勢，運思與天通。", "早欲獻奇策，豐財敘西戎。豈知年三十，未識大明宮。", "卷爾出岫雲，追吾入冥鴻。無為學驚俗，狂醉哭途窮。"]'),
('yuding-8','奉敕祭南嶽十四韻','呂溫','唐','御定全唐诗','yuding','','[]','皇家禮赤帝，謬獲司風域。致齋紫蓋下，宿設祝融側。',168,'御定全唐詩/json/371.json','["皇家禮赤帝，謬獲司風域。致齋紫蓋下，宿設祝融側。", "鳴澗驚宵寐，清猿遞時刻。澡潔事夙興，簪佩思盡飾。", "危壇象岳趾，秘殿翹翬翼。登拜不遑願，酌獻皆累息。", "贊道儀匪繁，祝史詞甚直。忽覺心魂悸，如有精靈逼。", "漠漠雲氣生，森森杉柏黑。風吹虛簫韻，露洗寒玉色。", "寂寞有至公，馨香在明德。禮成謝邑吏，駕言歸郡職。", "憩桑訪蠶事，遵疇課農力。所願風雨時，回首瞻南極。"]'),
('yuding-9','經河源軍漢村作','呂溫','唐','御定全唐诗','yuding','','[]','行行忽到舊河源，城外千家作漢村。樵采未侵征虜墓，',40,'御定全唐詩/json/371.json','["行行忽到舊河源，城外千家作漢村。樵采未侵征虜墓，", "暫駐單車空下淚，有心無力複何言。"]'),
('yuding-10','題河州赤岸橋','呂溫','唐','御定全唐诗','yuding','','[]','左南橋上見河州，遺老相依赤岸頭。',32,'御定全唐詩/json/371.json','["左南橋上見河州，遺老相依赤岸頭。", "匝塞歌鐘受恩者，誰憐被發哭東流。"]'),
('yuding-11','題陽人城','呂溫','唐','御定全唐诗','yuding','','[]','忠驅義感即風雷，誰道南方乏武才。',32,'御定全唐詩/json/371.json','["忠驅義感即風雷，誰道南方乏武才。", "天下起兵誅董卓，長沙子弟最先來。"]'),
('yuding-12','晉王龍驤墓','呂溫','唐','御定全唐诗','yuding','','[]','虎旗龍艦順長風，坐引全吳入掌中。',32,'御定全唐詩/json/371.json','["虎旗龍艦順長風，坐引全吳入掌中。", "孫皓小兒何足取，便令千載笑爭功。"]'),
('yuding-13','題石勒城二首','呂溫','唐','御定全唐诗','yuding','','[]','長驅到處積人頭，大旆連營壓上游。',64,'御定全唐詩/json/371.json','["長驅到處積人頭，大旆連營壓上游。", "建業烏棲何足問，慨然歸去王中州。", "天生傑異固難馴，應變摧枯若有神。", "夷甫自能疑倚嘯，忍將虛誕誤時人。"]'),
('yuding-14','劉郎浦口號','呂溫','唐','御定全唐诗','yuding','','[]','吳蜀成婚此水潯，明珠步障幄黃金。',32,'御定全唐詩/json/371.json','["吳蜀成婚此水潯，明珠步障幄黃金。", "誰將一女輕天下，欲換劉郎鼎峙心。"]'),
('yuding-15','自江華之衡陽途中作','呂溫','唐','御定全唐诗','yuding','','[]','孤棹遲遲悵有違，沿湘數日逗晴暉。',32,'御定全唐詩/json/371.json','["孤棹遲遲悵有違，沿湘數日逗晴暉。", "人生隨分為憂喜，回雁峰南是北歸。"]'),
('yuding-16','吐蕃別館送楊七錄事先歸','呂溫','唐','御定全唐诗','yuding','','[]','愁雲重拂地，飛雪亂遙程。莫慮前山暗，歸人正眼明。',24,'御定全唐詩/json/371.json','["愁雲重拂地，飛雪亂遙程。莫慮前山暗，歸人正眼明。"]'),
('yuding-17','奉送范司空赴朔方','呂溫','唐','御定全唐诗','yuding','','[]','築壇登上將，膝席委前籌。虜滅南侵跡，朝分北顧憂。',72,'御定全唐詩/json/371.json','["築壇登上將，膝席委前籌。虜滅南侵跡，朝分北顧憂。", "抗旌回廣漠，撫劍動旄頭。坐見黃雲暮，行看白草秋。", "山橫舊秦塞，河繞古靈州。戍守如無事，惟應獵騎遊。"]'),
('yuding-18','送文暢上人東游','呂溫','唐','御定全唐诗','yuding','','[]','隨緣聊振錫，高步出東城。水止無恒地，雲行不計程。',48,'御定全唐詩/json/371.json','["隨緣聊振錫，高步出東城。水止無恒地，雲行不計程。", "到時為彼岸，過處即前生。今日臨岐別，吾徒自有情。"]'),
('yuding-19','喜儉北至送宗禮南行','呂溫','唐','御定全唐诗','yuding','','[]','洞庭舟始泊，桂江帆又開。魂從會處斷，愁向笑中來。',48,'御定全唐詩/json/371.json','["洞庭舟始泊，桂江帆又開。魂從會處斷，愁向笑中來。", "惝怳看殘景，殷勤祝此杯。衡陽刷羽待，成取一行回。"]'),
('yuding-20','送段九秀才歸澧州','呂溫','唐','御定全唐诗','yuding','','[]','湘南孤白芷，幽托在清潯。豈有馨香發，空勞知處深。',72,'御定全唐詩/json/371.json','["湘南孤白芷，幽托在清潯。豈有馨香發，空勞知處深。", "摧賢路已隔，賑乏力不任。慚我一言分，貞君千里心。", "寸義薄聯組，片誠敵兼金。方期踐冰雪，無使弱思侵。"]'),
('yuding-21','衡州送李十一兵曹赴浙東','呂溫','唐','御定全唐诗','yuding','','[]','慷慨視別劍，淒清泛離琴。前程楚塞斷，此恨洞庭深。',48,'御定全唐詩/json/371.json','["慷慨視別劍，淒清泛離琴。前程楚塞斷，此恨洞庭深。", "文字已久廢，循良非所任。期君碧雲上，千里一揚音。"]'),
('yuding-22','臨洮送袁七書記歸朝','呂溫','唐','御定全唐诗','yuding','','[]','憶年十五在江湄，聞說平涼且半疑。',32,'御定全唐詩/json/371.json','["憶年十五在江湄，聞說平涼且半疑。", "豈料殷勤洮水上，卻將家信託袁師。"]'),
('yuding-23','江陵酒中留別坐客','呂溫','唐','御定全唐诗','yuding','','[]','尋常縱恣倚青春，不契心期便不親。',32,'御定全唐詩/json/371.json','["尋常縱恣倚青春，不契心期便不親。", "今日煙波九疑去，相逢儘是眼中人。"]'),
('yuding-24','道州酬送何山人之容州','呂溫','唐','御定全唐诗','yuding','','[]','匣有青萍筒有書，何門不可曳長裾。',32,'御定全唐詩/json/371.json','["匣有青萍筒有書，何門不可曳長裾。", "應須定取真知者，遣對明君說子虛。"]'),
('yuding-25','道州送戴簡處士往賀州謁楊侍郎','呂溫','唐','御定全唐诗','yuding','','[]','羸馬孤童鳥道微，三千客散獨南歸。',32,'御定全唐詩/json/371.json','["羸馬孤童鳥道微，三千客散獨南歸。", "山公念舊偏知我，今日因君淚滿衣。"]'),
('yuding-26','春日游郭駙馬大安亭子','呂溫','唐','御定全唐诗','yuding','','[]','戚裏容閑客，山泉若化成。寄遊芳徑好，借賞彩船輕。',48,'御定全唐詩/json/371.json','["戚裏容閑客，山泉若化成。寄遊芳徑好，借賞彩船輕。", "春至花常滿，年多水更清。此中如傳舍，但自立功名。"]'),
('yuding-27','楚州追制後舍弟直長安縣失囚花下共飲','呂溫','唐','御定全唐诗','yuding','','[]','天子收郡印，京兆責獄囚。狂兄與狂弟，不解對花愁。',24,'御定全唐詩/json/371.json','["天子收郡印，京兆責獄囚。狂兄與狂弟，不解對花愁。"]'),
('yuding-28','衡州歲前游合江亭見山櫻蕊未折因賦含彩吝驚春','呂溫','唐','御定全唐诗','yuding','','[]','山櫻先春發，紅蕊滿霜枝。幽處竟誰見，芳心空自知。',48,'御定全唐詩/json/371.json','["山櫻先春發，紅蕊滿霜枝。幽處竟誰見，芳心空自知。", "似奪朝日照，疑畏暖風吹。欲問含彩意，恐驚輕薄兒。"]'),
('yuding-29','衡州登樓望南館臨水花，呈房戴段李諸公','呂溫','唐','御定全唐诗','yuding','','[]','夭桃臨方塘，暮色堪秋思。托根豈求潤，照影非自媚。',48,'御定全唐詩/json/371.json','["夭桃臨方塘，暮色堪秋思。托根豈求潤，照影非自媚。", "罥掛青柳絲，零落綠錢地。佳期竟何許，時有幽禽至。"]'),
('yuding-30','合江亭檻前多高竹不見遠岸花客命翦之感而成詠','呂溫','唐','御定全唐诗','yuding','','[]','吉凶豈前卜，人事何翻覆。緣看數日花，卻翦淩霜竹。',48,'御定全唐詩/json/371.json','["吉凶豈前卜，人事何翻覆。緣看數日花，卻翦淩霜竹。", "常言契君操，今乃妨眾目。自古病當門，誰言出幽獨。"]'),
('yuding-31','道州春遊歐陽家林亭','呂溫','唐','御定全唐诗','yuding','','[]','道州城北歐陽家，去郭一裏占煙霞。主人雖朴甚有思，',40,'御定全唐詩/json/371.json','["道州城北歐陽家，去郭一裏占煙霞。主人雖朴甚有思，", "政成興足告即歸，門前便是家山道。"]'),
('yuding-32','衡州早春偶游黃溪口號','呂溫','唐','御定全唐诗','yuding','','[]','偶尋黃溪日欲沒，早梅未盡山櫻發。',32,'御定全唐詩/json/371.json','["偶尋黃溪日欲沒，早梅未盡山櫻發。", "無事江城閉此身，不得坐待花間月。"]'),
('yuding-33','衡州夜後把火看花留客','呂溫','唐','御定全唐诗','yuding','','[]','紅芳暗落碧池頭，把火遙看且少留。',32,'御定全唐詩/json/371.json','["紅芳暗落碧池頭，把火遙看且少留。", "半夜忽然風更起，明朝不復上南樓。"]'),
('yuding-34','夜後把火看花南園招李十一兵曹不至呈座上諸公','呂溫','唐','御定全唐诗','yuding','','[]','夭桃紅燭正相鮮，傲吏閑齋困獨眠。',32,'御定全唐詩/json/371.json','["夭桃紅燭正相鮮，傲吏閑齋困獨眠。", "應是夢中飛作蝶，悠揚只在此花前。"]'),
('yuding-35','順宗至德大聖大安孝皇帝挽歌詞三首','呂溫','唐','御定全唐诗','yuding','','[]','遐視輕神寶，傳歸屬聖猷。堯功終有待，文德本無憂。',144,'御定全唐詩/json/371.json','["遐視輕神寶，傳歸屬聖猷。堯功終有待，文德本無憂。", "坐受朝汾水，行看告岱丘。那知鼎成後，龍馭弗淹留。", "監撫垂三紀，聲徽洽萬方。禮因馳道著，明自墾田彰。", "積漸承鴻業，從容守太康。更留園寢詔，恭聽有餘芳。", "早秋同軌至，晨旆露華滋。挽度千夫咽，笳凝六馬遲。", "劍悲長閉日，衣望出遊時。風起西陵樹，淒涼滿孝思。"]'),
('yuding-36','詠蜀客石琴枕','呂溫','唐','御定全唐诗','yuding','','[]','可憐他山石，幾度負貞堅。推遷強為用，雕斫傷自然。',48,'御定全唐詩/json/371.json','["可憐他山石，幾度負貞堅。推遷強為用，雕斫傷自然。", "文含巴江浪，色起青城煙。更聞餘玉聲，時入朱絲弦。"]'),
('yuding-37','河南府試贖帖，賦得鄉飲酒詩','呂溫','唐','御定全唐诗','yuding','','[]','酌言修舊典，刈楚始登堂。百拜賓儀盡，三終樂奏長。',48,'御定全唐詩/json/371.json','["酌言修舊典，刈楚始登堂。百拜賓儀盡，三終樂奏長。", "想同鶯出穀，看似雁成行。禮罷知何適，隨雲入帝鄉。"]'),
('yuding-38','賦得失群鶴','呂溫','唐','御定全唐诗','yuding','','[]','杳杳沖天鶴，風排勢暫違。有心長自負，無伴可相依。',48,'御定全唐詩/json/371.json','["杳杳沖天鶴，風排勢暫違。有心長自負，無伴可相依。", "萬里寧辭遠，三山詎憶歸。但令毛羽在，何處不翻飛。"]'),
('yuding-39','道州南樓換柱','呂溫','唐','御定全唐诗','yuding','','[]','鴻災起無朕，有見非前知。蟻入不足恤，柱傾何可追。',48,'御定全唐詩/json/371.json','["鴻災起無朕，有見非前知。蟻入不足恤，柱傾何可追。", "良工操斤斧，沉吟方在斯。殫材事朽廢，曷若新宏規。"]'),
('yuding-40','道州北池放鵝','呂溫','唐','御定全唐诗','yuding','','[]','我非好鵝癖，爾乏鳴雁姿。安得免沸鼎，澹然游清池。',48,'御定全唐詩/json/371.json','["我非好鵝癖，爾乏鳴雁姿。安得免沸鼎，澹然游清池。", "見生不忍食，深情固在斯。能自遠飛去，無念稻粱為。"]'),
('yuding-41','回風有懷','呂溫','唐','御定全唐诗','yuding','','[]','銀宮翠島煙霏霏，珠樹玲瓏朝日暉。',32,'御定全唐詩/json/371.json','["銀宮翠島煙霏霏，珠樹玲瓏朝日暉。", "神仙望見不得到，卻逐回風何處歸。"]'),
('yuding-42','蕃中答退渾詞二首','呂溫','唐','御定全唐诗','yuding','','[]','退渾兒，退渾兒，朔風長在氣何衰。',64,'御定全唐詩/json/371.json','["退渾兒，退渾兒，朔風長在氣何衰。", "萬群鐵馬從奴虜，強弱由人莫歎時。", "退渾兒，退渾兒，冰消青海草如絲。", "明堂天子朝萬國，神島龍駒將與誰。"]'),
('yuding-43','上官昭容書樓歌','呂溫','唐','御定全唐诗','yuding','','[]','漢家婕妤唐昭容，工詩能賦千載同。自言才藝是天真，',119,'御定全唐詩/json/371.json','["漢家婕妤唐昭容，工詩能賦千載同。自言才藝是天真，", "玉樓寶架中天居，緘奇秘異萬卷餘。水精編帙綠鈿軸，", "香囊盛煙繡結絡，翠羽拂案青琉璃。吟披嘯卷終無已，", "碧雲起，心悠哉，境深轉苦坐自摧。金梯珠履聲一斷，", "神仙杳何許，遺逸滿人間。君不見洛陽南市賣書肆，"]'),
('yuding-44','聞砧有感','呂溫','唐','御定全唐诗','yuding','','[]','千門儼雲端，此地富羅紈。秋月三五夜，砧聲滿長安。',48,'御定全唐詩/json/371.json','["千門儼雲端，此地富羅紈。秋月三五夜，砧聲滿長安。", "幽人感中懷，靜聽淚汍瀾。所恨擣衣者，不知天下寒。"]'),
('yuding-45','早覺有感','呂溫','唐','御定全唐诗','yuding','','[]','東方殊未明，暗室蟲正飛。先覺忽先起，衣裳顛倒時。',48,'御定全唐詩/json/371.json','["東方殊未明，暗室蟲正飛。先覺忽先起，衣裳顛倒時。", "嚴冬寒漏長，此夜如何其。不用思秉燭，扶桑有清暉。"]'),
('yuding-46','冬日病中即事','呂溫','唐','御定全唐诗','yuding','','[]','牆下長安道，囂塵咫尺間。久牽身外役，暫得病中閑。',48,'御定全唐詩/json/371.json','["牆下長安道，囂塵咫尺間。久牽身外役，暫得病中閑。", "背喜朝陽滿，心憐暮鳥還。吾廬在何處，南有白雲山。"]'),
('yuding-47','病中自戶部員外郎轉司封','呂溫','唐','御定全唐诗','yuding','','[]','羸臥承新命，優容獲所安。遣兒迎賀客，無力拂塵冠。',48,'御定全唐詩/json/371.json','["羸臥承新命，優容獲所安。遣兒迎賀客，無力拂塵冠。", "偃仰晴軒暖，支離曉鏡寒。那堪報恩去，感激對衰蘭。"]'),
('yuding-48','久病初朝衢中即事','呂溫','唐','御定全唐诗','yuding','','[]','沉屙曠十旬，還過直城闉。老馬猶知路，羸童欲怕人。',48,'御定全唐詩/json/371.json','["沉屙曠十旬，還過直城闉。老馬猶知路，羸童欲怕人。", "久隳三徑計，更強百年身。許國將何力，空生衣上塵。"]'),
('yuding-49','道州城北樓觀李花','呂溫','唐','御定全唐诗','yuding','','[]','夜疑關山月，曉似沙場雪。曾使西域來，幽情望超越。',48,'御定全唐詩/json/371.json','["夜疑關山月，曉似沙場雪。曾使西域來，幽情望超越。", "將念浩無際，欲言忘所說。豈是花感人，自憐抱孤節。"]'),
('yuding-50','道州秋夜南樓即事','呂溫','唐','御定全唐诗','yuding','','[]','誰念獨坐愁，日暮此南樓。雲去舜祠閉，月明瀟水流。',48,'御定全唐詩/json/371.json','["誰念獨坐愁，日暮此南樓。雲去舜祠閉，月明瀟水流。", "猿聲何處曉，楓葉滿山秋。不分匣中鏡，少年看白頭。"]'),
('yuding-51','道州觀野火','呂溫','唐','御定全唐诗','yuding','','[]','南風吹烈火，焰焰燒楚澤。陽景當晝遲，陰天半夜赤。',120,'御定全唐詩/json/371.json','["南風吹烈火，焰焰燒楚澤。陽景當晝遲，陰天半夜赤。", "過處若彗掃，來時如電激。豈複辨蕭蘭，焉能分玉石。", "蟲蛇盡爍爛，虎兕出奔迫。積穢皆蕩除，和氣始融液。", "堯時既敬授，禹稼斯肇跡。遍生合穎禾，大秀兩岐麥。", "家有京坻詠，人無溝壑戚。乃悟焚如功，來歲終受益。"]'),
('yuding-52','衡州早春二首','呂溫','唐','御定全唐诗','yuding','','[]','碧水何逶迤，東風吹沙草。煙波千萬曲，不辨嵩陽道。',48,'御定全唐詩/json/371.json','["碧水何逶迤，東風吹沙草。煙波千萬曲，不辨嵩陽道。", "病肺不飲酒，傷心不看花。惟驚望鄉處，猶自隔長沙。"]'),
('yuding-53','郡內書懷寄劉連州竇夔州','呂溫','唐','御定全唐诗','yuding','','[]','朱邑何為者，桐鄉有古祠。我心常所慕，二郡老人知。',24,'御定全唐詩/json/371.json','["朱邑何為者，桐鄉有古祠。我心常所慕，二郡老人知。"]'),
('yuding-54','偶然作二首','呂溫','唐','御定全唐诗','yuding','','[]','棲棲複汲汲，忽覺年四十。今朝滿衣淚，不是傷春泣。',48,'御定全唐詩/json/371.json','["棲棲複汲汲，忽覺年四十。今朝滿衣淚，不是傷春泣。", "中夜兀然坐，無言空涕洟。丈夫志氣事，兒女安得知。"]'),
('yuding-55','古興','呂溫','唐','御定全唐诗','yuding','','[]','越歐百煉時，楚卞三泣地。二寶無人識，千齡皆棄置。',72,'御定全唐詩/json/371.json','["越歐百煉時，楚卞三泣地。二寶無人識，千齡皆棄置。", "空岩起白虹，古獄生紫氣。安得命世客，直來開奧秘。", "劍任刜鐘看，玉從投火試。必能絕疑惑，然後論奇異。"]'),
('yuding-56','風詠','呂溫','唐','御定全唐诗','yuding','','[]','微風生青蘋，習習出金塘。輕搖深林翠，靜獵幽徑芳。',84,'御定全唐詩/json/371.json','["微風生青蘋，習習出金塘。輕搖深林翠，靜獵幽徑芳。", "掩抑時未來，鴻毛亦無傷。一朝乘嚴氣，萬里號清霜。", "北走摧鄧林，東去落扶桑。掃卻垂天雲，澄清無私光。", "悠然返空寂，晏海通舟航。"]'),
('yuding-57','鏡中歎白髮','呂溫','唐','御定全唐诗','yuding','','[]','年過潘嶽才三歲，還見星星兩鬢中。',32,'御定全唐詩/json/371.json','["年過潘嶽才三歲，還見星星兩鬢中。", "縱使他時能早達，定知不作黑頭公。"]'),
('yuding-58','友人邀聽歌有感','呂溫','唐','御定全唐诗','yuding','','[]','文章拋盡愛功名，三十無成白髮生。',32,'御定全唐詩/json/371.json','["文章拋盡愛功名，三十無成白髮生。", "辜負壯心羞欲死，勞君貴買斷腸聲。"]'),
('yuding-59','貞元十四年旱甚，見權門移芍藥花','呂溫','唐','御定全唐诗','yuding','','[]','綠原青壟漸成塵，汲井開園日日新。',32,'御定全唐詩/json/371.json','["綠原青壟漸成塵，汲井開園日日新。", "四月帶花移芍藥，不知憂國是何人。"]'),
('yuding-60','冬夜即事','呂溫','唐','御定全唐诗','yuding','','[]','百憂攢心起複臥，夜長耿耿不可過。',32,'御定全唐詩/json/371.json','["百憂攢心起複臥，夜長耿耿不可過。", "風吹雪片似花落，月照冰文如鏡破。"]'),
('yuding-61','道州郡齋臥疾寄東館諸賢','呂溫','唐','御定全唐诗','yuding','','[]','東池送客醉年華，聞道風流勝習家。',32,'御定全唐詩/json/371.json','["東池送客醉年華，聞道風流勝習家。", "獨臥郡齋寥落意，隔簾微雨濕梨花。"]'),
('yuding-62','讀小弟詩有感，因口號以示之','呂溫','唐','御定全唐诗','yuding','','[]','憶吾未冠賞年華，二十年間在咄嗟。',32,'御定全唐詩/json/371.json','["憶吾未冠賞年華，二十年間在咄嗟。", "今來羨汝看花歲，似汝追思昨日花。"]'),
('yuding-63','讀句踐傳','呂溫','唐','御定全唐诗','yuding','','[]','丈夫可殺不可羞，如何送我海西頭。',32,'御定全唐詩/json/371.json','["丈夫可殺不可羞，如何送我海西頭。", "更生更聚終須報，二十年間死即休。"]'),
('yuding-64','道州月歎','呂溫','唐','御定全唐诗','yuding','','[]','別館月，犁牛冰河金山雪。道州月，霜樹子規啼是血。',40,'御定全唐詩/json/371.json','["別館月，犁牛冰河金山雪。道州月，霜樹子規啼是血。", "壯心感此孤劍鳴，沉火在灰殊未滅。"]'),
('yuding-65','風歎','呂溫','唐','御定全唐诗','yuding','','[]','青海風，飛沙射面隨驚蓬。洞庭風，危牆欲折身若空。',40,'御定全唐詩/json/371.json','["青海風，飛沙射面隨驚蓬。洞庭風，危牆欲折身若空。", "西馳南走有何事，會須一決百年中。"]'),
('yuding-66','道州感興','呂溫','唐','御定全唐诗','yuding','','[]','當代知文字，先皇記姓名。七年天下立，萬里海西行。',48,'御定全唐詩/json/371.json','["當代知文字，先皇記姓名。七年天下立，萬里海西行。", "苦節終難辨，勞生竟自輕。今朝流落處，嘯水繞孤城。"]'),
('yuding-67','和李使君三郎早秋城北亭宴崔司士因寄關中張評事','呂溫','唐','御定全唐诗','yuding','','[]','黃花古城路，上盡見青山。桑柘晴川口，牛羊落照間。',72,'御定全唐詩/json/371.json','["黃花古城路，上盡見青山。桑柘晴川口，牛羊落照間。", "野情隨卷幔，塵事隔重關。道合偏重賞，官微獨不閑。", "鶴分琴久罷，書到雁應還。為謝登臨客，瓊林寄一攀。"]'),
('yuding-68','題從叔園林','呂溫','唐','御定全唐诗','yuding','','[]','阮宅閑園暮，窗中見樹陰。樵歌依野草，僧語過長林。',48,'御定全唐詩/json/371.json','["阮宅閑園暮，窗中見樹陰。樵歌依野草，僧語過長林。", "鳥向花間井，人彈竹裏琴。自嫌身未老，已有住山心。"]'),
('yuding-69','送僧歸漳州','呂溫','唐','御定全唐诗','yuding','','[]','幾夏京城住，今朝獨遠歸。修行四分律，護淨七條衣。',48,'御定全唐詩/json/371.json','["幾夏京城住，今朝獨遠歸。修行四分律，護淨七條衣。", "溪寺黃橙熟，沙田紫芋肥。九龍潭上路，同去客應稀。"]'),
('yuding-0','列女操','孟郊','唐','御定全唐诗','yuding','','[]','梧桐相待老，鴛鴦會雙死。貞女貴徇夫，舍生亦如此。',36,'御定全唐詩/json/372.json','["梧桐相待老，鴛鴦會雙死。貞女貴徇夫，舍生亦如此。", "波瀾誓不起，妾心井中水。"]'),
('yuding-1','灞上輕薄行','孟郊','唐','御定全唐诗','yuding','','[]','長安無緩步，況值天景暮。相逢灞滻間，親戚不相顧。',60,'御定全唐詩/json/372.json','["長安無緩步，況值天景暮。相逢灞滻間，親戚不相顧。", "自歎方拙身，忽隨輕薄倫。常恐失所避，化為車轍塵。", "此中生白髮，疾走亦未歇。"]'),
('yuding-2','長安羈旅行','孟郊','唐','御定全唐诗','yuding','','[]','十日一理髮，每梳飛旅塵。三旬九過飲，每食唯舊貧。',96,'御定全唐詩/json/372.json','["十日一理髮，每梳飛旅塵。三旬九過飲，每食唯舊貧。", "萬物皆及時，獨餘不覺春。失名誰肯訪，得意爭相親。", "直木有恬翼，靜流無躁鱗。始知喧競場，莫處君子身。", "野策藤竹輕，山蔬薇蕨新。潛歌歸去來，事外風景真。"]'),
('yuding-3','長安道','孟郊','唐','御定全唐诗','yuding','','[]','胡風激秦樹，賤子風中泣。家家朱門開，得見不可入。',48,'御定全唐詩/json/372.json','["胡風激秦樹，賤子風中泣。家家朱門開，得見不可入。", "長安十二衢，投樹鳥亦急。高閣何人家，笙簧正喧吸。"]'),
('yuding-4','送遠吟','孟郊','唐','御定全唐诗','yuding','','[]','河水昏複晨，河邊相送頻。離杯有淚飲，別柳無枝春。',48,'御定全唐詩/json/372.json','["河水昏複晨，河邊相送頻。離杯有淚飲，別柳無枝春。", "一笑忽然斂，萬愁俄已新。東波與西日，不惜遠行人。"]'),
('yuding-5','古薄命妾','孟郊','唐','御定全唐诗','yuding','','[]','不惜十指弦，為君千萬彈。常恐新聲至，坐使故聲殘。',72,'御定全唐詩/json/372.json','["不惜十指弦，為君千萬彈。常恐新聲至，坐使故聲殘。", "棄置今日悲，即是昨日歡。將新變故易，持故為新難。", "青山有蘼蕪，淚葉長不幹。空令後代人，采掇幽思攢。"]'),
('yuding-6','古離別','孟郊','唐','御定全唐诗','yuding','','[]','松山雲繚繞，萍路水分離。雲去有歸日，水分無合時。',48,'御定全唐詩/json/372.json','["松山雲繚繞，萍路水分離。雲去有歸日，水分無合時。", "春芳役雙眼，春色柔四支。楊柳織別愁，千條萬條絲。"]'),
('yuding-7','雜怨','孟郊','唐','御定全唐诗','yuding','','[]','憶人莫至悲，至悲空自衰。寄人莫剪衣，剪衣未必歸。',156,'御定全唐詩/json/372.json','["憶人莫至悲，至悲空自衰。寄人莫剪衣，剪衣未必歸。", "朝為雙蒂花，莫為四散飛。花落還繞樹，遊子不顧期。", "夭桃花清晨，遊女紅粉新。夭桃花薄暮，遊女紅粉故。", "樹有百年花，人無一定顏。花送人老盡，人悲花自閑。", "貧女鏡不明，寒花日少容。暗蛩有虛織，短線無長縫。", "浪水不可照，狂夫不可從。浪水多散影，狂夫多異蹤。", "持此一生薄，空成萬恨濃。"]'),
('yuding-8','靜女吟','孟郊','唐','御定全唐诗','yuding','','[]','豔女皆妒色，靜女獨檢蹤。任禮恥任妝，嫁德不嫁容。',48,'御定全唐詩/json/372.json','["豔女皆妒色，靜女獨檢蹤。任禮恥任妝，嫁德不嫁容。", "君子易求聘，小人難自從。此志誰與諒，琴弦幽韻重。"]'),
('yuding-9','歸信吟','孟郊','唐','御定全唐诗','yuding','','[]','淚墨灑為書，將寄萬里親。書去魂亦去，兀然空一身。',24,'御定全唐詩/json/372.json','["淚墨灑為書，將寄萬里親。書去魂亦去，兀然空一身。"]'),
('yuding-10','山老吟','孟郊','唐','御定全唐诗','yuding','','[]','不行山下地，唯種山上田。腰斧斫旅松，手瓢汲家泉。',48,'御定全唐詩/json/372.json','["不行山下地，唯種山上田。腰斧斫旅松，手瓢汲家泉。", "詎知文字力，莫記日月遷。蟠木為我身，始得全天年。"]'),
('yuding-11','遊子吟','孟郊','唐','御定全唐诗','yuding','','[]','慈母手中線，遊子身上衣。臨行密密縫，意恐遲遲歸。',36,'御定全唐詩/json/372.json','["慈母手中線，遊子身上衣。臨行密密縫，意恐遲遲歸。", "誰言寸草心，報得三春暉。"]'),
('yuding-12','小隱吟','孟郊','唐','御定全唐诗','yuding','','[]','我飲不在醉，我歡長寂然。酌溪四五盞，聽彈兩三弦。',48,'御定全唐詩/json/372.json','["我飲不在醉，我歡長寂然。酌溪四五盞，聽彈兩三弦。", "煉性靜棲白，洗情深寄玄。號怒路傍子，貪敗不貪全。"]'),
('yuding-13','苦寒吟','孟郊','唐','御定全唐诗','yuding','','[]','天寒色青蒼，北風叫枯桑。厚冰無裂文，短日有冷光。',48,'御定全唐詩/json/372.json','["天寒色青蒼，北風叫枯桑。厚冰無裂文，短日有冷光。", "敲石不得火，壯陰奪正陽。苦調竟何言，凍吟成此章。"]'),
('yuding-14','猛將吟','孟郊','唐','御定全唐诗','yuding','','[]','擬膾樓蘭肉，蓄怒時未揚。秋鼙無退聲，夜劍不隱光。',48,'御定全唐詩/json/372.json','["擬膾樓蘭肉，蓄怒時未揚。秋鼙無退聲，夜劍不隱光。", "虎隊手驅出，豹篇心卷藏。古今皆有言，猛將出北方。"]'),
('yuding-15','傷哉行','孟郊','唐','御定全唐诗','yuding','','[]','眾毒蔓貞松，一枝難久榮。豈知黃庭客，仙骨生不成。',72,'御定全唐詩/json/372.json','["眾毒蔓貞松，一枝難久榮。豈知黃庭客，仙骨生不成。", "春色舍芳蕙，秋風繞枯莖。彈琴不成曲，始覺知音傾。", "館月改舊照，吊賓寫餘情。還舟空江上，波浪送銘旌。"]'),
('yuding-16','怨詩','孟郊','唐','御定全唐诗','yuding','','[]','試妾與君淚，兩處滴池水。看取芙蓉花，今年為誰死。',24,'御定全唐詩/json/372.json','["試妾與君淚，兩處滴池水。看取芙蓉花，今年為誰死。"]'),
('yuding-17','湘弦怨','孟郊','唐','御定全唐诗','yuding','','[]','昧者理芳草，蒿蘭同一鋤。狂飆怒秋林，曲直同一枯。',96,'御定全唐詩/json/372.json','["昧者理芳草，蒿蘭同一鋤。狂飆怒秋林，曲直同一枯。", "嘉木忌深蠹，哲人悲巧誣。靈均入回流，靳尚為良謨。", "我願分眾泉，清濁各異渠。我願分眾巢，梟鸞相遠居。", "此志諒難保，此情竟何如。湘弦少知音，孤響空踟躕。"]'),
('yuding-18','楚竹吟酬盧虔端公見和湘弦怨','孟郊','唐','御定全唐诗','yuding','','[]','握中有新聲，楚竹人未聞。識音者謂誰，清夜吹贈君。',96,'御定全唐詩/json/372.json','["握中有新聲，楚竹人未聞。識音者謂誰，清夜吹贈君。", "昔為瀟湘引，曾動瀟湘雲。一叫鳳改聽，再驚鶴失群。", "江花匪秋落，山日當晝曛。眾濁響雜遝，孤清思氛氳。", "欲知怨有形，願向明月分。一掬靈均淚，千年湘水文。"]'),
('yuding-19','遠愁曲','孟郊','唐','御定全唐诗','yuding','','[]','飄颻何所從，遺塚行未逢。東西不見人，哭向青青松。',72,'御定全唐詩/json/372.json','["飄颻何所從，遺塚行未逢。東西不見人，哭向青青松。", "此地有時盡，此哀無處容。聲翻太白雲，淚洗藍田峰。", "水涉七八曲，山登千萬重。願邀玄夜月，出視白日蹤。"]'),
('yuding-20','貧女詞寄從叔先輩簡','孟郊','唐','御定全唐诗','yuding','','[]','蠶女非不勤，今年獨無春。二月冰雪深，死盡萬木身。',60,'御定全唐詩/json/372.json','["蠶女非不勤，今年獨無春。二月冰雪深，死盡萬木身。", "時令自逆行，造化豈不仁。仰企碧霞仙，高控滄海雲。", "永別勞苦場，飄颻遊無垠。"]'),
('yuding-21','邊城吟','孟郊','唐','御定全唐诗','yuding','','[]','西城近日天，俗稟氣候偏。行子獨自渴，主人仍賣泉。',48,'御定全唐詩/json/372.json','["西城近日天，俗稟氣候偏。行子獨自渴，主人仍賣泉。", "燒烽碧雲外，牧馬青坡巔。何處鶻突夢，歸思寄仰眠。"]'),
('yuding-22','新平歌送許問','孟郊','唐','御定全唐诗','yuding','','[]','邊柳三四尺，暮春離別歌。早回儒士駕，莫飲土番河。',36,'御定全唐詩/json/372.json','["邊柳三四尺，暮春離別歌。早回儒士駕，莫飲土番河。", "誰識匣中寶，楚雲章句多。"]'),
('yuding-23','殺氣不在邊','孟郊','唐','御定全唐诗','yuding','','[]','殺氣不在邊，凜然中國秋。道險不在山，平地有摧輈。',132,'御定全唐詩/json/372.json','["殺氣不在邊，凜然中國秋。道險不在山，平地有摧輈。", "河南又起兵，清濁俱鎖流。豈唯私客艱，擁滯官行舟。", "況餘隔晨昏，去家成阻修。忽然兩鬢雪，同是一日愁。", "獨寢夜難曉，起視星漢浮。涼風蕩天地，日夕聲颼飀。", "萬物無少色，兆人皆老憂。長策苟未立，丈夫誠可羞。", "靈響複何事，劍鳴思戮讎。"]'),
('yuding-24','結愛','孟郊','唐','御定全唐诗','yuding','','[]','心心複心心，結愛務在深。一度欲離別，千回結衣襟。',60,'御定全唐詩/json/372.json','["心心複心心，結愛務在深。一度欲離別，千回結衣襟。", "結妾獨守志，結君早歸意。始知結衣裳，不如結心腸。", "坐結行亦結，結盡百年月。"]'),
('yuding-25','弦歌行','孟郊','唐','御定全唐诗','yuding','','[]','驅儺擊鼓吹長笛，瘦鬼染面惟齒白。暗中崒崒拽茅鞭，',24,'御定全唐詩/json/372.json','["驅儺擊鼓吹長笛，瘦鬼染面惟齒白。暗中崒崒拽茅鞭，"]'),
('yuding-26','覆巢行','孟郊','唐','御定全唐诗','yuding','','[]','荒城古木枝多枯，飛禽嗷嗷朝哺雛。枝傾巢覆雛墜地，',48,'御定全唐詩/json/372.json','["荒城古木枝多枯，飛禽嗷嗷朝哺雛。枝傾巢覆雛墜地，", "枝危巢小風雨多，未容長成已先覆。靈枝珍木滿上林，"]'),
('yuding-27','出門行','孟郊','唐','御定全唐诗','yuding','','[]','長河悠悠去無極，百齡同此可歎息。秋風白露沾人衣，',96,'御定全唐詩/json/372.json','["長河悠悠去無極，百齡同此可歎息。秋風白露沾人衣，", "一聞陌上苦寒奏，使我佇立驚且悲。君今得意厭粱肉，", "海風蕭蕭天雨霜，窮愁獨坐夜何長。驅車舊憶太行險，", "手持琅玕欲有贈，愛而不見心斷絕。南山峨峨白石爛，"]'),
('yuding-28','湘妃怨','孟郊','唐','御定全唐诗','yuding','','[]','南巡竟不返，二妃怨逾積。萬里喪蛾眉，瀟湘水空碧。',72,'御定全唐詩/json/372.json','["南巡竟不返，二妃怨逾積。萬里喪蛾眉，瀟湘水空碧。", "冥冥荒山下，古廟收貞魄。喬木深青春，清光滿瑤席。", "搴芳徒有薦，靈意殊脈脈。玉佩不可親，徘徊煙波夕。"]'),
('yuding-29','巫山曲','孟郊','唐','御定全唐诗','yuding','','[]','巴江上峽重複重，陽臺碧峭十二峰。荊王獵時逢暮雨，',40,'御定全唐詩/json/372.json','["巴江上峽重複重，陽臺碧峭十二峰。荊王獵時逢暮雨，", "目極魂斷望不見，猿啼三聲淚滴衣。"]'),
('yuding-30','巫山高','孟郊','唐','御定全唐诗','yuding','','[]','見盡數萬里，不聞三聲猿。但飛蕭蕭雨，中有亭亭魂。',48,'御定全唐詩/json/372.json','["見盡數萬里，不聞三聲猿。但飛蕭蕭雨，中有亭亭魂。", "千載楚王恨，遺文宋玉言。至今晴明天，雲結深閨門。"]'),
('yuding-31','楚怨','孟郊','唐','御定全唐诗','yuding','','[]','秋入楚江水，獨照汨羅魂。手把綠荷泣，意愁珠淚翻。',36,'御定全唐詩/json/372.json','["秋入楚江水，獨照汨羅魂。手把綠荷泣，意愁珠淚翻。", "九門不可入，一犬吠千門。"]'),
('yuding-32','塘下行','孟郊','唐','御定全唐诗','yuding','','[]','塘邊日欲斜，年少早還家。徒將白羽扇，調妾木蘭花。',36,'御定全唐詩/json/372.json','["塘邊日欲斜，年少早還家。徒將白羽扇，調妾木蘭花。", "不是城頭樹，那棲來去鴉。"]'),
('yuding-33','臨池曲','孟郊','唐','御定全唐诗','yuding','','[]','池中春蒲葉如帶，紫菱成角蓮子大。',32,'御定全唐詩/json/372.json','["池中春蒲葉如帶，紫菱成角蓮子大。", "羅裙蟬鬢倚迎風，雙雙伯勞飛向東。"]'),
('yuding-34','車遙遙','孟郊','唐','御定全唐诗','yuding','','[]','路喜到江盡，江上又通舟。舟車兩無阻，何處不得遊。',96,'御定全唐詩/json/372.json','["路喜到江盡，江上又通舟。舟車兩無阻，何處不得遊。", "丈夫四方志，女子安可留。郎自別日言，無令生遠愁。", "旅雁忽叫月，斷猿寒啼秋。此夕夢君夢，君在百城樓。", "寄淚無因波，寄恨無因輈。願為馭者手，與郎回馬頭。"]'),
('yuding-35','征婦怨','孟郊','唐','御定全唐诗','yuding','','[]','良人昨日去，明月又不圓。別時各有淚，零落青樓前。',108,'御定全唐詩/json/372.json','["良人昨日去，明月又不圓。別時各有淚，零落青樓前。", "君淚濡羅巾，妾淚滿路塵。羅巾長在手，今得隨妾身。", "路塵如得風，得上君車輪。", "漁陽千里道，近如中門限。中門逾有時，漁陽長在眼。", "生在綠羅下，不識漁陽道。良人自戍來，夜夜夢中到。"]'),
('yuding-36','空城雀','孟郊','唐','御定全唐诗','yuding','','[]','一雀入官倉，所食寧損幾。只慮往覆頻，官倉終害爾。',48,'御定全唐詩/json/372.json','["一雀入官倉，所食寧損幾。只慮往覆頻，官倉終害爾。", "魚網不在天，鳥羅不張水。飲啄要自然，可以空城裏。"]'),
('yuding-37','閑怨','孟郊','唐','御定全唐诗','yuding','','[]','妾恨比斑竹，下盤煩冤根。有筍未出土，中已含淚痕。',24,'御定全唐詩/json/372.json','["妾恨比斑竹，下盤煩冤根。有筍未出土，中已含淚痕。"]'),
('yuding-38','羽林行','孟郊','唐','御定全唐诗','yuding','','[]','朔雪寒斷指，朔風勁裂冰。胡中射雕者，此日猶不能。',48,'御定全唐詩/json/372.json','["朔雪寒斷指，朔風勁裂冰。胡中射雕者，此日猶不能。", "翩翩羽林兒，錦臂飛蒼鷹。揮鞭快白馬，走出黃河淩。"]'),
('yuding-39','古意','孟郊','唐','御定全唐诗','yuding','','[]','河邊織女星，河畔牽牛郎。未得渡清淺，相對遙相望。',24,'御定全唐詩/json/372.json','["河邊織女星，河畔牽牛郎。未得渡清淺，相對遙相望。"]'),
('yuding-40','古別離','孟郊','唐','御定全唐诗','yuding','','[]','欲別牽郎衣，郎今到何處。不恨歸來遲，莫向臨邛去。',24,'御定全唐詩/json/372.json','["欲別牽郎衣，郎今到何處。不恨歸來遲，莫向臨邛去。"]'),
('yuding-41','遊俠行','孟郊','唐','御定全唐诗','yuding','','[]','壯士性剛決，火中見石裂。殺人不回頭，輕生如暫別。',48,'御定全唐詩/json/372.json','["壯士性剛決，火中見石裂。殺人不回頭，輕生如暫別。", "豈知眼有淚，肯白頭上發。半生無恩酬，劍閑一百月。"]'),
('yuding-42','黃雀吟','孟郊','唐','御定全唐诗','yuding','','[]','黃雀舞承塵，倚恃主人仁。主人忽不仁，買彈彈爾身。',72,'御定全唐詩/json/372.json','["黃雀舞承塵，倚恃主人仁。主人忽不仁，買彈彈爾身。", "何不遠飛去，蓬蒿正繁新。蒿粒無人爭，食之足為珍。", "莫覷翻車粟，覷翻罪有因。黃雀不知言，贈之徒殷勤。"]'),
('yuding-43','有所思','孟郊','唐','御定全唐诗','yuding','','[]','桔槔烽火晝不滅，客路迢迢信難越。古鎮刀攢萬片霜，',24,'御定全唐詩/json/372.json','["桔槔烽火晝不滅，客路迢迢信難越。古鎮刀攢萬片霜，"]'),
('yuding-44','求仙曲','孟郊','唐','御定全唐诗','yuding','','[]','仙教生為門，仙宗靜為根。持心若妄求，服食安足論。',48,'御定全唐詩/json/372.json','["仙教生為門，仙宗靜為根。持心若妄求，服食安足論。", "鏟惑有靈藥，餌真成本源。自當出塵網，馭鳳登昆侖。"]'),
('yuding-45','嬋娟篇','孟郊','唐','御定全唐诗','yuding','','[]','花嬋娟，泛春泉。竹嬋娟，籠曉煙。妓嬋娟，不長妍。',64,'御定全唐詩/json/372.json','["花嬋娟，泛春泉。竹嬋娟，籠曉煙。妓嬋娟，不長妍。", "月嬋娟，真可憐。夜半姮娥朝太一，人間本自無靈匹。", "漢宮承寵不多時，飛燕婕妤相妒嫉。"]'),
('yuding-46','南浦篇','孟郊','唐','御定全唐诗','yuding','','[]','南浦桃花亞水紅，水邊柳絮由春風。鳥鳴喈喈煙濛濛，',24,'御定全唐詩/json/372.json','["南浦桃花亞水紅，水邊柳絮由春風。鳥鳴喈喈煙濛濛，"]'),
('yuding-47','清東曲','孟郊','唐','御定全唐诗','yuding','','[]','櫻桃花參差，香雨紅霏霏。含笑競攀折，美人濕羅衣。',60,'御定全唐詩/json/372.json','["櫻桃花參差，香雨紅霏霏。含笑競攀折，美人濕羅衣。", "采采清東曲，明眸豔珪玉。青巾艑上郎，上下看不足。", "南陽公首詞，編入新樂錄。"]'),
('yuding-48','望遠曲','孟郊','唐','御定全唐诗','yuding','','[]','朝朝候歸信，日日登高台。行人未去植庭梅，',44,'御定全唐詩/json/372.json','["朝朝候歸信，日日登高台。行人未去植庭梅，", "愁來望遠煙塵隔，空憐綠鬢風吹白。何當歸見遠行客。"]'),
('yuding-0','織婦辭','孟郊','唐','御定全唐诗','yuding','','[]','夫是田中郎，妾是田中女。當年嫁得君，為君秉機杼。',60,'御定全唐詩/json/373.json','["夫是田中郎，妾是田中女。當年嫁得君，為君秉機杼。", "筋力日已疲，不息窗下機。如何織紈素，自著藍縷衣。", "官家榜村路，更索栽桑樹。"]'),
('yuding-1','古意','孟郊','唐','御定全唐诗','yuding','','[]','蕩子守邊戍，佳人莫相從。去來年月多，苦愁改形容。',204,'御定全唐詩/json/373.json','["蕩子守邊戍，佳人莫相從。去來年月多，苦愁改形容。", "上山複下山，踏草成古蹤。徒言采蘼蕪，十度一不逢。", "鑒獨是明月，識志唯寒松。井桃始開花，一見悲萬重。", "人顏不再春，桃色有再濃。捐氣入空房，無憀乍從容。", "啟貼理針線，非獨學裁縫。手持未染彩，繡為白芙蓉。", "芙蓉無染汙，將以表心素。欲寄未歸人，當春無信去。", "無信反增愁，愁心緣隴頭。願君如隴水，冰鏡水還流。", "宛宛青絲線，纖纖白玉鉤。玉鉤不虧缺，青絲無斷絕。", "回還勝雙手，解盡心中結。"]'),
('yuding-2','折楊柳','孟郊','唐','御定全唐诗','yuding','','[]','楊柳多短枝，短枝多別離。贈遠屢攀折，柔條安得垂。',120,'御定全唐詩/json/373.json','["楊柳多短枝，短枝多別離。贈遠屢攀折，柔條安得垂。", "青春有定節，離別無定時。但恐人別促，不怨來遲遲。", "莫言短枝條，中有長相思。朱顏與綠楊，並在別離期。", "樓上春風過，風前楊柳歌。枝疏緣別苦，曲怨為年多。", "花驚燕地雲，葉映楚池波。誰堪別離此，征戍在交河。"]'),
('yuding-3','和丁助教塞上吟','孟郊','唐','御定全唐诗','yuding','','[]','哭雪複吟雪，廣文丁夫子。江南萬里寒，曾未及如此。',48,'御定全唐詩/json/373.json','["哭雪複吟雪，廣文丁夫子。江南萬里寒，曾未及如此。", "整頓氣候誰，言從生靈始。無令惻隱者，哀哀不能已。"]'),
('yuding-4','古怨別','孟郊','唐','御定全唐诗','yuding','','[]','颯颯秋風生，愁人怨離別。含情兩相向，欲語氣先咽。',48,'御定全唐詩/json/373.json','["颯颯秋風生，愁人怨離別。含情兩相向，欲語氣先咽。", "心曲千萬端，悲來卻難說。別後唯所思，天涯共明月。"]'),
('yuding-5','古別曲','孟郊','唐','御定全唐诗','yuding','','[]','山川古今路，縱橫無斷絕。來往天地間，人皆有離別。',96,'御定全唐詩/json/373.json','["山川古今路，縱橫無斷絕。來往天地間，人皆有離別。", "行衣未束帶，中腸已先結。不用看鏡中，自知生白髮。", "欲陳去留意，聲向言前咽。愁結填心胸，茫茫若為說。", "荒郊煙莽蒼，曠野風淒切。處處得相隨，人那不如月。"]'),
('yuding-6','戲贈陸大夫十二丈','孟郊','唐','御定全唐诗','yuding','','[]','蓮子不可得，荷花生水中。猶勝道傍柳，無事蕩春風。',72,'御定全唐詩/json/373.json','["蓮子不可得，荷花生水中。猶勝道傍柳，無事蕩春風。", "淥萍與荷葉，同此一水中。風吹荷葉在，淥萍西複東。", "蓮葉未開時，苦心終日卷。春水徒蕩漾，荷花未開展。"]'),
('yuding-7','勸善吟','孟郊','唐','御定全唐诗','yuding','','[]','瘦郭有志氣，相哀老龍鍾。勸我少吟詩，俗窄難爾容。',180,'御定全唐詩/json/373.json','["瘦郭有志氣，相哀老龍鍾。勸我少吟詩，俗窄難爾容。", "一口百味別，況在醉會中。四座正當喧，片言何由通。", "顧余昧時調，居止多疏慵。見書眼始開，聞樂耳不聰。", "視聽互相隔，一身且莫同。天疾難自醫，詩癖將何攻。", "見君如見書，語善千萬重。自悲咄咄感，變作煩惱翁。", "煩惱不可欺，古劍澀亦雄。知君方少年，少年懷古風。", "藏書拄屋脊，不惜與凡聾。我願拜少年，師之學崇崇。", "從他笑為矯，矯善亦可宗。"]'),
('yuding-8','望夫石','孟郊','唐','御定全唐诗','yuding','','[]','望夫石，夫不來兮江水碧。',28,'御定全唐詩/json/373.json','["望夫石，夫不來兮江水碧。", "行人悠悠朝與暮，千年萬年色如故。"]'),
('yuding-9','寒江吟','孟郊','唐','御定全唐诗','yuding','','[]','冬至日光白，始知陰氣凝。寒江波浪凍，千里無平冰。',144,'御定全唐詩/json/373.json','["冬至日光白，始知陰氣凝。寒江波浪凍，千里無平冰。", "飛鳥絕高羽，行人皆晏興。荻洲素浩渺，碕岸澌崚嶒。", "煙舟忽自阻，風帆不相乘。何況異形體，信任為股肱。", "涉江莫涉淩，得意須得朋。結交非賢良，誰免生愛憎。", "凍水有再浪，失飛有載騰。一言縱醜詞，萬響無善應。", "取鑒諒不遠，江水千萬層。何當春風吹，利涉吾道弘。"]'),
('yuding-10','審交','孟郊','唐','御定全唐诗','yuding','','[]','種樹須擇地，惡土變木根。結交若失人，中道生謗言。',72,'御定全唐詩/json/373.json','["種樹須擇地，惡土變木根。結交若失人，中道生謗言。", "君子芳桂性，春榮冬更繁。小人槿花心，朝在夕不存。", "莫躡冬冰堅，中有潛浪翻。唯當金石交，可以賢達論。"]'),
('yuding-11','怨別','孟郊','唐','御定全唐诗','yuding','','[]','一別一回老，志士白髮早。在富易為容，居貧難自好。',60,'御定全唐詩/json/373.json','["一別一回老，志士白髮早。在富易為容，居貧難自好。", "沉憂損性靈，服藥亦枯槁。秋風遊子衣，落日行遠道。", "君問去何之，賤身難自保。"]'),
('yuding-12','百憂','孟郊','唐','御定全唐诗','yuding','','[]','萱草女兒花，不解壯士憂。壯士心是劍，為君射鬥牛。',96,'御定全唐詩/json/373.json','["萱草女兒花，不解壯士憂。壯士心是劍，為君射鬥牛。", "朝思除國讎，暮思除國讎。計盡山河畫，意窮草木籌。", "智士日千慮，愚夫唯四愁。何必在波濤，然後驚沉浮。", "伯倫心不醉，四皓跡難留。出處各有時，眾議徒啾啾。"]'),
('yuding-13','路病','孟郊','唐','御定全唐诗','yuding','','[]','病客無主人，艱哉求臥難。飛光赤道路，內火焦肺肝。',72,'御定全唐詩/json/373.json','["病客無主人，艱哉求臥難。飛光赤道路，內火焦肺肝。", "欲飲井泉竭，欲醫囊用單。稚顏能幾日，壯志忽已殘。", "人子不言苦，歸書但雲安。愁環在我腸，宛轉終無端。"]'),
('yuding-14','衰松','孟郊','唐','御定全唐诗','yuding','','[]','近世交道衰，青松落顏色。人心忌孤直，木性隨改易。',48,'御定全唐詩/json/373.json','["近世交道衰，青松落顏色。人心忌孤直，木性隨改易。", "既摧棲日幹，未展擎天力。終是君子材，還思君子識。"]'),
('yuding-15','遣興','孟郊','唐','御定全唐诗','yuding','','[]','弦貞五條音，松直百尺心。貞弦含古風，直松淩高岑。',36,'御定全唐詩/json/373.json','["弦貞五條音，松直百尺心。貞弦含古風，直松淩高岑。", "浮聲與狂葩，胡為欲相侵。"]'),
('yuding-16','退居','孟郊','唐','御定全唐诗','yuding','','[]','退身何所食，敗力不能閑。種稻耕白水，負薪斫青山。',48,'御定全唐詩/json/373.json','["退身何所食，敗力不能閑。種稻耕白水，負薪斫青山。", "眾聽喜巴唱，獨醒愁楚顏。日暮靜歸時，幽幽扣松關。"]'),
('yuding-17','臥病','孟郊','唐','御定全唐诗','yuding','','[]','貧病誠可羞，故床無新裘。春色燒肌膚，時餐苦咽喉。',60,'御定全唐詩/json/373.json','["貧病誠可羞，故床無新裘。春色燒肌膚，時餐苦咽喉。", "倦寢意蒙昧，強言聲幽柔。承顏自俯仰，有淚不敢流。", "默默寸心中，朝愁續莫愁。"]'),
('yuding-18','隱士','孟郊','唐','御定全唐诗','yuding','','[]','本末一相返，漂浮不還真。山野多餒士，市井無饑人。',156,'御定全唐詩/json/373.json','["本末一相返，漂浮不還真。山野多餒士，市井無饑人。", "虎豹忌當道，糜鹿知藏身。奈何貪競者，日與患害親。", "顏貌歲歲改，利心朝朝新。孰知富生禍，取富不取貧。", "寶玉忌出璞，出璞先為塵。松柏忌出山，出山先為薪。", "君子隱石壁，道書為我鄰。寢興思其義，澹泊味始真。", "陶公自放歸，尚平去有依。草木擇地生，禽鳥順性飛。", "青青與冥冥，所保各不違。"]'),
('yuding-19','獨愁','孟郊','唐','御定全唐诗','yuding','','[]','前日遠別離，昨日生白髮。欲知萬里情，曉臥半床月。',36,'御定全唐詩/json/373.json','["前日遠別離，昨日生白髮。欲知萬里情，曉臥半床月。", "常恐百蟲鳴，使我芳草歇。"]'),
('yuding-20','春日有感','孟郊','唐','御定全唐诗','yuding','','[]','雨滴草芽出，一日長一日。風吹柳線垂，一枝連一枝。',48,'御定全唐詩/json/373.json','["雨滴草芽出，一日長一日。風吹柳線垂，一枝連一枝。", "獨有愁人顏，經春如等閒。且持酒滿杯，狂歌狂笑來。"]'),
('yuding-21','將見故人','孟郊','唐','御定全唐诗','yuding','','[]','故人季夏中，及此百餘日。無日不相思，明鏡改形色。',48,'御定全唐詩/json/373.json','["故人季夏中，及此百餘日。無日不相思，明鏡改形色。", "甯知仲冬時，忽有相逢期。振衣起躑躅，赬鯉躍天池。"]'),
('yuding-22','傷時','孟郊','唐','御定全唐诗','yuding','','[]','常聞貧賤士之常，嗟爾富者莫相笑。男兒得路即榮名，',72,'御定全唐詩/json/373.json','["常聞貧賤士之常，嗟爾富者莫相笑。男兒得路即榮名，", "勸人一種種桃李，種亦直須遍天地。一生不愛囑人事，", "有財有勢即相識，無財無勢同路人。因知世事皆如此，"]'),
('yuding-23','寓言','孟郊','唐','御定全唐诗','yuding','','[]','誰言碧山曲，不廢青松直。誰言濁水泥，不汙明月色。',48,'御定全唐詩/json/373.json','["誰言碧山曲，不廢青松直。誰言濁水泥，不汙明月色。", "我有松月心，俗騁風霜力。貞明既如此，摧折安可得。"]'),
('yuding-24','偶作','孟郊','唐','御定全唐诗','yuding','','[]','利劍不可近，美人不可親。利劍近傷手，美人近傷身。',48,'御定全唐詩/json/373.json','["利劍不可近，美人不可親。利劍近傷手，美人近傷身。", "道險不在廣，十步能摧輪。情愛不在多，一夕能傷神。"]'),
('yuding-25','勸學','孟郊','唐','御定全唐诗','yuding','','[]','擊石乃有火，不擊元無煙。人學始知道，不學非自然。',48,'御定全唐詩/json/373.json','["擊石乃有火，不擊元無煙。人學始知道，不學非自然。", "萬事須己運，他得非我賢。青春須早為，豈能長少年。"]'),
('yuding-26','贈農人','孟郊','唐','御定全唐诗','yuding','','[]','勸爾勤耕田，盈爾倉中粟。勸爾伐桑株，減爾身上服。',60,'御定全唐詩/json/373.json','["勸爾勤耕田，盈爾倉中粟。勸爾伐桑株，減爾身上服。", "清霜一委地，萬草色不綠。狂飆一入林，萬葉不著木。", "青春如不耕，何以自結束。"]'),
('yuding-27','長安早春','孟郊','唐','御定全唐诗','yuding','','[]','旭日朱樓光，東風不驚塵。公子醉未起，美人爭探春。',60,'御定全唐詩/json/373.json','["旭日朱樓光，東風不驚塵。公子醉未起，美人爭探春。", "探春不為桑，探春不為麥。日日出西園，只望花柳色。", "乃知田家春，不入五侯宅。"]'),
('yuding-28','罪松','孟郊','唐','御定全唐诗','yuding','','[]','雖為青松姿，霜風何所宜。二月天下樹，綠于青松枝。',120,'御定全唐詩/json/373.json','["雖為青松姿，霜風何所宜。二月天下樹，綠于青松枝。", "勿謂賢者喻，勿謂愚者規。伊呂代封爵，夷齊終身饑。", "彼曲既在斯，我正實在茲。涇流合渭流，清濁各自持。", "天令設四時，榮衰有常期。榮合隨時榮，衰合隨時衰。", "天令既不從，甚不敬天時。松乃不臣木，青青獨何為。"]'),
('yuding-29','感興','孟郊','唐','御定全唐诗','yuding','','[]','拔心草不死，去根柳亦榮。獨有失意人，恍然無力行。',84,'御定全唐詩/json/373.json','["拔心草不死，去根柳亦榮。獨有失意人，恍然無力行。", "昔為連理枝，今為斷弦聲。連理時所重，斷弦今所輕。", "吾欲進孤舟，三峽水不平。吾欲載車馬，太行路崢嶸。", "萬物根一氣，如何互相傾。"]'),
('yuding-30','感懷','孟郊','唐','御定全唐诗','yuding','','[]','秋氣悲萬物，驚風振長道。登高有所思，寒雨傷百草。',504,'御定全唐詩/json/373.json','["秋氣悲萬物，驚風振長道。登高有所思，寒雨傷百草。", "平生有親愛，零落不相保。五情今已傷，安得自能老。", "晨登洛陽阪，目極天茫茫。群物歸大化，六龍頹西荒。", "豺狼日已多，草木日已霜。饑年無遺粟，眾鳥去空場。", "路傍誰家子，白首離故鄉。含酸望松柏，仰面訴穹蒼。", "去去勿複道，苦饑形貌傷。", "徘徊不能寐，耿耿含酸辛。中夜登高樓，憶我舊星辰。", "四時互遷移，萬物何時春。唯憶首陽路，永謝當時人。", "長安佳麗地，宮月生蛾眉。陰氣凝萬里，坐看芳草衰。", "玉堂有玄鳥，亦以從此辭。傷哉志士歎，故國多遲遲。", "深宮豈無樂，擾擾複何為。朝見名與利，莫還生是非。", "姜牙佐周武，世業永巍巍。", "舉才天道親，首陽誰采薇。去去荒澤遠，落日當西歸。", "羲和駐其輪，四海借餘暉。極目何蕭索，驚風正離披。", "鴟鴞鳴高樹，眾鳥相因依。東方有一士，歲暮常苦饑。", "主人數相問，脈脈今何為。貧賤亦有樂，且願掩柴扉。", "火雲流素月，三五何明明。光曜侵白日，賢愚迷至精。", "四時更變化，天道有虧盈。常恐今已沒，須臾還複生。", "河梁暮相遇，草草不復言。漢家正離亂，王粲別荊蠻。", "野澤何蕭條，悲風振空山。舉頭是星辰，念我何時還。", "親愛久別散，形神各離遷。未為生死訣，長在心目間。", "有鳥東西來，哀鳴過我前。願飛浮雲外，飲啄見青天。"]'),
('yuding-31','達士','孟郊','唐','御定全唐诗','yuding','','[]','四時如逝水，百川皆東波。青春去不還，白髮鑷更多。',60,'御定全唐詩/json/373.json','["四時如逝水，百川皆東波。青春去不還，白髮鑷更多。", "達人識元化，變愁為高歌。傾產取一醉，富者奈貧何。", "君看土中宅，富貴無偏頗。"]'),
('yuding-32','暮秋感思','孟郊','唐','御定全唐诗','yuding','','[]','西風吹垂楊，條條脆如藕。上有噪日蟬，催人成皓首。',84,'御定全唐詩/json/373.json','["西風吹垂楊，條條脆如藕。上有噪日蟬，催人成皓首。", "亦恐旅步難，何獨朱顏醜。欲慰一時心，莫如千日酒。", "優哉遵渚鴻，自得養身旨。不啄太倉粟，不飲方塘水。", "振羽戛浮雲，罝羅任徒爾。"]'),
('yuding-33','古興','孟郊','唐','御定全唐诗','yuding','','[]','楚血未幹衣，荊虹尚埋輝。痛玉不痛身，抱璞求所歸。',24,'御定全唐詩/json/373.json','["楚血未幹衣，荊虹尚埋輝。痛玉不痛身，抱璞求所歸。"]'),
('yuding-34','勸友','孟郊','唐','御定全唐诗','yuding','','[]','至白涅不緇，至交淡不疑。人生靜躁殊，莫厭相箴規。',48,'御定全唐詩/json/373.json','["至白涅不緇，至交淡不疑。人生靜躁殊，莫厭相箴規。", "膠漆武可接，金蘭文可思。堪嗟無心人，不如松柏枝。"]'),
('yuding-35','夷門雪贈主人','孟郊','唐','御定全唐诗','yuding','','[]','夷門貧士空吟雪，夷門豪士皆飲酒。酒聲歡閑入雪銷，',24,'御定全唐詩/json/373.json','["夷門貧士空吟雪，夷門豪士皆飲酒。酒聲歡閑入雪銷，"]'),
('yuding-36','堯歌','孟郊','唐','御定全唐诗','yuding','','[]','爾室何不安，爾孝無與齊。一言應對姑，一度為出妻。',156,'御定全唐詩/json/373.json','["爾室何不安，爾孝無與齊。一言應對姑，一度為出妻。", "往轍才晚鐘，還轍及晨雞。往還跡徒新，很戾竟獨迷。", "娥女無禮數，汙家如糞泥。父母吞聲哭，禽鳥亦為啼。", "如何天與惡，不得和鳴棲。", "山色挽心肝，將歸盡日看。村肩籃輿子，野坐白髮官。", "鶯弄方短短，花明碎攢攢。琉璃堆可掬，琴瑟饒多歡。", "翠韻仙窈窕，嵐漪出無端。養館洞庭秋，響答虛吹彈。"]'),
('yuding-0','亂離','孟郊','唐','御定全唐诗','yuding','','[]','天下無義劍，中原多瘡痍。哀哀陸大夫，正直神反欺。',132,'御定全唐詩/json/374.json','["天下無義劍，中原多瘡痍。哀哀陸大夫，正直神反欺。", "子路已成血，嵇康今尚嗤。為君每一慟，如劍在四肢。", "折羽不復飛，逝水不復歸。直松摧高柯，弱蔓將何依。", "朝為春日歡，夕為秋日悲。淚下無尺寸，紛紛天雨絲。", "積怨成疾疹，積恨成狂癡。怨草豈有邊，恨水豈有涯。", "怨恨馳我心，茫茫日何之。"]'),
('yuding-1','勸酒','孟郊','唐','御定全唐诗','yuding','','[]','白日無定影，清江無定波。人無百年壽，百年複如何。',72,'御定全唐詩/json/374.json','["白日無定影，清江無定波。人無百年壽，百年複如何。", "堂上陳美酒，堂下列清歌。勸君金曲卮，勿謂朱顏酡。", "松柏歲歲茂，丘陵日日多。君看終南山，千古青峨峨。"]'),
('yuding-2','去婦','孟郊','唐','御定全唐诗','yuding','','[]','君心匣中鏡，一破不復全。妾心藕中絲，雖斷猶牽連。',60,'御定全唐詩/json/374.json','["君心匣中鏡，一破不復全。妾心藕中絲，雖斷猶牽連。", "安知禦輪士，今日翻回轅。一女事一夫，安可再移天。", "君聽去鶴言，哀哀七絲弦。"]'),
('yuding-3','君子勿鬱鬱士有謗毀者作詩以贈之','孟郊','唐','御定全唐诗','yuding','','[]','君子勿鬱鬱，聽我青蠅歌。人間少平地，森聳山嶽多。',144,'御定全唐詩/json/374.json','["君子勿鬱鬱，聽我青蠅歌。人間少平地，森聳山嶽多。", "折輈不在道，覆舟不在河。須知一尺水，日夜增高波。", "叔孫毀仲尼，臧倉掩孟軻。蘭艾不同香，自然難為和。", "良玉燒不熱，直竹文不頗。自古皆如此，其如道在何。", "日往復不見，秋堂暮仍學。玄發不知白，曉入寒銅覺。", "為林未離樹，有玉猶在璞。誰把碧梧枝，刻作雲門樂。"]'),
('yuding-4','聞砧','孟郊','唐','御定全唐诗','yuding','','[]','杜鵑聲不哀，斷猿啼不切。月下誰家砧，一聲腸一絕。',48,'御定全唐詩/json/374.json','["杜鵑聲不哀，斷猿啼不切。月下誰家砧，一聲腸一絕。", "杵聲不為客，客聞發自白。杵聲不為衣，欲令遊子歸。"]'),
('yuding-5','遊子','孟郊','唐','御定全唐诗','yuding','','[]','萱草生堂階，遊子行天涯。慈親倚堂門，不見萱草花。',24,'御定全唐詩/json/374.json','["萱草生堂階，遊子行天涯。慈親倚堂門，不見萱草花。"]'),
('yuding-6','自歎','孟郊','唐','御定全唐诗','yuding','','[]','愁與發相形，一愁白數莖。有發能幾多，禁愁日日生。',96,'御定全唐詩/json/374.json','["愁與發相形，一愁白數莖。有發能幾多，禁愁日日生。", "古若不置兵，天下無戰爭。古若不置名，道路無欹傾。", "太行聳巍峨，是天產不平。黃河奔濁浪，是天生不清。", "四蹄日日多，雙輪日日成。二物不在天，安能免營營。"]'),
('yuding-7','求友','孟郊','唐','御定全唐诗','yuding','','[]','北風臨大海，堅冰臨河面。下有大波瀾，對之無由見。',60,'御定全唐詩/json/374.json','["北風臨大海，堅冰臨河面。下有大波瀾，對之無由見。", "求友須在良，得良終相善。求友若非良，非良中道變。", "欲知求友心，先把黃金煉。"]'),
('yuding-8','投所知','孟郊','唐','御定全唐诗','yuding','','[]','苦心知苦節，不容一毛髮。煉金索堅貞，洗玉求明潔。',180,'御定全唐詩/json/374.json','["苦心知苦節，不容一毛髮。煉金索堅貞，洗玉求明潔。", "自慚所業微，功用如鳩拙。何殊嫫母顏，對彼寒塘月。", "君存古人心，道出古人轍。盡美固可揚，片善亦不遏。", "朝向公卿說，暮向公卿說。誰謂黃鐘管，化為君子舌。", "一說清嶰竹，二說變嶰穀。三說四說時，寒花拆寒木。", "曄曄家道路，燦燦我衣服。豈直輝友朋，亦用慰骨肉。", "一暖荷匹素，一飽荷升粟。而況大恩恩，此身報得足。", "且將食檗勞，酬之作金刀。"]'),
('yuding-9','病客吟','孟郊','唐','御定全唐诗','yuding','','[]','主人夜呻吟，皆入妻子心。客子晝呻吟，徒為蟲鳥音。',97,'御定全唐詩/json/374.json','["主人夜呻吟，皆入妻子心。客子晝呻吟，徒為蟲鳥音。", "妻子手中病，愁思不復深。僮僕手中病，憂危獨難任。", "丈夫久漂泊，神氣自然沉。況于滯疾中，何人免噓eS。", "大海亦有涯，高山亦有岑。沉憂獨無極，塵淚互盈襟。"]'),
('yuding-10','感懷','孟郊','唐','御定全唐诗','yuding','','[]','孟冬陰氣交，兩河正屯兵。煙塵相馳突，烽火日夜驚。',120,'御定全唐詩/json/374.json','["孟冬陰氣交，兩河正屯兵。煙塵相馳突，烽火日夜驚。", "太行險阻高，挽粟輸連營。奈何操弧者，不使梟巢傾。", "猶聞漢北兒，怙亂謀縱橫。擅搖干戈柄，呼叫豺狼聲。", "白日臨爾軀，胡為喪丹誠。豈無感激士，以致天下平。", "登高望寒原，黃雲郁崢嶸。坐馳悲風暮，歎息空沾纓。"]'),
('yuding-11','離思','孟郊','唐','御定全唐诗','yuding','','[]','不寐亦不語，片月秋稍舉。孤鴻憶霜群，獨鶴叫雲侶。',60,'御定全唐詩/json/374.json','["不寐亦不語，片月秋稍舉。孤鴻憶霜群，獨鶴叫雲侶。", "怨彼浮花心，飄飄無定所。高張系繂帆，遠過梅根渚。", "回織別離字，機聲有酸楚。"]'),
('yuding-12','結交','孟郊','唐','御定全唐诗','yuding','','[]','鑄鏡須青銅，青銅易磨拭。結交遠小人，小人難姑息。',48,'御定全唐詩/json/374.json','["鑄鏡須青銅，青銅易磨拭。結交遠小人，小人難姑息。", "鑄鏡圖鑒微，結交圖相依。凡銅不可照，小人多是非。"]'),
('yuding-13','傷春','孟郊','唐','御定全唐诗','yuding','','[]','兩河春草海水清，十年征戰城郭腥。亂兵殺兒將女去，',48,'御定全唐詩/json/374.json','["兩河春草海水清，十年征戰城郭腥。亂兵殺兒將女去，", "春色不揀墓傍株，紅顏皓色逐春去。春去春來那得知，"]'),
('yuding-14','擇友','孟郊','唐','御定全唐诗','yuding','','[]','獸中有人性，形異遭人隔。人中有獸心，幾人能真識。',144,'御定全唐詩/json/374.json','["獸中有人性，形異遭人隔。人中有獸心，幾人能真識。", "古人形似獸，皆有大聖德。今人表似人，獸心安可測。", "雖笑未必和，雖哭未必戚。面結口頭交，肚裏生荊棘。", "好人常直道，不順世間逆。惡人巧諂多，非義苟且得。", "若是效真人，堅心如鐵石。不諂亦不欺，不奢複不溺。", "面無吝色容，心無詐憂惕。君子大道人，朝夕恒的的。"]'),
('yuding-15','夜憂','孟郊','唐','御定全唐诗','yuding','','[]','豈獨科鬥死，所嗟文字捐。蒿蔓轉驕弄，菱荇減嬋娟。',48,'御定全唐詩/json/374.json','["豈獨科鬥死，所嗟文字捐。蒿蔓轉驕弄，菱荇減嬋娟。", "未遂擺鱗志，空思吹浪旋。何當再霖雨，洗濯生華鮮。"]'),
('yuding-16','惜苦','孟郊','唐','御定全唐诗','yuding','','[]','於鵠值諫議，以球不能官。焦蒙值舍人，以杯不得完。',84,'御定全唐詩/json/374.json','["於鵠值諫議，以球不能官。焦蒙值舍人，以杯不得完。", "可惜大雅旨，意此小團欒。名回不敢辨，心轉實是難。", "不惜為君轉，轉非君子觀。轉之複轉之，強轉誰能歡。", "哀哉虛轉言，不可窮波瀾。"]'),
('yuding-17','寒地百姓吟','孟郊','唐','御定全唐诗','yuding','','[]','無火炙地眠，半夜皆立號。冷箭何處來，棘針風騷勞。',96,'御定全唐詩/json/374.json','["無火炙地眠，半夜皆立號。冷箭何處來，棘針風騷勞。", "霜吹破四壁，苦痛不可逃。高堂搥鐘飲，到曉聞烹炮。", "寒者願為蛾，燒死彼華膏。華膏隔仙羅，虛繞千萬遭。", "到頭落地死，踏地為遊遨。游遨者是誰，君子為郁陶。"]'),
('yuding-18','出東門','孟郊','唐','御定全唐诗','yuding','','[]','餓馬骨亦聳，獨驅出東門。少年一日程，衰叟十日奔。',72,'御定全唐詩/json/374.json','["餓馬骨亦聳，獨驅出東門。少年一日程，衰叟十日奔。", "寒景不我為，疾走落平原。眇默荒草行，恐懼夜魄翻。", "一生自組織，千首大雅言。道路如抽蠶，宛轉羈腸繁。"]'),
('yuding-19','教坊歌兒','孟郊','唐','御定全唐诗','yuding','','[]','十歲小小兒，能歌得朝天。六十孤老人，能詩獨臨川。',60,'御定全唐詩/json/374.json','["十歲小小兒，能歌得朝天。六十孤老人，能詩獨臨川。", "去年西京寺，眾伶集講筵。能嘶竹枝詞，供養繩床禪。", "能詩不如歌，悵望三百篇。"]'),
('yuding-20','訪疾','孟郊','唐','御定全唐诗','yuding','','[]','冷氣入瘡痛，夜來痛如何。瘡從公怒生，豈以私恨多。',60,'御定全唐詩/json/374.json','["冷氣入瘡痛，夜來痛如何。瘡從公怒生，豈以私恨多。", "公怒亦非道，怒消乃天和。古有煥輝句，嵇康閑婆娑。", "請君吟嘯之，正氣庶不訛。"]'),
('yuding-21','酒德','孟郊','唐','御定全唐诗','yuding','','[]','酒是古明鏡，輾開小人心。醉見異舉止，醉聞異聲音。',48,'御定全唐詩/json/374.json','["酒是古明鏡，輾開小人心。醉見異舉止，醉聞異聲音。", "酒功如此多，酒屈亦以深。罪人免罪酒，如此可為箴。"]'),
('yuding-22','冬日','孟郊','唐','御定全唐诗','yuding','','[]','老人行人事，百一不及周。凍馬四蹄吃，陟卓難自收。',84,'御定全唐詩/json/374.json','["老人行人事，百一不及周。凍馬四蹄吃，陟卓難自收。", "短景仄飛過，午光不上頭。少壯日與輝，衰老日與愁。", "日愁疑在日，歲箭迸如讎。萬事有何味，一生虛自囚。", "不知文字利，到死空遨遊。"]'),
('yuding-23','饑雪吟','孟郊','唐','御定全唐诗','yuding','','[]','饑烏夜相啄，瘡聲互悲鳴。冰腸一直刀，天殺無曲情。',108,'御定全唐詩/json/374.json','["饑烏夜相啄，瘡聲互悲鳴。冰腸一直刀，天殺無曲情。", "大雪壓梧桐，折柴墮崢嶸。安知鸞鳳巢，不與梟鳶傾。", "下有幸災兒，拾遺多新爭。但求彼失所，但誇此經營。", "君子亦拾遺，拾遺非拾名。將補鸞鳳巢，免與梟鳶並。", "因為饑雪吟，至曉竟不平。"]'),
('yuding-24','偷詩','孟郊','唐','御定全唐诗','yuding','','[]','餓犬齰枯骨，自吃饞饑涎。今文與古文，各各稱可憐。',84,'御定全唐詩/json/374.json','["餓犬齰枯骨，自吃饞饑涎。今文與古文，各各稱可憐。", "亦如嬰兒食，餳桃口旋旋。唯有一點味，豈見逃景延。", "繩床獨坐翁，默覽有所傳。終當罷文字，別著逍遙篇。", "從來文字淨，君子不以賢。"]'),
('yuding-25','晚雪吟','孟郊','唐','御定全唐诗','yuding','','[]','貧富喜雪晴，出門意皆饒。鏡海見纖悉，冰天步飄颻。',180,'御定全唐詩/json/374.json','["貧富喜雪晴，出門意皆饒。鏡海見纖悉，冰天步飄颻。", "一一仙子行，家家塵聲銷。小兒擊玉指，大耋歌聖朝。", "睿氣流不盡，瑞仙何夐寥。始知望幸色，終疑異禮招。", "市井亦清潔，閭閻聳岧嶢。蒼生願東顧，翠華仍西遙。", "天念豈薄厚，宸衷多憂焦。憂焦致太平，以茲時比堯。", "古耳有未通，新詞有潛韶。甘為酒伶擯，坐恥歌女嬌。", "選音不易言，裁正逢今朝。今朝前古文，律異同一調。", "願于堯管中，奏盡鬱抑謠。"]'),
('yuding-26','自惜','孟郊','唐','御定全唐诗','yuding','','[]','傾盡眼中力，抄詩過與人。自悲風雅老，恐被巴竹嗔。',72,'御定全唐詩/json/374.json','["傾盡眼中力，抄詩過與人。自悲風雅老，恐被巴竹嗔。", "零落雪文字，分明鏡精神。坐甘冰抱晚，永謝酒懷春。", "徒有言言舊，慚無默默新。始驚儒教誤，漸與佛乘親。"]'),
('yuding-27','老恨','孟郊','唐','御定全唐诗','yuding','','[]','無子抄文字，老吟多飄零。有時吐向床，枕席不解聽。',48,'御定全唐詩/json/374.json','["無子抄文字，老吟多飄零。有時吐向床，枕席不解聽。", "鬥蟻甚微細，病聞亦清泠。小大不自識，自然天性靈。"]'),
('yuding-28','湖州取解述情','孟郊','唐','御定全唐诗','yuding','','[]','霅水徒清深，照影不照心。白鶴未輕舉，眾鳥爭浮沉。',36,'御定全唐詩/json/374.json','["霅水徒清深，照影不照心。白鶴未輕舉，眾鳥爭浮沉。", "因茲掛帆去，遂作歸山吟。"]'),
('yuding-29','落第','孟郊','唐','御定全唐诗','yuding','','[]','曉月難為光，愁人難為腸。誰言春物榮，獨見葉上霜。',48,'御定全唐詩/json/374.json','["曉月難為光，愁人難為腸。誰言春物榮，獨見葉上霜。", "雕鶚失勢病，鷦鷯假翼翔。棄置複棄置，情如刀劍傷。"]'),
('yuding-30','詠懷','孟郊','唐','御定全唐诗','yuding','','[]','濁水心易傾，明波興初發。思逢海底人，乞取蚌中月。',36,'御定全唐詩/json/374.json','["濁水心易傾，明波興初發。思逢海底人，乞取蚌中月。", "此興若未諧，此心終不歇。"]'),
('yuding-31','病起言懷','孟郊','唐','御定全唐诗','yuding','','[]','強行尋溪水，洗卻殘病姿。花景晼晚盡，麥風清泠吹。',60,'御定全唐詩/json/374.json','["強行尋溪水，洗卻殘病姿。花景晼晚盡，麥風清泠吹。", "交道賤來見，世情貧去知。高閑思楚逸，澹泊厭齊兒。", "終伴碧山侶，結言青桂枝。"]'),
('yuding-32','秋夕貧居述懷','孟郊','唐','御定全唐诗','yuding','','[]','臥冷無遠夢，聽秋酸別情。高枝低枝風，千葉萬葉聲。',48,'御定全唐詩/json/374.json','["臥冷無遠夢，聽秋酸別情。高枝低枝風，千葉萬葉聲。", "淺井不供飲，瘦田長廢耕。今交非古交，貧語聞皆輕。"]'),
('yuding-33','夜感自遣','孟郊','唐','御定全唐诗','yuding','','[]','夜學曉未休，苦吟神鬼愁。如何不自閑，心與身為讎。',48,'御定全唐詩/json/374.json','["夜學曉未休，苦吟神鬼愁。如何不自閑，心與身為讎。", "死辱片時痛，生辱長年羞。清桂無直枝，碧江思舊遊。"]'),
('yuding-34','再下第','孟郊','唐','御定全唐诗','yuding','','[]','一夕九起嗟，夢短不到家。兩度長安陌，空將淚見花。',24,'御定全唐詩/json/374.json','["一夕九起嗟，夢短不到家。兩度長安陌，空將淚見花。"]'),
('yuding-35','下第東歸留別長安知己','孟郊','唐','御定全唐诗','yuding','','[]','共照日月影，獨為愁思人。豈知鶗鴂鳴，瑤草不得春。',60,'御定全唐詩/json/374.json','["共照日月影，獨為愁思人。豈知鶗鴂鳴，瑤草不得春。", "一片兩片雲，千里萬里身。雲歸嵩之陽，身寄江之濱。", "棄置複何道，楚情吟白蘋。"]'),
('yuding-36','失意歸吳因寄東台劉複侍禦','孟郊','唐','御定全唐诗','yuding','','[]','自念西上身，忽隨東歸風。長安日下影，又落江湖中。',60,'御定全唐詩/json/374.json','["自念西上身，忽隨東歸風。長安日下影，又落江湖中。", "離婁豈不明，子野豈不聰。至寶非眼別，至音非耳通。", "因緘俗外詞，仰寄高天鴻。"]'),
('yuding-37','下第東南行','孟郊','唐','御定全唐诗','yuding','','[]','越風東南清，楚日瀟湘明。試逐伯鸞去，還作靈均行。',60,'御定全唐詩/json/374.json','["越風東南清，楚日瀟湘明。試逐伯鸞去，還作靈均行。", "江蘺伴我泣，海月投人驚。失意容貌改，畏途性命輕。", "時聞喪侶猿，一叫千愁並。"]'),
('yuding-38','歎命','孟郊','唐','御定全唐诗','yuding','','[]','三十年來命，唯藏一卦中。題詩還問易，問易蒙複蒙。',60,'御定全唐詩/json/374.json','["三十年來命，唯藏一卦中。題詩還問易，問易蒙複蒙。", "本望文字達，今因文字窮。影孤別離月，衣破道路風。", "歸去不自息，耕耘成楚農。"]'),
('yuding-39','遠遊','孟郊','唐','御定全唐诗','yuding','','[]','慈烏不遠飛，孝子念先歸。而我獨何事，四時心有違。',96,'御定全唐詩/json/374.json','["慈烏不遠飛，孝子念先歸。而我獨何事，四時心有違。", "江海戀空積，波濤信來稀。長為路傍食，著盡家中衣。", "別劍不割物，離人難作威。遠行少僮僕，驅使無是非。", "為性玩好盡，積愁心緒微。始知時節駛，夏日非長輝。"]'),
('yuding-40','商州客舍','孟郊','唐','御定全唐诗','yuding','','[]','商山風雪壯，遊子衣裳單。四望失道路，百憂攢肺肝。',72,'御定全唐詩/json/374.json','["商山風雪壯，遊子衣裳單。四望失道路，百憂攢肺肝。", "日短覺易老，夜長知至寒。淚流瀟湘弦，調苦屈宋彈。", "識聲今所易，識意古所難。聲意今詎辨，高明鑒其端。"]'),
('yuding-41','長安旅情','孟郊','唐','御定全唐诗','yuding','','[]','盡說青雲路，有足皆可至。我馬亦四蹄，出門似無地。',48,'御定全唐詩/json/374.json','["盡說青雲路，有足皆可至。我馬亦四蹄，出門似無地。", "玉京十二樓，峨峨倚青翠。下有千朱門，何門薦孤士。"]'),
('yuding-42','長安羈旅','孟郊','唐','御定全唐诗','yuding','','[]','聽樂別離中，聲聲入幽腸。曉淚滴楚瑟，夜魄繞吳鄉。',36,'御定全唐詩/json/374.json','["聽樂別離中，聲聲入幽腸。曉淚滴楚瑟，夜魄繞吳鄉。", "幾回羈旅情，夢覺殘燭光。"]'),
('yuding-43','渭上思歸','孟郊','唐','御定全唐诗','yuding','','[]','獨訪千里信，回臨千里河。家在吳楚鄉，淚寄東南波。',24,'御定全唐詩/json/374.json','["獨訪千里信，回臨千里河。家在吳楚鄉，淚寄東南波。"]'),
('yuding-44','登科後','孟郊','唐','御定全唐诗','yuding','','[]','昔日齷齪不足誇，今朝放蕩思無涯。',32,'御定全唐詩/json/374.json','["昔日齷齪不足誇，今朝放蕩思無涯。", "春風得意馬蹄疾，一日看盡長安花。"]'),
('yuding-45','初於洛中選','孟郊','唐','御定全唐诗','yuding','','[]','塵土日易沒，驅馳力無餘。青雲不我與，白首方選書。',84,'御定全唐詩/json/374.json','["塵土日易沒，驅馳力無餘。青雲不我與，白首方選書。", "宦途事非遠，拙者取自疏。終然戀皇邑，誓以結吾廬。", "帝城富高門，京路繞勝居。碧水走龍蛇，蜿蜒繞庭除。", "尋常異方客，過此亦踟躕。"]'),
('yuding-46','乙酉歲舍弟扶侍歸興義莊居後獨止舍待替人','孟郊','唐','御定全唐诗','yuding','','[]','誰言舊居止，主人忽成客。僮僕強與言，相懼終脈脈。',108,'御定全唐詩/json/374.json','["誰言舊居止，主人忽成客。僮僕強與言，相懼終脈脈。", "出亦何所求，入亦何所索。飲食迷精粗，衣裳失寬窄。", "回風卷閑簟，新月生空壁。士有百役身，官無一姓宅。", "丈夫恥自飾，衰須從颯白。蘭交早已謝，榆景徒相迫。", "惟予心中鏡，不語光歷歷。"]'),
('yuding-47','西齋養病夜懷多感因呈上從叔子雲','孟郊','唐','御定全唐诗','yuding','','[]','遠客夜衣薄，厭眠待雞鳴。一床空月色，四壁秋蛩聲。',84,'御定全唐詩/json/374.json','["遠客夜衣薄，厭眠待雞鳴。一床空月色，四壁秋蛩聲。", "守淡遺眾俗，養屙念餘生。方全君子拙，恥學小人明。", "蚊蚋亦有時，羽毛各有成。如何騏驥跡，蜷局未能行。", "西北有平路，運來無相輕。"]'),
('yuding-0','秋懷','孟郊','唐','御定全唐诗','yuding','','[]','孤骨夜難臥，吟蟲相唧唧。老泣無涕洟，秋露為滴瀝。',516,'御定全唐詩/json/375.json','["孤骨夜難臥，吟蟲相唧唧。老泣無涕洟，秋露為滴瀝。", "去壯暫如翦，來衰紛似織。觸緒無新心，叢悲有餘憶。", "詎忍逐南帆，江山踐往昔。", "秋月顏色冰，老客志氣單。冷露滴夢破，峭風梳骨寒。", "席上印病文，腸中轉愁盤。疑懷無所憑，虛聽多無端。", "梧桐枯崢嶸，聲響如哀彈。", "一尺月透戶，仡栗如劍飛。老骨坐亦驚，病力所尚微。", "蟲苦貪剪色，鳥危巢焚輝。孀娥理故絲，孤哭抽餘思。", "浮年不可追，衰步多夕歸。", "秋至老更貧，破屋無門扉。一片月落床，四壁風入衣。", "疏夢不復遠，弱心良易歸。商葩將去綠，繚繞爭餘輝。", "野步踏事少，病謀向物違。幽幽草根蟲，生意與我微。", "竹風相戛語，幽閨暗中聞。鬼神滿衰聽，恍惚難自分。", "商葉墮幹雨，秋衣臥單雲。病骨可剸物，酸呻亦成文。", "瘦攢如此枯，壯落隨西曛。褭褭一線命，徒言系絪縕。", "老骨懼秋月，秋月刀劍棱。纖輝不可幹，冷魂坐自凝。", "羈雌巢空鏡，仙飆蕩浮冰。驚步恐自翻，病大不敢淩。", "單床寤皎皎，瘦臥心兢兢。洗河不見水，透濁為清澄。", "詩壯昔空說，詩衰今何憑。", "老病多異慮，朝夕非一心。商蟲哭衰運，繁響不可尋。", "秋草瘦如發，貞芳綴疏金。晚鮮詎幾時，馳景還易陰。", "弱習徒自恥，莫知欲何任。露才一見讒，潛智早已深。", "防深不防露，此意古所箴。", "歲暮景氣幹，秋風兵甲聲。織織勞無衣，喓喓徒自鳴。"]'),
('yuding-1','靖安寄居','孟郊','唐','御定全唐诗','yuding','','[]','寄靜不寄華，愛茲嵽嵲居。渴飲濁清泉，饑食無名蔬。',168,'御定全唐詩/json/375.json','["寄靜不寄華，愛茲嵽嵲居。渴飲濁清泉，饑食無名蔬。", "敗菜不敢火，補衣亦寫書。古雲儉成德，今乃實起予。", "戇叟戇不足，賢人賢有餘。役生皆促促，心竟誰舒舒。", "萬馬踏風衢，眾塵隨奔車。高賓盡不見，大道夜方虛。", "臥有洞庭夢，坐無長安儲。英髦空駭耳，煙火獨微如。", "厚念恐傷性，薄田憶親鋤。承世不出力，冬竹肯抽菹。", "外物莫相誘，約心誓從初。碧芳既似水，日日詠歸歟。"]'),
('yuding-2','雪','孟郊','唐','御定全唐诗','yuding','','[]','忽然太行雪，昨夜飛入來。崚嶒墮庭中，嚴白何皚皚。',132,'御定全唐詩/json/375.json','["忽然太行雪，昨夜飛入來。崚嶒墮庭中，嚴白何皚皚。", "奴婢曉開戶，四肢凍徘徊。咽言詞不成，告訴情狀摧。", "官給未入門，家人盡以灰。意勸莫笑雪，笑雪貧為災。", "將暖此殘疾，典賣爭致杯。教令再舉手，誇曜餘生才。", "強起吐巧詞，委曲多新裁。為爾作非夫，忍恥轟暍雷。", "書之與君子，庶免生嫌猜。"]'),
('yuding-3','春愁','孟郊','唐','御定全唐诗','yuding','','[]','春物與愁客，遇時各有違。故花辭新枝，新淚落故衣。',36,'御定全唐詩/json/375.json','["春物與愁客，遇時各有違。故花辭新枝，新淚落故衣。", "日暮兩寂寞，飄然亦同歸。"]'),
('yuding-4','懊惱','孟郊','唐','御定全唐诗','yuding','','[]','惡詩皆得官，好詩空抱山。抱山冷殑殑，終日悲顏顏。',73,'御定全唐詩/json/375.json','["惡詩皆得官，好詩空抱山。抱山冷殑殑，終日悲顏顏。", "好詩更相嫉，劍戟生牙關。前賢死已久，猶在咀嚼間。", "以我殘杪身，清峭養高閑。求閑未得閒，眾誚瞋bF々。"]'),
('yuding-5','遊城南韓氏莊','孟郊','唐','御定全唐诗','yuding','','[]','初疑瀟湘水，鎖在朱門中。時見水底月，動搖池上風。',72,'御定全唐詩/json/375.json','["初疑瀟湘水，鎖在朱門中。時見水底月，動搖池上風。", "清氣潤竹林，白光連虛空。浪簇霄漢羽，岸芳金碧叢。", "何言數畝間，環泛路不窮。願逐神仙侶，飄然汗漫通。"]'),
('yuding-6','與二三友秋宵會話清上人院','孟郊','唐','御定全唐诗','yuding','','[]','何處山不幽，此中情又別。一僧敲一磬，七子吟秋月。',132,'御定全唐詩/json/375.json','["何處山不幽，此中情又別。一僧敲一磬，七子吟秋月。", "激石泉韻清，寄枝風嘯咽。泠然諸境靜，頓覺浮累滅。", "扣寂兼探真，通宵詎能輟。", "好鳥無雜棲，華堂有嘉攜。琴樽互傾奏，歌賦相和諧。", "但嘉魚水合，莫令雲雨乖。一為鶤雞彈，再鼓壯士懷。", "初景待誰曉，新春逐君來。願言良友會，高駕不知回。"]'),
('yuding-7','招文士飲','孟郊','唐','御定全唐诗','yuding','','[]','曹劉不免死，誰敢負年華。文士莫辭酒，詩人命屬花。',108,'御定全唐詩/json/375.json','["曹劉不免死，誰敢負年華。文士莫辭酒，詩人命屬花。", "退之如放逐，李白自矜誇。萬古忽將似，一朝同歎嗟。", "何言天道正，獨使地形斜。南士愁多病，北人悲去家。", "梅芳已流管，柳色未藏鴉。相勸罷吟雪，相從愁飲霞。", "醒時不可過，愁海浩無涯。"]'),
('yuding-8','陪侍禦叔游城南山墅','孟郊','唐','御定全唐诗','yuding','','[]','夜坐擁腫亭，晝登崔巍岑。日窺萬峰首，月見雙泉心。',48,'御定全唐詩/json/375.json','["夜坐擁腫亭，晝登崔巍岑。日窺萬峰首，月見雙泉心。", "鬆氣清耳目，竹氛碧衣襟。佇想琅玕字，數聽枯槁吟。"]'),
('yuding-9','登華岩寺樓望終南山贈林校書兄弟','孟郊','唐','御定全唐诗','yuding','','[]','地脊亞為崖，聳出冥冥中。樓根插迥雲，殿翼翔危空。',72,'御定全唐詩/json/375.json','["地脊亞為崖，聳出冥冥中。樓根插迥雲，殿翼翔危空。", "前山胎元氣，靈異生不窮。勢吞萬象高，秀奪五嶽雄。", "一望俗慮醒，再登仙願崇。青蓮三居士，晝景真賞同。"]'),
('yuding-10','游終南山','孟郊','唐','御定全唐诗','yuding','','[]','南山塞天地，日月石上生。高峰夜留景，深谷晝未明。',60,'御定全唐詩/json/375.json','["南山塞天地，日月石上生。高峰夜留景，深谷晝未明。", "山中人自正，路險心亦平。長風驅松柏，聲拂萬壑清。", "到此悔讀書，朝朝近浮名。"]'),
('yuding-11','游終南龍池寺','孟郊','唐','御定全唐诗','yuding','','[]','飛鳥不到處，僧房終南巔。龍在水長碧，雨開山更鮮。',60,'御定全唐詩/json/375.json','["飛鳥不到處，僧房終南巔。龍在水長碧，雨開山更鮮。", "步出白日上，坐依清溪邊。地寒松桂短，石險道路偏。", "晚磬送歸客，數聲落遙天。"]'),
('yuding-12','南陽公請東櫻桃亭子春宴','孟郊','唐','御定全唐诗','yuding','','[]','萬木皆未秀，一林先含春。此地獨何力，我公佈深仁。',132,'御定全唐詩/json/375.json','["萬木皆未秀，一林先含春。此地獨何力，我公佈深仁。", "霜葉日舒卷，風枝遠埃塵。初英濯紫霞，飛雨流清津。", "賞異出囂雜，折芳積歡忻。文心茲焉重，俗尚安能珍。", "碧玉妝粉比，飛瓊穠豔均。鴛鴦七十二，花態並相新。", "常恐遺秀志，迨茲廣宴陳。芳菲爭勝引，歌詠竟良辰。", "方知戲馬會，永謝登龍賓。"]'),
('yuding-13','游華山雲台觀','孟郊','唐','御定全唐诗','yuding','','[]','華嶽獨靈異，草木恒新鮮。山盡五色石，水無一色泉。',60,'御定全唐詩/json/375.json','["華嶽獨靈異，草木恒新鮮。山盡五色石，水無一色泉。", "仙酒不醉人，仙芝皆延年。夜聞明星館，時韻女蘿弦。", "敬茲不能寐，焚柏吟道篇。"]'),
('yuding-14','喜與長文上人宿李秀才小山池亭','孟郊','唐','御定全唐诗','yuding','','[]','燈盡語不盡，主人庭砌幽。柳枝星影曙，蘭葉露華浮。',48,'御定全唐詩/json/375.json','["燈盡語不盡，主人庭砌幽。柳枝星影曙，蘭葉露華浮。", "塊嶺笑群岫，片池輕眾流。更聞清淨子，逸唱頗難儔。"]'),
('yuding-15','邀花伴','孟郊','唐','御定全唐诗','yuding','','[]','邊地春不足，十裏見一花。及時須遨遊，日暮饒風沙。',24,'御定全唐詩/json/375.json','["邊地春不足，十裏見一花。及時須遨遊，日暮饒風沙。"]'),
('yuding-16','石淙','孟郊','唐','御定全唐诗','yuding','','[]','岩穀不自勝，水木幽奇多。朔風入空曲，涇流無大波。',516,'御定全唐詩/json/375.json','["岩穀不自勝，水木幽奇多。朔風入空曲，涇流無大波。", "迢遞徑難盡，參差勢相羅。雪霜有時洗，塵土無由和。", "潔冷誠未厭，晚步將如何。", "出曲水未斷，入山深更重。泠泠若仙語，皎皎多異容。", "萬響不相雜，四時皆有濃。日月互分照，雲霞各生峰。", "久迷向方理，逮茲聳前蹤。", "荒策每恣遠，戇步難自回。已抱苔蘚疾，尚淩潺湲隈。", "驛驥苦銜勒，籠禽恨摧頹。實力苟未足，浮誇信悠哉。", "顧惟非時用，靜言還自咍。", "朔水刀劍利，秋石瓊瑤鮮。魚龍氣不腥，潭洞狀更妍。", "磴雪入呀穀，掬星灑遙天。聲忙不及韻，勢疾多斷漣。", "輸去雖有恨，躁氣一何顛。蜿蜒相纏掣，犖確亦迴旋。", "黑草濯鐵發，白苔浮冰錢。具生此雲遙，非德不可甄。", "何況被犀士，制之空以權。始知靜剛猛，文教從來先。", "空穀聳視聽，幽湍澤心靈。疾流脫鱗甲，疊岸沖風霆。", "丹巘墮環景，霽波灼虛形。淙淙豗厚軸，棱棱攢高冥。", "弱棧跨旋碧，危梯倚凝青。飄飄鶴骨仙，飛動鼇背庭。", "常聞誇大言，下顧皆細萍。", "百尺明鏡流，千曲寒星飛。為君洗故物，有色如新衣。", "不飲泥土汙，但飲雪霜饑。石棱玉纖纖，草色瓊霏霏。", "穀磑有餘力，溪舂亦多機。從來一智萌，能使眾利歸。", "因之山水中，喧然論是非。", "入深得奇趣，升險為良躋。搜勝有聞見，逃俗無蹤蹊。", "穴流恣回轉，竅景忘東西。戇獸鮮猜懼，羅人巧罝罤。"]'),
('yuding-17','游韋七洞庭別業','孟郊','唐','御定全唐诗','yuding','','[]','洞庭如瀟湘，疊翠蕩浮碧。松桂無赤日，風物饒清激。',240,'御定全唐詩/json/375.json','["洞庭如瀟湘，疊翠蕩浮碧。松桂無赤日，風物饒清激。", "逍遙展幽韻，參差逗良覿。道勝不知疲，冥搜自無斁。", "曠然青霞抱，永矣白雲適。崆峒非凡鄉，蓬瀛在仙籍。", "無言從遠尚，還思君子識。波濤漱古岸，鏗鏘辨奇石。", "靈響非外求，殊音自中積。人皆走煩濁，君能致虛寂。", "何以祛擾擾，叩調清淅淅。既懼豪華損，誓從詩書益。", "一舉獨往姿，再搖飛遁跡。山深有變異，意愜無驚惕。", "采翠奪日月，照耀迷晝夕。松齋何用掃，蘿院自然滌。", "業峻謝煩蕪，文高追古昔。暫遙朱門戀，終立青史績。", "物表易淹留，人間重離析。難隨洞庭酌，且醉橫塘席。"]'),
('yuding-18','越中山水','孟郊','唐','御定全唐诗','yuding','','[]','日覺耳目勝，我來山水州。蓬瀛若仿佛，田野如泛浮。',120,'御定全唐詩/json/375.json','["日覺耳目勝，我來山水州。蓬瀛若仿佛，田野如泛浮。", "碧嶂幾千繞，清泉萬餘流。莫窮合遝步，孰盡派別遊。", "越水淨難汙，越天陰易收。氣鮮無隱物，目視遠更周。", "舉俗媚蔥蒨，連冬擷芳柔。菱湖有餘翠，茗圃無荒疇。", "賞異忽已遠，探奇誠淹留。永言終南色，去矣銷人憂。"]'),
('yuding-19','春集越州皇甫秀才山亭','孟郊','唐','御定全唐诗','yuding','','[]','嘉賓在何處，置亭春山巔。顧餘寂寞者，謬廁芳菲筵。',60,'御定全唐詩/json/375.json','["嘉賓在何處，置亭春山巔。顧餘寂寞者，謬廁芳菲筵。", "視聽日澄澈，聲光坐連綿。晴湖瀉峰嶂，翠浪多萍蘚。", "何以逞高志，為君吟秋天。"]'),
('yuding-20','和皇甫判官游琅琊溪','孟郊','唐','御定全唐诗','yuding','','[]','山中琉璃境，物外琅琊溪。房廊逐岩壑，道路隨高低。',84,'御定全唐詩/json/375.json','["山中琉璃境，物外琅琊溪。房廊逐岩壑，道路隨高低。", "碧瀨漱白石，翠煙含青蜺。客來暫遊踐，意欲忘簪珪。", "樹杪燈火夕，雲端鐘梵齊。時同雖可仰，跡異難相攜。", "唯當清宵夢，仿佛願攀躋。"]'),
('yuding-0','汝州南潭陪陸中丞公宴','孟郊','唐','御定全唐诗','yuding','','[]','一雨百泉漲，南潭夜來深。分明碧沙底，寫出青天心。',108,'御定全唐詩/json/376.json','["一雨百泉漲，南潭夜來深。分明碧沙底，寫出青天心。", "遠客洞庭至，因茲滌煩襟。既登飛雲舫，願奏清風琴。", "高岸立旗戟，潛蛟失浮沉。威棱護斯浸，魍魎逃所侵。", "山態變初霽，水聲流新音。耳目極眺聽，潺湲與嶔岑。", "誰言柳太守，空有白蘋吟。"]'),
('yuding-1','汝州陸中丞席喜張從事至同賦十韻','孟郊','唐','御定全唐诗','yuding','','[]','汝水無濁波，汝山饒奇石。大賢為此郡，佳士來如積。',120,'御定全唐詩/json/376.json','["汝水無濁波，汝山饒奇石。大賢為此郡，佳士來如積。", "有客乘白駒，奉義愜所適。清風蕩華館，雅瑟泛瑤席。", "芳醑靜無喧，金尊光有滌。縱情孰慮損，聽論自招益。", "願折若木枝，卻彼曜靈夕。貴賤一相接，憂悰忽轉易。", "會合勿言輕，別離古來惜。請君駐征車，良遇難再覿。"]'),
('yuding-2','夜集汝州郡齋聽陸僧辯彈琴','孟郊','唐','御定全唐诗','yuding','','[]','康樂寵詞客，清宵意無窮。徵文北山外，借月南樓中。',48,'御定全唐詩/json/376.json','["康樂寵詞客，清宵意無窮。徵文北山外，借月南樓中。", "千里愁並盡，一樽歡暫同。胡為戛楚琴，淅瀝起寒風。"]'),
('yuding-3','同年春燕','孟郊','唐','御定全唐诗','yuding','','[]','少年三十士，嘉會良在茲。高歌搖春風，醉舞摧花枝。',192,'御定全唐詩/json/376.json','["少年三十士，嘉會良在茲。高歌搖春風，醉舞摧花枝。", "意蕩晼晚景，喜凝芳菲時。馬跡攢騕褭，樂聲韻參差。", "視聽改舊趣，物象含新姿。紅雨花上滴，綠煙柳際垂。", "淹中講精義，南皮獻清詞。前賢與今人，千載為一期。", "明鑒有皎潔，澄玉無磷緇。永與沙泥別，各整雲漢儀。", "盛氣自中積，英名日四馳。塞鴻絕儔匹，海月難等夷。", "鬱抑忽已盡，親朋樂無涯。幽蘅發空曲，芳杜綿所思。", "浮跡自聚散，壯心誰別離。願保金石志，無令有奪移。"]'),
('yuding-4','羅氏花下奉招陳侍禦','孟郊','唐','御定全唐诗','yuding','','[]','眼在枝上春，落地成埃塵。不是風流者，誰為攀折人。',96,'御定全唐詩/json/376.json','["眼在枝上春，落地成埃塵。不是風流者，誰為攀折人。", "甯辭波浪闊，莫道往來頻。拾紫豈宜晚，掇芳須及晨。", "勞收賈生淚，強起屈平身。花下本無俗，酒中別有神。", "遊蜂不飲故，戲蝶亦爭新。萬物盡如此，過時非所珍。"]'),
('yuding-5','游石龍渦','孟郊','唐','御定全唐诗','yuding','','[]','石龍不見形，石雨如散星。山下晴皎皎，山中陰泠泠。',84,'御定全唐詩/json/376.json','["石龍不見形，石雨如散星。山下晴皎皎，山中陰泠泠。", "水飛林木杪，珠綴莓苔屏。畜異物皆別，當晨景欲暝。", "泉芳春氣碧，松月寒色青。險力此獨壯，猛獸亦不停。", "日暮且回去，浮心恨未寧。"]'),
('yuding-6','浮石亭','孟郊','唐','御定全唐诗','yuding','','[]','曾是風雨力，崔巍漂來時。落星夜皎潔，近榜朝逶迤。',48,'御定全唐詩/json/376.json','["曾是風雨力，崔巍漂來時。落星夜皎潔，近榜朝逶迤。", "翠瀲遞明滅，清潈瀉欹危。況逢蓬島仙，會合良在茲。"]'),
('yuding-7','看花','孟郊','唐','御定全唐诗','yuding','','[]','家家有芍藥，不妨至溫柔。溫柔一同女，紅笑笑不休。',216,'御定全唐詩/json/376.json','["家家有芍藥，不妨至溫柔。溫柔一同女，紅笑笑不休。", "月娥雙雙下，楚豔枝枝浮。洞裏逢仙人，綽約青宵遊。", "芍藥誰為婿，人人不敢來。唯應待詩老，日日殷勤開。", "玉立無氣力，春凝且裴徊。將何謝青春，痛飲一百杯。", "芍藥吹欲盡，無奈曉風何。餘花欲誰待，唯待諫郎過。", "諫郎不事俗，黃金買高歌。高歌夜更清，花意晚更多。", "飲之不見底，醉倒深紅波。紅波蕩諫心，諫心終無它。", "獨遊終難醉，挈榼徒經過。問花不解語，勸得酒無多。", "三年此村落，春色入心悲。料得一孀婦，經時獨淚垂。"]'),
('yuding-8','濟源春','孟郊','唐','御定全唐诗','yuding','','[]','太行橫偃脊，百里芳崔巍。濟濱花異顏，枋口雲如裁。',120,'御定全唐詩/json/376.json','["太行橫偃脊，百里芳崔巍。濟濱花異顏，枋口雲如裁。", "新畫彩色濕，上界光影來。深紅縷草木，淺碧珩溯洄。", "千家門前飲，一道傳禊杯。玉鱗吞金鉤，仙璿琉璃開。", "朴童茂言語，善俗無驚猜。狂吹寢恒宴，曉清夢先回。", "治生鮮惰夫，積學多深材。再遊詎癲戇，一洗驚塵埃。"]'),
('yuding-9','濟源寒食','孟郊','唐','御定全唐诗','yuding','','[]','風巢嫋嫋春鴉鴉，無子老人仰面嗟。',224,'御定全唐詩/json/376.json','["風巢嫋嫋春鴉鴉，無子老人仰面嗟。", "柳弓葦箭覷不見，高紅遠綠勞相遮。", "女嬋童子黃短短，耳中聞人惜春晚。", "逃蜂匿蝶踏地來，拋卻齋糜一瓷碗。", "一日踏春一百回，朝朝沒腳走芳埃。", "饑童餓馬掃花喂，向晚飲溪三兩杯。", "莓苔井上空相憶，轆轤索斷無消息。", "酒人皆倚春發綠，病叟獨藏秋發白。", "長安落花飛上天，南風引至三殿前。", "可憐春物亦朝謁，唯我孤吟渭水邊。", "枋口花間掣手歸，嵩陽為我留紅暉。", "可憐躑躅千萬尺，柱地柱天疑欲飛。", "蜜蜂為主各磨牙，咬盡村中萬木花。", "君家甕甕今應滿，五色冬籠甚可誇。"]'),
('yuding-10','遊枋口','孟郊','唐','御定全唐诗','yuding','','[]','一步複一步，出行千里幽。為取山水意，故作寂寞遊。',192,'御定全唐詩/json/376.json','["一步複一步，出行千里幽。為取山水意，故作寂寞遊。", "太行青巔高，枋口碧照浮。明明無底鏡，泛泛忘機鷗。", "老逸不自限，病狂不可周。恣閑饒淡薄，怠玩多淹留。", "芳物競晼晚，綠梢掛新柔。和友鶯相繞，言語亦以稠。", "始知萬類然，靜躁難相求。", "聳我殘病骨，健如一仙人。鏡中照千里，鏡浪洞百神。", "此神日月華，不作尋常春。三十夜皆明，四時晝恒新。", "鳥聲盡依依，獸心亦忻忻。澄幽出所怪，閃異坐微絪。", "可來複可來，此地靈相親。"]'),
('yuding-11','與王二十一員外涯游枋口柳溪','孟郊','唐','御定全唐诗','yuding','','[]','萬株古柳根，拏此磷磷溪。野榜多屈曲，仙潯無端倪。',180,'御定全唐詩/json/376.json','["萬株古柳根，拏此磷磷溪。野榜多屈曲，仙潯無端倪。", "春桃散紅煙，寒竹含晚淒。曉聽忽以異，芳樹安能齊。", "共疑落鏡中，坐泛紅景低。水意酒易醒，浪情事非迷。", "小儒峭章句，大賢嘉提攜。潛竇韻靈瑟，翠崖鳴玉珪。", "主人稷卨翁，德茂芝朮畦。鑿出幽隱端，氣象皆升躋。", "曾是清樂抱，逮茲幾省溪。宴位席蘭草，濫觴驚鳧鷖。", "靈味薦魴瓣，金花屑橙齏。江調擺衰俗，洛風遠塵泥。", "徒言奏狂狷，詎敢忘筌蹄。"]'),
('yuding-12','與王二十一員外涯游昭成寺','孟郊','唐','御定全唐诗','yuding','','[]','洛友寂寂約，省騎霏霏塵。游僧步晚磬，話茗含芳春。',84,'御定全唐詩/json/376.json','["洛友寂寂約，省騎霏霏塵。游僧步晚磬，話茗含芳春。", "瑤策冰入手，粉壁畫瑩神。赬廓芙蓉霽，碧殿琉璃勻。", "玄講島嶽盡，淵詠文字新。屢笑寒竹宴，況接青雲賓。", "顧慚餘眷下，衰瘵嬰殘身。"]'),
('yuding-13','嵩少','孟郊','唐','御定全唐诗','yuding','','[]','沙彌舞袈裟，走向躑躅飛。閒步亦惺惺，芳援相依依。',60,'御定全唐詩/json/376.json','["沙彌舞袈裟，走向躑躅飛。閒步亦惺惺，芳援相依依。", "噎塞春咽喉，蜂蝶事光輝。群嬉且已晚，孤引將何歸。", "流豔去不息，朝英亦疏微。"]'),
('yuding-14','旅次洛城東水亭','孟郊','唐','御定全唐诗','yuding','','[]','水竹色相洗，碧花動軒楹。自然逍遙風，蕩滌浮競情。',48,'御定全唐詩/json/376.json','["水竹色相洗，碧花動軒楹。自然逍遙風，蕩滌浮競情。", "霜落葉聲燥，景寒人語清。我來招隱亭，衣上塵暫輕。"]'),
('yuding-15','洛橋晚望','孟郊','唐','御定全唐诗','yuding','','[]','天津橋下冰初結，洛陽陌上人行絕。',32,'御定全唐詩/json/376.json','["天津橋下冰初結，洛陽陌上人行絕。", "榆柳蕭疏樓閣閑，月明直見嵩山雪。"]'),
('yuding-16','北郭貧居','孟郊','唐','御定全唐诗','yuding','','[]','進乏廣莫力，退為蒙籠居。三年失意歸，四向相識疏。',60,'御定全唐詩/json/376.json','["進乏廣莫力，退為蒙籠居。三年失意歸，四向相識疏。", "地僻草木壯，荒條扶我廬。夜貧燈燭絕，明月照吾書。", "欲識貞靜操，秋蟬飲清虛。"]'),
('yuding-17','題陸鴻漸上饒新開山舍','孟郊','唐','御定全唐诗','yuding','','[]','驚彼武陵狀，移歸此岩邊。開亭擬貯雲，鑿石先得泉。',48,'御定全唐詩/json/376.json','["驚彼武陵狀，移歸此岩邊。開亭擬貯雲，鑿石先得泉。", "嘯竹引清吹，吟花成新篇。乃知高潔情，擺落區中緣。"]'),
('yuding-18','題韋承總吳王故城下幽居','孟郊','唐','御定全唐诗','yuding','','[]','才飽身自貴，巷荒門豈貧。韋生堪繼相，孟子願依鄰。',72,'御定全唐詩/json/376.json','["才飽身自貴，巷荒門豈貧。韋生堪繼相，孟子願依鄰。", "夜思琴語切，晝情茶味新。霜枝留過鵲，風竹掃蒙塵。", "郢唱一聲發，吳花千片春。對君何所得，歸去覺情真。"]'),
('yuding-19','蘇州昆山惠聚寺僧房','孟郊','唐','御定全唐诗','yuding','','[]','昨日到上方，片雲掛石床。錫杖莓苔青，袈裟松柏香。',48,'御定全唐詩/json/376.json','["昨日到上方，片雲掛石床。錫杖莓苔青，袈裟松柏香。", "晴磬無短韻，古燈含永光。有時乞鶴歸，還訪逍遙場。"]'),
('yuding-20','題從叔述靈岩山壁','孟郊','唐','御定全唐诗','yuding','','[]','換卻世上心，獨起山中情。露衣涼且鮮，雲策高複輕。',84,'御定全唐詩/json/376.json','["換卻世上心，獨起山中情。露衣涼且鮮，雲策高複輕。", "喜見夏日來，變為松景清。每將逍遙聽，不厭颼飀聲。", "遠念塵末宗，未疏俗間名。桂枝妄舉手，萍路空勞生。", "仰謝開淨弦，相招時一鳴。"]'),
('yuding-21','題林校書花嚴寺書窗','孟郊','唐','御定全唐诗','yuding','','[]','隱詠不誇俗，問禪徒淨居。翻將白雲字，寄向青蓮書。',48,'御定全唐詩/json/376.json','["隱詠不誇俗，問禪徒淨居。翻將白雲字，寄向青蓮書。", "擬古投松坐，就明開紙疏。昭昭南山景，獨與心相如。"]'),
('yuding-22','藍溪元居士草堂','孟郊','唐','御定全唐诗','yuding','','[]','市井不容義，義歸山谷中。夫君宅松桂，招我棲蒙籠。',96,'御定全唐詩/json/376.json','["市井不容義，義歸山谷中。夫君宅松桂，招我棲蒙籠。", "人樸情慮肅，境閑視聽空。清溪宛轉水，修竹徘徊風。", "木倦采樵子，土勞稼穡翁。讀書業雖異，敦本志亦同。", "藍岸青漠漠，藍峰碧崇崇。日昏各命酒，寒蛩鳴蕙叢。"]'),
('yuding-23','新卜清羅幽居奉獻陸大夫','孟郊','唐','御定全唐诗','yuding','','[]','黔婁住何處，仁邑無餒寒。豈悟舊羈旅，變為新閑安。',120,'御定全唐詩/json/376.json','["黔婁住何處，仁邑無餒寒。豈悟舊羈旅，變為新閑安。", "二傾有餘食，三農行可觀。籠禽得高巢，轍鮒還層瀾。", "翳翳桑柘墟，紛紛田裏歡。兵戈忽消散，耦耕非艱難。", "嘉木偶良酌，芳陰庇清彈。力農唯一事，趣世徒萬端。", "靜覺本相厚，動為末所殘。此外有餘暇，鋤荒出幽蘭。"]'),
('yuding-24','題韋少保靜恭宅藏書洞','孟郊','唐','御定全唐诗','yuding','','[]','高意合天制，自然狀無窮。仙華凝四時，玉蘚生數峰。',72,'御定全唐詩/json/376.json','["高意合天制，自然狀無窮。仙華凝四時，玉蘚生數峰。", "書秘漆文字，匣藏金蛟龍。閑為氣候肅，開作雲雨濃。", "洞隱諒非久，岩夢誠必通。將綴文士集，貫就真珠叢。"]'),
('yuding-25','生生亭','孟郊','唐','御定全唐诗','yuding','','[]','灘鬧不妨語，跨溪仍置亭。置亭嵽嵲頭，開窗納遙青。',108,'御定全唐詩/json/376.json','["灘鬧不妨語，跨溪仍置亭。置亭嵽嵲頭，開窗納遙青。", "遙青新畫出，三十六扇屏。褭褭立平地，棱棱浮高冥。", "一日數開扉，仙閃目不停。徒誇遠方岫，曷若中峰靈。", "拔意千餘丈，浩言永堪銘。浩言無愧同，愧同忍醜醒。", "致之未有力，力在君子聽。"]'),
('yuding-26','寒溪','孟郊','唐','御定全唐诗','yuding','','[]','霜洗水色盡，寒溪見纖鱗。幸臨虛空鏡，照此殘悴身。',528,'御定全唐詩/json/376.json','["霜洗水色盡，寒溪見纖鱗。幸臨虛空鏡，照此殘悴身。", "潛滑不自隱，露底瑩更新。豁如君子懷，曾是危陷人。", "始明淺俗心，夜結朝已津。淨漱一掬碧，遠消千慮塵。", "始知泥步泉，莫與山源鄰。", "洛陽岸邊道，孟氏莊前溪。舟行素冰折，聲作青瑤嘶。", "綠水結綠玉，白波生白珪。明明寶鏡中，物物天照齊。", "仄步下危曲，攀枯聞孀啼。霜芬稍消歇，凝景微茫齊。", "癡坐直視聽，戇行失蹤蹊。岸童劚棘勞，語言多悲淒。", "曉飲一杯酒，踏雪過清溪。波瀾凍為刀，剸割鳧與鷖。", "宿羽皆翦棄，血聲沉沙泥。獨立欲何語，默念心酸嘶。", "凍血莫作春，作春生不齊。凍血莫作花，作花發孀啼。", "幽幽棘針村，凍死難耕犁。", "篙工磓玉星，一路隨迸螢。朔凍哀徹底，獠饞詠潛鯹。", "冰齒相磨齧，風音酸鐸鈴。清悲不可逃，洗出纖悉聽。", "碧瀲卷已盡，彩縷飛飄零。下躡滑不定，上棲折難停。", "哮嘐呷喢冤，仰訴何時寧。", "一曲一直水，白龍何鱗鱗。凍飆雜碎號，齏音坑谷辛。", "柧椾吃無力，飛走更相仁。猛弓一折弦，餘喘爭來賓。", "大嚴此之立，小殺不復陳。皎皎何皎皎，氤氳複氤氳。", "瑞晴刷日月，高碧開星辰。獨立兩腳雪，孤吟千慮新。", "天欃徒昭昭，箕舌虛齗齗。堯聖不聽汝，孔微亦有臣。", "諫書竟成章，古義終難陳。", "因凍死得食，殺風仍不休。以兵為仁義，仁義生刀頭。", "刀頭仁義腥，君子不可求。波瀾抽劍冰，相劈如仇讎。"]'),
('yuding-27','立德新居','孟郊','唐','御定全唐诗','yuding','','[]','立德何亭亭，西南聳高隅。陽崖泄春意，井圃留冬蕪。',480,'御定全唐詩/json/376.json','["立德何亭亭，西南聳高隅。陽崖泄春意，井圃留冬蕪。", "勝引即紆道，幽行豈通衢。碧峰遠相揖，清思誰言孤。", "寺秩雖貴家，濁醪良可哺。", "聳城架霄漢，潔宅涵絪縕。開門洛北岸，時鎖嵩陽雲。", "夜高星辰大，晝長天地分。厚韻屬疏語，薄名謝囂聞。", "茲焉有殊隔，永矣難及群。", "賓秩已覺厚，私儲常恐多。清貧聊自爾，素責將如何。", "儉教先勉力，修襟無餘佗。良棲一枝木，靈巢片葉荷。", "仰笑鶤鵬輩，委身拂天波。", "疏門不掩水，洛色寒更高。曉碧流視聽，夕清濯衣袍。", "為于仁義得，未覺登陟勞。遠岸雪難莫，勁枝風易號。", "霜禽各嘯侶，吾亦愛吾曹。", "崎嶇有懸步，委曲饒荒尋。遠樹足良木，疏巢無爭禽。", "素魄銜夕岸，綠水生曉潯。空曠伊洛視，仿佛瀟湘心。", "何必尚遠異，憂勞滿行襟。", "懸途多仄足，崎圃無修畦。芳蘭與宿艾，手擷心不迷。", "品子懶讀書，轅駒難服犁。虛食日相投，誇腸詎能低。", "恥從新學遊，願將古農齊。", "都城多聳秀，愛此高縣居。伊雒繞街巷，鴛鴦飛閻閭。", "翠景何的礫，霜颸飄空虛。突出萬家表，獨治二畝蔬。", "一旬一手版，十日九手鋤。", "手鋤手自勖，激勸亦已饒。畏彼梨栗兒，空資玩弄驕。", "夜景臥難盡，晝光坐易消。治舊得新義，耕荒生嘉苗。", "鋤治苟愜適，心形俱逍遙。"]'),
('yuding-0','西上經靈寶觀','孟郊','唐','御定全唐诗','yuding','','[]','道士無白髮，語音靈泉清。青松多壽色，白石恒夜明。',72,'御定全唐詩/json/377.json','["道士無白髮，語音靈泉清。青松多壽色，白石恒夜明。", "放步霽霞起，振衣華風生。真文秘中頂，寶氣浮四楹。", "一片古關路，萬里今人行。上仙不可見，驅策徒西征。"]'),
('yuding-1','泛黃河','孟郊','唐','御定全唐诗','yuding','','[]','誰開昆侖源，流出混沌河。積雨飛作風，驚龍噴為波。',48,'御定全唐詩/json/377.json','["誰開昆侖源，流出混沌河。積雨飛作風，驚龍噴為波。", "湘瑟颼飀弦，越賓嗚咽歌。有恨不可洗，虛此來經過。"]'),
('yuding-2','往河陽宿峽陵，寄李侍禦','孟郊','唐','御定全唐诗','yuding','','[]','暮天寒風悲屑屑，啼鳥繞樹泉水噎。行路解鞍投古陵，',40,'御定全唐詩/json/377.json','["暮天寒風悲屑屑，啼鳥繞樹泉水噎。行路解鞍投古陵，", "人生窮達感知己，明日投君申片言。"]'),
('yuding-3','鴉路溪行，呈陸中丞','孟郊','唐','御定全唐诗','yuding','','[]','鴉路不可越，三十六渡溪。有物飲碧水，高林掛青蜺。',108,'御定全唐詩/json/377.json','["鴉路不可越，三十六渡溪。有物飲碧水，高林掛青蜺。", "曆覽道更險，驅使跡頻暌。視聽易常主，心魂互相迷。", "浪石忽搖動，沙堤信難躋。危峰紫霄外，古木浮雲齊。", "出阻望汝郡，大賢多招攜。疲馬戀舊秣，羈禽思故棲。", "應憐泣楚玉，棄置如塵泥。"]'),
('yuding-4','獨宿峴首憶長安故人','孟郊','唐','御定全唐诗','yuding','','[]','月迥無隱物，況複大江秋。江城與沙村，人語風颼飀。',48,'御定全唐詩/json/377.json','["月迥無隱物，況複大江秋。江城與沙村，人語風颼飀。", "峴亭當此時，故人不同游。故人在長安，亦可將夢求。"]'),
('yuding-5','自商行謁複州盧使君虔','孟郊','唐','御定全唐诗','yuding','','[]','一身繞千山，遠作行路人。未遂東吳歸，暫出西京塵。',96,'御定全唐詩/json/377.json','["一身繞千山，遠作行路人。未遂東吳歸，暫出西京塵。", "仲宣荊州客，今餘竟陵賓。往跡雖不同，托意皆有因。", "商嶺莓苔滑，石阪上下頻。江漢沙泥潔，永日光景新。", "獨淚起殘夜，孤吟望初晨。驅馳竟何事，章句依深仁。"]'),
('yuding-6','夢澤中行','孟郊','唐','御定全唐诗','yuding','','[]','楚山爭蔽虧，日月無全輝。楚路饒回惑，旅人有迷歸。',48,'御定全唐詩/json/377.json','["楚山爭蔽虧，日月無全輝。楚路饒回惑，旅人有迷歸。", "騏驥思北首，鷓鴣願南飛。我懷京洛遊，未厭風塵衣。"]'),
('yuding-7','京山行','孟郊','唐','御定全唐诗','yuding','','[]','眾虻聚病馬，流血不得行。後路起夜色，前山聞虎聲。',36,'御定全唐詩/json/377.json','["眾虻聚病馬，流血不得行。後路起夜色，前山聞虎聲。", "此時遊子心，百尺風中旌。"]'),
('yuding-8','旅次湘沅有懷靈均','孟郊','唐','御定全唐诗','yuding','','[]','分拙多感激，久遊遵長途。經過湘水源，懷古方踟躕。',240,'御定全唐詩/json/377.json','["分拙多感激，久遊遵長途。經過湘水源，懷古方踟躕。", "舊稱楚靈均，此處殞忠軀。側聆故老言，遂得旌賢愚。", "名參君子場，行為小人儒。騷文衒貞亮，體物情崎嶇。", "三黜有慍色，即非賢哲模。五十爵高秩，謬膺從大夫。", "胸襟積憂愁，容鬢複凋枯。死為不吊鬼，生作猜謗徒。", "吟澤潔其身，忠節寧見輸。懷沙滅其性，孝行焉能俱。", "且聞善稱君，一何善自殊。且聞過稱己，一何過不渝。", "悠哉風土人，角黍投川隅。相傳曆千祀，哀悼延八區。", "如今聖明朝，養育無羈孤。君臣逸雍熙，德化盈紛敷。", "巾車徇前侶，白日猶昆吾。寄君臣子心，戒此真良圖。"]'),
('yuding-9','過彭澤','孟郊','唐','御定全唐诗','yuding','','[]','揚帆過彭澤，舟人訝歎息。不見種柳人，霜風空寂曆。',24,'御定全唐詩/json/377.json','["揚帆過彭澤，舟人訝歎息。不見種柳人，霜風空寂曆。"]'),
('yuding-10','過分水嶺','孟郊','唐','御定全唐诗','yuding','','[]','山壯馬力短，馬行石齒中。十步九舉轡，回環失西東。',60,'御定全唐詩/json/377.json','["山壯馬力短，馬行石齒中。十步九舉轡，回環失西東。", "溪水變為雨，懸崖陰濛濛。客衣飄颻秋，葛花零落風。", "白日舍我沒，征途忽然窮。"]'),
('yuding-11','分水嶺別夜示從弟寂','孟郊','唐','御定全唐诗','yuding','','[]','南中少平地，山水重疊生。別泉萬餘曲，迷舟獨難行。',96,'御定全唐詩/json/377.json','["南中少平地，山水重疊生。別泉萬餘曲，迷舟獨難行。", "四際亂峰合，一眺千慮並。潺湲冬夏冷，光彩晝夜明。", "賞心難久勝，離腸忽自驚。古木搖霽色，高風動秋聲。", "飲爾一樽酒，慰我百憂輕。嘉期何處定，此晨堪寄情。"]'),
('yuding-12','連州吟','孟郊','唐','御定全唐诗','yuding','','[]','春風朝夕起，吹綠日日深。試為連州吟，淚下不可禁。',264,'御定全唐詩/json/377.json','["春風朝夕起，吹綠日日深。試為連州吟，淚下不可禁。", "連山何連連，連天碧岑岑。哀猿哭花死，子規裂客心。", "蘭芷結新佩，瀟湘遺舊音。怨聲能翦弦，坐撫零落琴。", "羽翼不自有，相追力難任。唯憑方寸靈，獨夜萬里尋。", "方尋魂飄颻，南夢山嶇嶔。仿佛驚魍魎，悉窣聞楓林。", "正直被放者，鬼魅無所侵。賢人多安排，俗士多虛欽。", "孤懷吐明月，眾毀鑠黃金。願君保玄曜，壯志無自沉。", "朝亦連州吟，暮亦連州吟。連州果有信，一紙萬里心。", "開緘白雲斷，明月墮衣襟。南風嘶舜管，苦竹動猿音。", "萬里愁一色，瀟湘雨淫淫。兩劍忽相觸，雙蛟恣浮沉。", "鬥水正回斡，倒流安可禁。空愁江海信，驚浪隔相尋。"]'),
('yuding-13','旅行','孟郊','唐','御定全唐诗','yuding','','[]','楚水結冰薄，楚雲為雨微。野梅參差發，旅榜逍遙歸。',24,'御定全唐詩/json/377.json','["楚水結冰薄，楚雲為雨微。野梅參差發，旅榜逍遙歸。"]'),
('yuding-14','上河陽李大夫','孟郊','唐','御定全唐诗','yuding','','[]','上將秉神略，至兵無猛威。三軍當嚴冬，一撫勝重衣。',108,'御定全唐詩/json/377.json','["上將秉神略，至兵無猛威。三軍當嚴冬，一撫勝重衣。", "霜劍奪眾景，夜星失長輝。蒼鷹獨立時，惡鳥不敢飛。", "武牢鎖天關，河橋紐地機。大將奚以安，守此稱者稀。", "貧士少顏色，貴門多輕肥。試登山嶽高，方見草木微。", "山嶽恩既廣，草木心皆歸。"]'),
('yuding-15','投贈張端公','孟郊','唐','御定全唐诗','yuding','','[]','君子量不極，胸吞百川流。嫉邪霜氣直，問俗春辭柔。',72,'御定全唐詩/json/377.json','["君子量不極，胸吞百川流。嫉邪霜氣直，問俗春辭柔。", "日戶晝輝靜，月杯夜景幽。詠驚芙蓉發，笑激風飆秋。", "鸞步獨無侶，鶴音仍寡儔。幸沾分寸顧，散此千萬憂。"]'),
('yuding-16','贈蘇州韋郎中使君','孟郊','唐','御定全唐诗','yuding','','[]','謝客吟一聲，霜落群聽清。文含元氣柔，鼓動萬物輕。',96,'御定全唐詩/json/377.json','["謝客吟一聲，霜落群聽清。文含元氣柔，鼓動萬物輕。", "嘉木依性植，曲枝亦不生。塵埃徐庾詞，金玉曹劉名。", "章句作雅正，江山益鮮明。萍蘋一浪草，菰蒲片池榮。", "曾是康樂詠，如今搴其英。顧惟菲薄質，亦願將此並。"]'),
('yuding-17','上張徐州','孟郊','唐','御定全唐诗','yuding','','[]','為水不入海，安得浮天波。為木不在山，安得橫日柯。',144,'御定全唐詩/json/377.json','["為水不入海，安得浮天波。為木不在山，安得橫日柯。", "再來君子傍，始覺精義多。大德唯一施，眾情自偏頗。", "至樂無宮征，至聲遺謳歌。願鼓空桑弦，永使萬物和。", "顧己誠拙訥，幹名已蹉跎。獻詞惟在口，所欲無餘佗。", "乍作支泉石，乍作翳松蘿。一不改方圓，破質為琢磨。", "賤子本如此，大賢心若何。豈是無異途，異途難經過。"]'),
('yuding-18','上包祭酒','孟郊','唐','御定全唐诗','yuding','','[]','岳岳冠蓋彥，英英文字雄。瓊音獨聽時，塵韻固不同。',72,'御定全唐詩/json/377.json','["岳岳冠蓋彥，英英文字雄。瓊音獨聽時，塵韻固不同。", "春雲生紙上，秋濤起胸中。時吟五君詠，再舉七子風。", "何幸松桂侶，見知勤苦功。願將黃鶴翅，一借飛雲空。"]'),
('yuding-19','贈別崔純亮','孟郊','唐','御定全唐诗','yuding','','[]','食薺腸亦苦，強歌聲無歡。出門即有礙，誰謂天地寬。',192,'御定全唐詩/json/377.json','["食薺腸亦苦，強歌聲無歡。出門即有礙，誰謂天地寬。", "有礙非遐方，長安大道傍。小人智慮險，平地生太行。", "鏡破不改光，蘭死不改香。始知君子心，交久道益彰。", "君心與我懷，離別俱回遑。譬如浸蘖泉，流苦已日長。", "忍泣目易衰，忍憂形易傷。項籍豈不壯，賈生豈不良。", "當其失意時，涕泗各沾裳。古人勸加餐，此餐難自強。", "一飯九祝噎，一嗟十斷腸。況是兒女怨，怨氣淩彼蒼。", "彼蒼若有知，白日下清霜。今朝始驚歎，碧落空茫茫。"]'),
('yuding-20','贈文應上人','孟郊','唐','御定全唐诗','yuding','','[]','棲遲青山巔，高靜身所便。不踐有命草，但飲無聲泉。',60,'御定全唐詩/json/377.json','["棲遲青山巔，高靜身所便。不踐有命草，但飲無聲泉。", "齋性空轉寂，學情深更專。經文開貝葉，衣制垂秋蓮。", "厭此俗人群，暫來還卻旋。"]'),
('yuding-21','嚴河南','孟郊','唐','御定全唐诗','yuding','','[]','赤令風骨峭，語言清霜寒。不必用雄威，見者毛髮攢。',156,'御定全唐詩/json/377.json','["赤令風骨峭，語言清霜寒。不必用雄威，見者毛髮攢。", "我有赤令心，未得赤令官。終朝衡門下，忍志將築彈。", "君從西省郎，正有東洛觀。洛民蕭條久，威恩憫撫難。", "苦竹聲嘯雪，夜齋聞千竿。詩人偶寄耳，聽苦心多端。", "多端落杯酒，酒中方得歡。隱士多飲酒，此言信難刊。", "取次令坊沽，舉止務在寬。何必紅燭嬌，始言清宴闌。", "丈夫莫矜莊，矜莊不中看。"]'),
('yuding-22','贈李觀','孟郊','唐','御定全唐诗','yuding','','[]','誰言形影親，燈滅影去身。誰言魚水歡，水竭魚枯鱗。',96,'御定全唐詩/json/377.json','["誰言形影親，燈滅影去身。誰言魚水歡，水竭魚枯鱗。", "昔為同恨客，今為獨笑人。舍予在泥轍，飄跡上雲津。", "臥木易成蠹，棄花難再春。何言對芳景，愁望極蕭晨。", "埋劍誰識氣，匣弦日生塵。願君語高風，為餘問蒼旻。"]'),
('yuding-23','吳安西館贈從弟楚客','孟郊','唐','御定全唐诗','yuding','','[]','蒙籠楊柳館，中有南風生。風生今為誰，湘客多遠情。',60,'御定全唐詩/json/377.json','["蒙籠楊柳館，中有南風生。風生今為誰，湘客多遠情。", "孤枕楚水夢，獨帆楚江程。覺來殘恨深，尚與歸路並。", "玉匣五弦在，請君時一鳴。"]'),
('yuding-24','贈章仇將軍','孟郊','唐','御定全唐诗','yuding','','[]','將軍不誇劍，才氣為英雄。五嶽拽力內，百川傾意中。',48,'御定全唐詩/json/377.json','["將軍不誇劍，才氣為英雄。五嶽拽力內，百川傾意中。", "本立誰敢拔，飛文自難窮。前時天地翻，已有扶正功。"]'),
('yuding-25','贈道月上人','孟郊','唐','御定全唐诗','yuding','','[]','僧貌淨無點，僧衣甯綴華。尋常晝日行，不使身影斜。',48,'御定全唐詩/json/377.json','["僧貌淨無點，僧衣甯綴華。尋常晝日行，不使身影斜。", "飯術煮松柏，坐山敷雲霞。欲知禪隱高，緝薜為袈裟。"]'),
('yuding-26','抒情因上郎中二十二叔監察十五叔兼呈李益端公柳縝評事','孟郊','唐','御定全唐诗','yuding','','[]','方憑指下弦，寫出心中言。寸草賤子命，高山主人恩。',108,'御定全唐詩/json/377.json','["方憑指下弦，寫出心中言。寸草賤子命，高山主人恩。", "游邊風沙意，夢楚波濤魂。一日引別袂，九回沾淚痕。", "自悲何以然，在禮闕晨昏。名利時轉甚，是非宵亦喧。", "浮情少定主，百慮隨世翻。舉此胸臆恨，幸從賢哲論。", "明明三飛鸞，照物如朝暾。"]'),
('yuding-27','贈城郭道士','孟郊','唐','御定全唐诗','yuding','','[]','望裏失卻山，聽中遺卻泉。松枝休策雲，藥囊翻貯錢。',48,'御定全唐詩/json/377.json','["望裏失卻山，聽中遺卻泉。松枝休策雲，藥囊翻貯錢。", "曾依青桂鄰，學得白雪弦。別來意未回，世上為隱仙。"]'),
('yuding-28','桐廬山中贈李明府','孟郊','唐','御定全唐诗','yuding','','[]','靜境無濁氛，清雨零碧雲。千山不隱響，一葉動亦聞。',48,'御定全唐詩/json/377.json','["靜境無濁氛，清雨零碧雲。千山不隱響，一葉動亦聞。", "即此佳志士，精微誰相群。欲識楚章句，袖中蘭茝熏。"]'),
('yuding-29','獻漢南樊尚書','孟郊','唐','御定全唐诗','yuding','','[]','天下昔崩亂，大君識賢臣。眾木盡搖落，始見竹色真。',120,'御定全唐詩/json/377.json','["天下昔崩亂，大君識賢臣。眾木盡搖落，始見竹色真。", "兵勢走山嶽，陽光潛埃塵。心開玄女符，面縛清波人。", "異俗既從化，澆風亦歸淳。自公理斯郡，寒穀皆變春。", "旗影卷赤電，劍鋒匣青鱗。如何嵩高氣，作鎮楚水濱。", "雲鏡忽開霽，孤光射無垠。乃知尋常鑒，照影不照神。"]'),
('yuding-30','贈轉運陸中丞','孟郊','唐','御定全唐诗','yuding','','[]','掌運職既大，摧邪名更雄。鵬飛簸曲雲，鶚怒生直風。',120,'御定全唐詩/json/377.json','["掌運職既大，摧邪名更雄。鵬飛簸曲雲，鶚怒生直風。", "投彼霜雪令，翦除荊棘叢。楚倉傾向西，吳米發自東。", "帆影咽河口，車聲聾關中。堯知才策高，人喜道路通。", "皆經內史力，繼得酂侯功。萊子真為少，相如未免窮。", "衣花野菡萏，書葉山梧桐。不是宗匠心，誰憐久棲蓬。"]'),
('yuding-31','贈萬年陸郎中','孟郊','唐','御定全唐诗','yuding','','[]','天子憂劇縣，寄深華省郎。紛紛風響佩，蟄蟄劍開霜。',72,'御定全唐詩/json/377.json','["天子憂劇縣，寄深華省郎。紛紛風響佩，蟄蟄劍開霜。", "舊事笑堆案，新聲唯雅章。誰言百里才，終作橫天梁。", "江鴻恥承眷，雲津未能翔。徘徊塵俗中，短毳無輝光。"]'),
('yuding-32','擢第後東歸書懷，獻座主呂侍禦','孟郊','唐','御定全唐诗','yuding','','[]','昔歲辭親淚，今為戀主泣。去住情難並，別離景易戢。',180,'御定全唐詩/json/377.json','["昔歲辭親淚，今為戀主泣。去住情難並，別離景易戢。", "夭矯大空鱗，曾為小泉蟄。幽意獨沉時，震雷忽相及。", "神行既不宰，直致非所執。至運本遺功，輕生各自立。", "大君思此化，良佐自然集。寶鏡無私光，時文有新習。", "慈親誡志就，賤子歸情急。擢第謝靈台，牽衣出皇邑。", "行襟海日曙，逸抱江風入。蒹葭得波浪，芙蓉紅岸濕。", "雲寺勢動搖，山鐘韻噓吸。舊遊期再踐，懸水得重挹。", "松蘿雖可居，青紫終當拾。"]'),
('yuding-33','古意贈梁肅補闕','孟郊','唐','御定全唐诗','yuding','','[]','曲木忌日影，讒人畏賢明。自然照燭間，不受邪佞輕。',48,'御定全唐詩/json/377.json','["曲木忌日影，讒人畏賢明。自然照燭間，不受邪佞輕。", "不有百煉火，孰知寸金精。金鉛正同爐，願分精與粗。"]'),
('yuding-34','贈黔府王中丞楚','孟郊','唐','御定全唐诗','yuding','','[]','舊說天下山，半在黔中青。又聞天下泉，半落黔中鳴。',132,'御定全唐詩/json/377.json','["舊說天下山，半在黔中青。又聞天下泉，半落黔中鳴。", "山水千萬繞，中有君子行。儒風一以扇，汙俗心皆平。", "我願中國春，化從異方生。昔為陰草毒，今為陽華英。", "嘉實綴綠蔓，涼湍瀉清聲。逍遙物景勝，視聽空曠並。", "困驥猶在轅，沉珠尚隱精。路遐莫及眄，泥汙日已盈。", "歲晏將何從，落葉甘自輕。"]'),
('yuding-35','上達奚舍人','孟郊','唐','御定全唐诗','yuding','','[]','北山少日月，草木苦風霜。貧士在重坎，食梅有酸腸。',72,'御定全唐詩/json/377.json','["北山少日月，草木苦風霜。貧士在重坎，食梅有酸腸。", "萬俗皆走圓，一身猶學方。常恐眾毀至，春葉成秋黃。", "大賢秉高鑒，公燭無私光。暗室曉未及，幽行涕空行。"]'),
('yuding-36','贈主人','孟郊','唐','御定全唐诗','yuding','','[]','鬥水瀉大海，不如瀉枯池。分明賢達交，豈顧豪華兒。',84,'御定全唐詩/json/377.json','["鬥水瀉大海，不如瀉枯池。分明賢達交，豈顧豪華兒。", "海有不足流，豪有不足資。枯鱗易為水，貧士易為施。", "幸睹君子席，會將幽賤期。側聞清風議，飫如黃金卮。", "此道與日月，同光無盡時。"]'),
('yuding-37','贈建業契公','孟郊','唐','御定全唐诗','yuding','','[]','師住青山寺，清華常繞身。雖然到城郭，衣上不棲塵。',24,'御定全唐詩/json/377.json','["師住青山寺，清華常繞身。雖然到城郭，衣上不棲塵。"]'),
('yuding-38','獻襄陽于大夫','孟郊','唐','御定全唐诗','yuding','','[]','襄陽青山郭，漢江白銅堤。謝公領茲郡，山水無塵泥。',132,'御定全唐詩/json/377.json','["襄陽青山郭，漢江白銅堤。謝公領茲郡，山水無塵泥。", "鐵馬萬霜雪，絳旗千虹霓。風漪參差泛，石板重疊躋。", "舊淚不復墮，新歡居然齊。還耕竟原野，歸老相扶攜。", "物色增曖曖，寒芳更萋萋。淵清有遐略，高躅無近蹊。", "即此富蒼翠，自然引翔棲。曩游常抱憶，夙好今尚暌。", "願言從逸轡，暇日淩清溪。"]'),
('yuding-39','贈鄭夫子魴','孟郊','唐','御定全唐诗','yuding','','[]','天地入胸臆，籲嗟生風雷。文章得其微，物象由我裁。',60,'御定全唐詩/json/377.json','["天地入胸臆，籲嗟生風雷。文章得其微，物象由我裁。", "宋玉逞大句，李白飛狂才。苟非聖賢心，孰與造化該。", "勉矣鄭夫子，驪珠今始胎。"]'),
('yuding-40','大隱坊：崔從事鄖以直隳職','孟郊','唐','御定全唐诗','yuding','','[]','古人留清風，千載遙贈君。破松見貞心，裂竹見直文。',72,'御定全唐詩/json/377.json','["古人留清風，千載遙贈君。破松見貞心，裂竹見直文。", "殘月色不改，高賢德常新。家懷詩書富，宅抱草木貧。", "安得一蹄泉，來化千尺鱗。含意永不語，釣璜幽水濱。"]'),
('yuding-41','大隱坊：章仇將軍良棄功守貧','孟郊','唐','御定全唐诗','yuding','','[]','飲君江海心，詎能辨淺深。挹君山嶽德，誰能齊嶔岑。',72,'御定全唐詩/json/377.json','["飲君江海心，詎能辨淺深。挹君山嶽德，誰能齊嶔岑。", "東海精為月，西嶽氣凝金。進則萬景晝，退則群物陰。", "我欲薦此言，天門峻沉沉。風飆亦感激，為我颼飀吟。"]'),
('yuding-42','大隱坊：趙記室俶在職無事','孟郊','唐','御定全唐诗','yuding','','[]','卑靜身後老，高動物先摧。方圓水任器，剛勁木成灰。',72,'御定全唐詩/json/377.json','["卑靜身後老，高動物先摧。方圓水任器，剛勁木成灰。", "大道母群物，達人腹眾才。時吟堯舜篇，心向無為開。", "彼隱山萬曲，我隱酒一杯。公庭何所有，日日清風來。"]'),
('yuding-43','贈韓郎中愈','孟郊','唐','御定全唐诗','yuding','','[]','何以定交契，贈君高山石。何以保貞堅，贈君青松色。',156,'御定全唐詩/json/377.json','["何以定交契，贈君高山石。何以保貞堅，贈君青松色。", "貧居過此外，無可相彩飾。聞君碩鼠詩，吟之淚空滴。", "碩鼠既穿墉，又齧機上絲。穿墉有閑土，齧絲無餘衣。", "朝吟枯桑柘，暮泣空杼機。豈是無巧妙，絲斷將何施。", "眾人尚肥華，志士多饑羸。願君保此節，天意當察微。", "前日遠別離，今日生白髮。欲知萬里情，曉臥半床月。", "常恐百蟲秋，使我芳草歇。"]'),
('yuding-44','戲贈無本','孟郊','唐','御定全唐诗','yuding','','[]','長安秋聲幹，木葉相號悲。瘦僧臥冰淩，嘲詠含金痍。',240,'御定全唐詩/json/377.json','["長安秋聲幹，木葉相號悲。瘦僧臥冰淩，嘲詠含金痍。", "金痍非戰痕，峭病方在茲。詩骨聳東野，詩濤湧退之。", "有時踉蹌行，人驚鶴阿師。可惜李杜死，不見此狂癡。", "燕僧聳聽詞，袈裟喜新翻。北嶽厭利殺，玄功生微言。", "天高亦可飛，海廣亦可源。文章杳無底，劚掘誰能根。", "夢靈仿佛到，對我方與論。拾月鯨口邊，何人免為吞。", "燕僧擺造化，萬有隨手奔。補綴雜霞衣，笑傲諸貴門。", "將明文在身，亦爾道所存。朔雪凝別句，朔風飄征魂。", "再期嵩少遊，一訪蓬蘿村。春草步步綠，春山日日暄。", "遙鶯相應吟，晚聽恐不繁。相思塞心胸，高逸難攀援。"]'),
('yuding-0','寄張籍','孟郊','唐','御定全唐诗','yuding','','[]','夜鏡不照物，朝光何時升。黯然秋思來，走入志士膺。',108,'御定全唐詩/json/378.json','["夜鏡不照物，朝光何時升。黯然秋思來，走入志士膺。", "志士惜時逝，一宵三四興。清漢徒自朗，濁河終無澄。", "舊愛忽已遠，新愁坐相淩。君其隱壯懷，我亦逃名稱。", "古人貴從晦，君子忌党朋。傾敗生所競，保全歸懵懵。", "浮雲何當來，潛虯會飛騰。"]'),
('yuding-1','憶周秀才、素上人，時聞各在一方','孟郊','唐','御定全唐诗','yuding','','[]','東西分我情，魂夢安能定。野客雲作心，高僧月為性。',72,'御定全唐詩/json/378.json','["東西分我情，魂夢安能定。野客雲作心，高僧月為性。", "浮雲自高閑，明月常空淨。衣敝得古風，居山無俗病。", "吟聽碧雲語，手把青松柄。羨爾欲寄書，飛禽杳難倩。"]'),
('yuding-2','舟中喜遇從叔簡別後寄上時從叔初擢第歸江南郊不從行','孟郊','唐','御定全唐诗','yuding','','[]','一意兩片雲，暫合還卻分。南雲乘慶歸，北雲與誰群。',36,'御定全唐詩/json/378.json','["一意兩片雲，暫合還卻分。南雲乘慶歸，北雲與誰群。", "寄聲千里風，相喚聞不聞。"]'),
('yuding-3','懷南嶽隱士','孟郊','唐','御定全唐诗','yuding','','[]','見說祝融峰，擎天勢似騰。藏千尋布水，出十八高僧。',96,'御定全唐詩/json/378.json','["見說祝融峰，擎天勢似騰。藏千尋布水，出十八高僧。", "古路無人跡，新霞吐石棱。終居將爾叟，一一共餘登。", "千峰映碧湘，真叟此中藏。飯不煮石吃，眉應似發長。", "楓杞榰酒甕，鶴虱落琴床。強效忘機者，斯人尚未忘。"]'),
('yuding-4','春夜憶蕭子真','孟郊','唐','御定全唐诗','yuding','','[]','半夜不成寐，燈盡又無月。獨向階前立，子規啼不歇。',48,'御定全唐詩/json/378.json','["半夜不成寐，燈盡又無月。獨向階前立，子規啼不歇。", "況我有金蘭，忽爾為胡越。爭得明鏡中，久長無白髮。"]'),
('yuding-5','寄院中諸公','孟郊','唐','御定全唐诗','yuding','','[]','奕奕秋水傍，駸駸綠雲蹄。月仙有高曜，靈鳳無卑棲。',96,'御定全唐詩/json/378.json','["奕奕秋水傍，駸駸綠雲蹄。月仙有高曜，靈鳳無卑棲。", "翠色繞雲谷，碧華凝月溪。竹林遞曆覽，雲寺行攀躋。", "冠豸猶屈蠖，匣龍期剸犀。千山驚月曉，百里聞霜鼙。", "戎府多秀異，謝公期相攜。因之仰群彥，養拙固難齊。"]'),
('yuding-6','寄洺州李大夫','孟郊','唐','御定全唐诗','yuding','','[]','自從薊師反，中國事紛紛。儒道一失所，賢人多在軍。',108,'御定全唐詩/json/378.json','["自從薊師反，中國事紛紛。儒道一失所，賢人多在軍。", "鳥巢憂迸射，鹿耳駭驚聞。劍折唯恐匣，弓貪不讓勳。", "方知省事將，動必謝前群。鸛陣常先罷，魚符最晚分。", "步閑洺水曲，笑激太行雲。詩叟未相識，竹兒爭見君。", "殷勤越談說，記盡古風文。"]'),
('yuding-7','寄盧虔使君','孟郊','唐','御定全唐诗','yuding','','[]','霜露再相換，遊人猶未歸。歲新月改色，客久線斷衣。',60,'御定全唐詩/json/378.json','["霜露再相換，遊人猶未歸。歲新月改色，客久線斷衣。", "有鶴冰在翅，竟久力難飛。千家舊素沼，昨日生綠輝。", "春色若可借，為君步芳菲。"]'),
('yuding-8','寄崔純亮','孟郊','唐','御定全唐诗','yuding','','[]','百川有餘水，大海無滿波。器量各相懸，賢愚不同科。',60,'御定全唐詩/json/378.json','["百川有餘水，大海無滿波。器量各相懸，賢愚不同科。", "群辯有姿語，眾歡無行歌。唯餘洛陽子，鬱鬱恨常多。", "時讀過秦篇，為君涕滂沱。"]'),
('yuding-9','汴州離亂後憶韓愈、李翱','孟郊','唐','御定全唐诗','yuding','','[]','會合一時哭，別離三斷腸。殘花不待風，春盡各飛揚。',108,'御定全唐詩/json/378.json','["會合一時哭，別離三斷腸。殘花不待風，春盡各飛揚。", "歡去收不得，悲來難自防。孤門清館夜，獨臥明月床。", "忠直血白刃，道路聲蒼黃。食恩三千士，一旦為豺狼。", "海島士皆直，夷門士非良。人心既不類，天道亦反常。", "自殺與彼殺，未知何者臧。"]'),
('yuding-10','寄張籍','孟郊','唐','御定全唐诗','yuding','','[]','未見天子面，不如雙盲人。賈生對文帝，終日猶悲辛。',94,'御定全唐詩/json/378.json','["未見天子面，不如雙盲人。賈生對文帝，終日猶悲辛。", "夫子亦如盲，所以空泣麟。有時獨齋心，仿佛夢稱臣。", "夢中稱臣言，覺後真埃塵。東京有眼富不如，", "轔轔車聲輾冰玉，南郊壇上禮百神。西明寺後窮瞎張太祝，"]'),
('yuding-11','寄義興小女子','孟郊','唐','御定全唐诗','yuding','','[]','江南莊宅淺，所固唯疏籬。小女未解行，酒弟老更癡。',108,'御定全唐詩/json/378.json','["江南莊宅淺，所固唯疏籬。小女未解行，酒弟老更癡。", "家中多吳語，教爾遙可知。山怪夜動門，水妖時弄池。", "所憂癡酒腸，不解委曲辭。漁妾性崛強，耕童手皴厘。", "想茲為繈褓，如鳥拾柴枝。我詠元魯山，胸臆流甘滋。", "終當學自乳，起坐常相隨。"]'),
('yuding-12','憶江南弟','孟郊','唐','御定全唐诗','yuding','','[]','白首眼垂血，望爾唯夢中。筋力強起時，魂魄猶在東。',144,'御定全唐詩/json/378.json','["白首眼垂血，望爾唯夢中。筋力強起時，魂魄猶在東。", "眼光寄明星，起來東望空。望空不見人，江海波無窮。", "衰老無氣力，呼叫不成風。孑然憶憶言，落地何由通。", "常師共被教，竟作生離翁。生離不可訴，上天何曾聰。", "未忍對松柏，自鞭殘朽躬。自鞭亦何益，知教非所崇。", "努力拄杖來，餘活與爾同。不然死後恥，遺死亦有終。"]'),
('yuding-13','宿空侄院寄澹公','孟郊','唐','御定全唐诗','yuding','','[]','夜坐冷竹聲，二三高人語。燈窗看律鈔，小師別為侶。',72,'御定全唐詩/json/378.json','["夜坐冷竹聲，二三高人語。燈窗看律鈔，小師別為侶。", "雪簷晴滴滴，茗碗華舉舉。磬音多風飆，聲韻聞江楚。", "官街不相隔，詩思空愁予。明日策杖歸，去住兩延佇。"]'),
('yuding-14','寄陝府鄧給事','孟郊','唐','御定全唐诗','yuding','','[]','陝城臨大道，館宇屹幾鮮。候謁隨芳語，鏗詞芬蜀箋。',228,'御定全唐詩/json/378.json','["陝城臨大道，館宇屹幾鮮。候謁隨芳語，鏗詞芬蜀箋。", "從來鏡目下，見盡道心前。自謂古詩量，異將新學偏。", "戇人年六十，每月請三千。不敢等閒用，願為長壽錢。", "非關亦潔爾，將以救羸然。孤省癡皎皎，默吟寫綿綿。", "病書憑晝日，驛信寄宵鞭。疾訴將何諭，肆鱗今倒懸。", "塵鯉見枯浪，土鬣思幹泉。感感無緒蕩，愁愁作□邊。", "貞元文祭酒，比謹學韋玄。滿坐風無雜，當朝雅獨全。", "見知囑徐孺，賞句類陶淵。一顧生鴻羽，再言將鶴翩。", "宣揚隘車馬，君子湊駢闐。曾是此同眷，至今應賜憐。", "磨墨零落淚，楷字貢仁賢。"]'),
('yuding-15','送諫議十六叔至孝義渡後奉寄','孟郊','唐','御定全唐诗','yuding','','[]','曉渡明鏡中，霞衣相飄颻。浪鳧驚亦雙，蓬客將誰僚。',84,'御定全唐詩/json/378.json','["曉渡明鏡中，霞衣相飄颻。浪鳧驚亦雙，蓬客將誰僚。", "別飲孤易醒，離憂壯難銷。文清雖無敵，儒貴不敢驕。", "江吏捧紫泥，海旗剪紅蕉。分明太守禮，跨躡毗陵橋。", "伊洛去未回，遐矚空寂寥。"]'),
('yuding-16','至孝義渡寄鄭軍事唐二十五','孟郊','唐','御定全唐诗','yuding','','[]','咫尺不得見，心中空嗟嗟。官街泥水深，下腳道路斜。',72,'御定全唐詩/json/378.json','["咫尺不得見，心中空嗟嗟。官街泥水深，下腳道路斜。", "嵩少玉峻峻，伊雒碧華華。岸亭當四迥，詩老獨一家。", "洧叟何所如，鄭石唯有些。何當來說事，為君開流霞。"]'),
('yuding-17','答友人','孟郊','唐','御定全唐诗','yuding','','[]','白日照清水，淺深無隱姿。君子業高文，懷抱多正思。',120,'御定全唐詩/json/378.json','["白日照清水，淺深無隱姿。君子業高文，懷抱多正思。", "砥行碧山石，結交青松枝。碧山無轉易，青松難傾移。", "落落出俗韻，琅琅大雅詞。自非隨氏掌，明月安能持。", "千里不可倒，一返無近期。如何非意中，良覿忽在茲。", "道語必疏淡，儒風易淩遲。願存堅貞節，勿為霜霰欺。"]'),
('yuding-18','酬友人見寄新文','孟郊','唐','御定全唐诗','yuding','','[]','為客棲未定，況當玄月中。繁雲翳碧霄，落雪和清風。',96,'御定全唐詩/json/378.json','["為客棲未定，況當玄月中。繁雲翳碧霄，落雪和清風。", "郊陌絕行人，原隰多飛蓬。耕牛返村巷，野鳥依房櫳。", "我無饑凍憂，身托蓮花宮。安閒賴禪伯，複得疏塵蒙。", "覽君郢曲文，詞彩何沖融。謳吟不能已，頓覺形神空。"]'),
('yuding-19','答韓愈、李觀別，因獻張徐州','孟郊','唐','御定全唐诗','yuding','','[]','富別愁在顏，貧別愁銷骨。懶磨舊銅鏡，畏見新白髮。',180,'御定全唐詩/json/378.json','["富別愁在顏，貧別愁銷骨。懶磨舊銅鏡，畏見新白髮。", "古樹春無花，子規啼有血。離弦不堪聽，一聽四五絕。", "世途非一險，俗慮有千結。有客步大方，驅車獨迷轍。", "故人韓與李，逸翰雙皎潔。哀我摧折歸，贈詞縱橫設。", "徐方國東樞，元戎天下傑。禰生投刺游，王粲吟詩謁。", "高情無遺照，朗抱開曉月。有土不埋冤，有仇皆為雪。", "願為直草木，永向君地列。願為古琴瑟，永向君聽發。", "欲識丈夫心，曾將孤劍說。"]'),
('yuding-20','答晝上人止讒作','孟郊','唐','御定全唐诗','yuding','','[]','烈烈鸑鷟吟，鏗鏗琅玕音。梟摧明月嘯，鶴起清風心。',60,'御定全唐詩/json/378.json','["烈烈鸑鷟吟，鏗鏗琅玕音。梟摧明月嘯，鶴起清風心。", "渭水不可渾，涇流徒相侵。俗侶唱桃葉，隱士鳴桂琴。", "子野真遺卻，浮淺藏淵深。"]'),
('yuding-21','答姚怤見寄','孟郊','唐','御定全唐诗','yuding','','[]','日月不同光，晝夜各有宜。賢哲不苟合，出處亦待時。',84,'御定全唐詩/json/378.json','["日月不同光，晝夜各有宜。賢哲不苟合，出處亦待時。", "而我獨迷見，意求異士知。如將舞鶴管，誤向驚鳧吹。", "大雅難具陳，正聲易漂淪。君有丈夫淚，泣人不泣身。", "行吟楚山玉，義淚沾衣巾。"]'),
('yuding-22','答郭郎中','孟郊','唐','御定全唐诗','yuding','','[]','松柏死不變，千年色青青。志士貧更堅，守道無異營。',60,'御定全唐詩/json/378.json','["松柏死不變，千年色青青。志士貧更堅，守道無異營。", "每彈瀟湘瑟，獨抱風波聲。中有失意吟，知者淚滿纓。", "何以報知者，永存堅與貞。"]'),
('yuding-23','答盧虔故園見寄','孟郊','唐','御定全唐诗','yuding','','[]','訪舊無一人，獨歸清雒春。花聞哭聲死，水見別容新。',48,'御定全唐詩/json/378.json','["訪舊無一人，獨歸清雒春。花聞哭聲死，水見別容新。", "亂後故鄉宅，多為行路塵。因悲楚左右，謗玉不知瑉。"]'),
('yuding-24','汝墳蒙從弟楚材見贈，時郊將入秦，楚材適楚','孟郊','唐','御定全唐诗','yuding','','[]','朝為主人心，暮為行客吟。汝水忽淒咽，汝風流苦音。',60,'御定全唐詩/json/378.json','["朝為主人心，暮為行客吟。汝水忽淒咽，汝風流苦音。", "北闕秦門高，南路楚石深。分淚灑白日，離腸繞青岑。", "何以寄遠懷，黃鶴能相尋。"]'),
('yuding-25','同從叔簡酬盧殷少府','孟郊','唐','御定全唐诗','yuding','','[]','梅尉吟楚聲，竹風為淒清。深虛冰在性，高潔雲入情。',48,'御定全唐詩/json/378.json','["梅尉吟楚聲，竹風為淒清。深虛冰在性，高潔雲入情。", "借水洗閑貌，寄蕉書逸名。羞將片石文，鬥此雙瓊英。"]'),
('yuding-26','酬李侍禦書記秋夕雨中病假見寄','孟郊','唐','御定全唐诗','yuding','','[]','秋風繞衰柳，遠客聞雨聲。重茲阻良夕，孤坐唯積誠。',72,'御定全唐詩/json/378.json','["秋風繞衰柳，遠客聞雨聲。重茲阻良夕，孤坐唯積誠。", "果枉移疾詠，中含嘉慮明。洗滌煩濁盡，視聽昭曠生。", "未覺衾枕倦，久為章奏嬰。達人不寶藥，所保在閒情。"]'),
('yuding-27','答盧仝','孟郊','唐','御定全唐诗','yuding','','[]','楚屈入水死，詩孟踏雪僵。直氣苟有存，死亦何所妨。',204,'御定全唐詩/json/378.json','["楚屈入水死，詩孟踏雪僵。直氣苟有存，死亦何所妨。", "日劈高查牙，清棱含冰漿。前古後古冰，與山氣勢強。", "閃怪千石形，異狀安可量。有時春鏡破，百道聲飛揚。", "潛仙不足言，朗客無隱腸。為君傾海宇，日夕多文章。", "天下豈無緣，此山雪昂藏。煩君前致詞，哀我老更狂。", "狂歌不及狂，歌聲緣鳳凰。鳳兮何當來，消我孤直瘡。", "君文真鳳聲，宣隘滿鏗鏘。洛友零落盡，逮茲悲重傷。", "獨自奮異骨，將騎白角翔。再三勸莫行，寒氣有刀槍。", "仰慚君子多，慎勿作芬芳。"]'),
('yuding-28','奉報翰林張舍人見遺之詩','孟郊','唐','御定全唐诗','yuding','','[]','百蟲笑秋律，清削月夜聞。曉棱視聽微，風剪葉已紛。',264,'御定全唐詩/json/378.json','["百蟲笑秋律，清削月夜聞。曉棱視聽微，風剪葉已紛。", "君子鑒大雅，老人非俊群。收拾古所棄，俯仰補空文。", "孤韻恥春俗，餘響逸零雰。自然蹈終南，滌暑淩寒氛。", "岩霰不知午，澗澌鎮含曛。曾是醒古醉，所以多隱淪。", "江調樂之遠，溪謠生徒新。眾蘊有餘采，寒泉空哀呻。", "南謝竟莫至，北宋當時珍。賾靈各自異，酌酒誰能均。", "昔詠多寫諷，今詞詎無因。品松何高翠，宮殿沒荒榛。", "苔趾識宏制，沙潈遊崩津。忽吟陶淵明，此即羲皇人。", "心放出天地，形拘在風塵。前賢素行階，夙嗜青山勤。", "達士立明鏡，朗言為近臣。將期律萬有，傾倒甄無垠。", "鸑鷟應蟋蟀，絲毫意皆申。況于三千章，哀叩不為神。"]'),
('yuding-29','送從弟郢東歸','孟郊','唐','御定全唐诗','yuding','','[]','爾去東南夜，我無西北夢。誰言貧別易，貧別愁更重。',48,'御定全唐詩/json/378.json','["爾去東南夜，我無西北夢。誰言貧別易，貧別愁更重。", "曉色奪明月，征人逐群動。秋風楚濤高，旅榜將誰共。"]'),
('yuding-30','山中送從叔簡赴舉','孟郊','唐','御定全唐诗','yuding','','[]','石根百尺杉，山眼一片泉。倚之道氣高，飲之詩思鮮。',48,'御定全唐詩/json/378.json','["石根百尺杉，山眼一片泉。倚之道氣高，飲之詩思鮮。", "於此逍遙場，忽奏別離弦。卻笑薜蘿子，不同鳴躍年。"]'),
('yuding-31','送別崔寅亮下第','孟郊','唐','御定全唐诗','yuding','','[]','天地唯一氣，用之自偏頗。憂人成苦吟，達士為高歌。',84,'御定全唐詩/json/378.json','["天地唯一氣，用之自偏頗。憂人成苦吟，達士為高歌。", "君子識不淺，桂枝憂更多。歲晏期攀折，時歸且婆娑。", "素質如削玉，清詞若傾河。虯龍未化時，魚鱉同一波。", "去矣當自適，故鄉饒薜蘿。"]'),
('yuding-32','大樑送柳淳先入關','孟郊','唐','御定全唐诗','yuding','','[]','青山輾為塵，白日無閒人。自古推高車，爭利西入秦。',48,'御定全唐詩/json/378.json','["青山輾為塵，白日無閒人。自古推高車，爭利西入秦。", "王門與侯門，待富不待貧。空攜一束書，去去誰相親。"]'),
('yuding-33','送無懷道士游富春山水','孟郊','唐','御定全唐诗','yuding','','[]','造化絕高處，富春獨多觀。山濃翠滴灑，水折珠摧殘。',96,'御定全唐詩/json/378.json','["造化絕高處，富春獨多觀。山濃翠滴灑，水折珠摧殘。", "溪鏡不隱發，樹衣長遇寒。風猿虛空飛，月狖叫嘯酸。", "信此神仙路，豈為時俗安。煮金陰陽火，囚怪星宿壇。", "花發我未識，玉生忽叢攢。蓬萊浮蕩漾，非道相從難。"]'),
('yuding-34','送溫初下第','孟郊','唐','御定全唐诗','yuding','','[]','日落濁水中，夜光誰能分。高懷無近趣，清抱多遠聞。',48,'御定全唐詩/json/378.json','["日落濁水中，夜光誰能分。高懷無近趣，清抱多遠聞。", "欲識丈夫志，心藏孤嶽雲。長安風塵別，咫尺不見君。"]'),
('yuding-35','送盧虔端公守複州','孟郊','唐','御定全唐诗','yuding','','[]','師曠聽群木，自然識孤桐。正聲逢知音，願出大樸中。',96,'御定全唐詩/json/378.json','["師曠聽群木，自然識孤桐。正聲逢知音，願出大樸中。", "知音不韻俗，獨立占古風。忽掛觸邪冠，逮逐南飛鴻。", "肅肅太守章，明明華轂熊。商山無平路，楚水有驚潈。", "日月千裏外，光陰難載同。新愁徒自積，良會何由通。"]'),
('yuding-36','送任載、齊古二秀才自洞庭游宣城','孟郊','唐','御定全唐诗','yuding','','[]','洞庭非人境，道路行虛空。二客月中下，一帆天外風。',108,'御定全唐詩/json/378.json','["洞庭非人境，道路行虛空。二客月中下，一帆天外風。", "魚龍波五色，金碧樹千叢。閃怪如可懼，在誠無不通。", "扣奇知浩淼，采異訪穹崇。物表即高韻，人間訪仙公。", "宣城文雅地，謝守聲聞融。證玉易為力，辨瑉誰不同。", "從茲阮籍淚，且免泣途窮。"]'),
('yuding-37','送曉公歸庭山','孟郊','唐','御定全唐诗','yuding','','[]','庭山何崎嶇，寺路緣翠微。秋霽山盡出，日落人獨歸。',60,'御定全唐詩/json/378.json','["庭山何崎嶇，寺路緣翠微。秋霽山盡出，日落人獨歸。", "雲生高高步，泉灑田田衣。枯巢無還羽，新木有爭飛。", "茲焉不可繼，夢寐空清輝。"]'),
('yuding-38','送豆盧策歸別墅','孟郊','唐','御定全唐诗','yuding','','[]','短松鶴不巢，高石雲不棲。君今瀟湘去，意與雲鶴齊。',60,'御定全唐詩/json/378.json','["短松鶴不巢，高石雲不棲。君今瀟湘去，意與雲鶴齊。", "力買奇險地，手開清淺溪。身披薜荔衣，山陟莓苔梯。", "一卷冰雪文，避俗常自攜。"]'),
('yuding-39','送清遠上人歸楚山舊寺','孟郊','唐','御定全唐诗','yuding','','[]','波中出吳境，霞際登楚岑。山寺一別來，雲蘿三改陰。',48,'御定全唐詩/json/378.json','["波中出吳境，霞際登楚岑。山寺一別來，雲蘿三改陰。", "詩誇碧雲句，道證青蓮心。應笑泛萍者，不知松隱深。"]'),
('yuding-40','山中送從叔簡','孟郊','唐','御定全唐诗','yuding','','[]','莫以手中瓊，言邀世上名。莫以山中跡，久向人間行。',48,'御定全唐詩/json/378.json','["莫以手中瓊，言邀世上名。莫以山中跡，久向人間行。", "松柏有霜操，風泉無俗聲。應憐枯朽質，驚此別離情。"]'),
('yuding-41','送蕭煉師入四明山','孟郊','唐','御定全唐诗','yuding','','[]','閑於獨鶴心，大於高松年。迥出萬物表，高棲四明巔。',60,'御定全唐詩/json/378.json','["閑於獨鶴心，大於高松年。迥出萬物表，高棲四明巔。", "千尋直裂峰，百尺倒瀉泉。絳雪為我飯，白雲為我田。", "靜言不語俗，靈蹤時步天。"]'),
('yuding-0','感別送從叔校書簡再登科東歸','孟郊','唐','御定全唐诗','yuding','','[]','長安車馬道，高槐結浮陰。下有名利人，一人千萬心。',84,'御定全唐詩/json/379.json','["長安車馬道，高槐結浮陰。下有名利人，一人千萬心。", "黃鵠多遠勢，滄溟無近潯。怡怡靜退姿，泠泠思歸吟。", "菱唱忽生聽，芸書回望深。清風散言笑，餘花綴衣襟。", "獨恨魚鳥別，一飛將一沉。"]'),
('yuding-1','送玄亮師','孟郊','唐','御定全唐诗','yuding','','[]','蘭泉滌我襟，杉月棲我心。茗啜綠淨花，經誦清柔音。',36,'御定全唐詩/json/379.json','["蘭泉滌我襟，杉月棲我心。茗啜綠淨花，經誦清柔音。", "何處笑為別，淡情愁不侵。"]'),
('yuding-2','送李尊師玄','孟郊','唐','御定全唐诗','yuding','','[]','口誦碧簡文，身是青霞君。頭冠兩片月，肩披一條雲。',36,'御定全唐詩/json/379.json','["口誦碧簡文，身是青霞君。頭冠兩片月，肩披一條雲。", "松骨輕自飛，鶴心高不群。"]'),
('yuding-3','同晝上人送郭秀才江南尋兄弟','孟郊','唐','御定全唐诗','yuding','','[]','地上春色生，眼前詩彩明。手攜片寶月，言是高僧名。',48,'御定全唐詩/json/379.json','["地上春色生，眼前詩彩明。手攜片寶月，言是高僧名。", "溪轉萬曲心，水流千里聲。飛鳴向誰去，江鴻弟與兄。"]'),
('yuding-4','春日同韋郎中使君送鄒儒立少府扶侍赴雲陽','孟郊','唐','御定全唐诗','yuding','','[]','離思著百草，綿綿生無窮。側聞畿甸秀，三振詞策雄。',120,'御定全唐詩/json/379.json','["離思著百草，綿綿生無窮。側聞畿甸秀，三振詞策雄。", "太守不韻俗，諸生皆變風。郡齋敞西清，楚瑟驚南鴻。", "海畔帝城望，雲陽天色中。酒酣正芳景，詩綴新碧叢。", "服彩老萊並，侍車江革同。過隋柳憔悴，入洛花蒙籠。", "高步詎留足，前程在層空。獨慚病鶴羽，飛送力難崇。"]'),
('yuding-5','送從叔校書簡南歸','孟郊','唐','御定全唐诗','yuding','','[]','長安別離道，宛在東城隅。寒草根未死，愁人心已枯。',72,'御定全唐詩/json/379.json','["長安別離道，宛在東城隅。寒草根未死，愁人心已枯。", "促促水上景，遙遙天際途。生隨昏曉中，皆被日月驅。", "北騎達山嶽，南帆指江湖。高蹤一超越，千里在須臾。"]'),
('yuding-6','送韓愈從軍','孟郊','唐','御定全唐诗','yuding','','[]','志士感恩起，變衣非變性。親賓改舊觀，僮僕生新敬。',120,'御定全唐詩/json/379.json','["志士感恩起，變衣非變性。親賓改舊觀，僮僕生新敬。", "坐作群書吟，行為孤劍詠。始知出處心，不失平生正。", "淒淒天地秋，凜凜軍馬令。驛塵時一飛，物色極四靜。", "王師既不戰，廟略在無競。王粲有所依，元瑜初應命。", "一章喻檄明，百萬心氣定。今朝旌鼓前，笑別丈夫盛。"]'),
('yuding-7','同茅郎中使君送河南裴文學','孟郊','唐','御定全唐诗','yuding','','[]','河南有歸客，江風繞行襟。送君無塵聽，舞鶴清瑟音。',48,'御定全唐詩/json/379.json','["河南有歸客，江風繞行襟。送君無塵聽，舞鶴清瑟音。", "菱蔓綴楚棹，日華正嵩岑。如何謝文學，還起會雲吟。"]'),
('yuding-8','送李翱習之','孟郊','唐','御定全唐诗','yuding','','[]','習之勢翩翩，東南去遙遙。贈君雙履足，一為上皋橋。',144,'御定全唐詩/json/379.json','["習之勢翩翩，東南去遙遙。贈君雙履足，一為上皋橋。", "皋橋路逶迤，碧水清風飄。新秋折藕花，應對吳語嬌。", "千巷分淥波，四門生早潮。湖榜輕嫋嫋，酒旗高寥寥。", "小時屐齒痕，有處應未銷。舊憶如霧星，怳見於夢消。", "言之燒人心，事去不可招。獨孤宅前曲，箜篌醉中謠。", "壯年俱悠悠，逮茲各焦焦。執手複執手，唯道無枯凋。"]'),
('yuding-9','送丹霞子阮芳顏上人歸山','孟郊','唐','御定全唐诗','yuding','','[]','松色不肯秋，玉性不可柔。登山須正路，飲水須直流。',48,'御定全唐詩/json/379.json','["松色不肯秋，玉性不可柔。登山須正路，飲水須直流。", "倩鶴附書信，索雲作衣裘。仙村莫道遠，枉策招交遊。"]'),
('yuding-10','送從舅端適楚地','孟郊','唐','御定全唐诗','yuding','','[]','歸情似泛空，飄蕩楚波中。羽扇掃輕汗，布帆篩細風。',48,'御定全唐詩/json/379.json','["歸情似泛空，飄蕩楚波中。羽扇掃輕汗，布帆篩細風。", "江花折菡萏，岸影泊梧桐。元舅唱離別，賤生愁不窮。"]'),
('yuding-11','送盧汀侍禦歸天德幕','孟郊','唐','御定全唐诗','yuding','','[]','仲宣領騎射，結束皆少年。匹馬黃河岸，射雕清霜天。',72,'御定全唐詩/json/379.json','["仲宣領騎射，結束皆少年。匹馬黃河岸，射雕清霜天。", "旌旗防日北，道路上雲巔。古雪無銷鑠，新冰有堆填。", "清溪徒聳誚，白璧自招賢。豈比重恩者，閉門方獨全。"]'),
('yuding-12','送草書獻上人歸廬山','孟郊','唐','御定全唐诗','yuding','','[]','狂僧不為酒，狂筆自通天。將書雲霞片，直至清明巔。',85,'御定全唐詩/json/379.json','["狂僧不為酒，狂筆自通天。將書雲霞片，直至清明巔。", "手中飛黑電，象外瀉玄泉。萬物隨指顧，三光為迴旋。", "聚書雲霮zw，洗硯山晴鮮。忽怒畫蛇虺，噴然生風煙。", "江人願停筆，驚浪恐傾船。"]'),
('yuding-13','和薛先輩送獨孤秀才上都赴嘉會得青字','孟郊','唐','御定全唐诗','yuding','','[]','秦雲攀窈窕，楚桂搴芳馨。五色豈徒爾，萬枝皆有靈。',48,'御定全唐詩/json/379.json','["秦雲攀窈窕，楚桂搴芳馨。五色豈徒爾，萬枝皆有靈。", "仙謠天上貴，林詠雪中青。持此一為贈，送君翔杳冥。"]'),
('yuding-14','送崔爽之湖南','孟郊','唐','御定全唐诗','yuding','','[]','江與湖相通，二水洗高空。定知一日帆，使得千里風。',48,'御定全唐詩/json/379.json','["江與湖相通，二水洗高空。定知一日帆，使得千里風。", "雪唱與誰和，俗情多不通。何當逸翮縱，飛起泥沙中。"]'),
('yuding-15','送超上人歸天臺','孟郊','唐','御定全唐诗','yuding','','[]','天臺山最高，動躡赤城霞。何以靜雙目，掃山除妄花。',84,'御定全唐詩/json/379.json','["天臺山最高，動躡赤城霞。何以靜雙目，掃山除妄花。", "何以潔其性，濾泉去泥沙。靈境物皆直，萬松無一斜。", "月中見心近，雲外將俗賒。山獸護方丈，山猿捧袈裟。", "遺身獨得身，笑我牽名華。"]'),
('yuding-16','同李益、崔放送王煉師還樓觀，兼為群公先營山居','孟郊','唐','御定全唐诗','yuding','','[]','十年白雲士，一卷紫芝書。來結崆峒侶，還期縹緲居。',48,'御定全唐詩/json/379.json','["十年白雲士，一卷紫芝書。來結崆峒侶，還期縹緲居。", "霞冠遺彩翠，月帔上空虛。寄謝泉根水，清泠閑有餘。"]'),
('yuding-17','張徐州席送岑秀才','孟郊','唐','御定全唐诗','yuding','','[]','振振芝蘭步，升自君子堂。泠泠松桂吟，生自楚客腸。',84,'御定全唐詩/json/379.json','["振振芝蘭步，升自君子堂。泠泠松桂吟，生自楚客腸。", "羈鳥無定棲，驚蓬在他鄉。去茲門館閑，即彼道路長。", "雨餘山川淨，麥熟草木涼。楚淚滴章句，京塵染衣裳。", "贈君無餘佗，久要不可忘。"]'),
('yuding-18','送黃構擢第後歸江南','孟郊','唐','御定全唐诗','yuding','','[]','澹澹滄海氣，結成黃香才。幼齡思奮飛，弱冠遊靈台。',108,'御定全唐詩/json/379.json','["澹澹滄海氣，結成黃香才。幼齡思奮飛，弱冠遊靈台。", "一鶚顧喬木，眾禽不敢猜。一驥騁長衢，眾獸不敢陪。", "遂得會風雨，感通如雲雷。至矣小宗伯，確乎心不回。", "能令幽靜人，聲實喧九垓。卻憶江南道，祖筵花裏開。", "春風不能別，別罷空徘徊。"]'),
('yuding-19','送道士','孟郊','唐','御定全唐诗','yuding','','[]','千年山上行，山上無遺蹤。一日人間遊，六合人皆逢。',36,'御定全唐詩/json/379.json','["千年山上行，山上無遺蹤。一日人間遊，六合人皆逢。", "自有意中侶，白寒徒相從。"]'),
('yuding-20','送孟寂赴舉','孟郊','唐','御定全唐诗','yuding','','[]','烈士不憂身，為君吟苦辛。男兒久失意，寶劍亦生塵。',72,'御定全唐詩/json/379.json','["烈士不憂身，為君吟苦辛。男兒久失意，寶劍亦生塵。", "浮俗官是貴，君子道所珍。況當聖明主，豈乏證玉臣。", "濁水無白日，清流鑒蒼旻。賢愚皎然別，結交當有因。"]'),
('yuding-21','同溧陽宰送孫秀才','孟郊','唐','御定全唐诗','yuding','','[]','廢瑟難為弦，南風難為歌。幽幽拙疾中，忽忽浮夢多。',60,'御定全唐詩/json/379.json','["廢瑟難為弦，南風難為歌。幽幽拙疾中，忽忽浮夢多。", "清韻始嘯侶，雅言相與和。訟閑每往招，祖送奈若何。", "牽苦強為贈，邦邑光峨峨。"]'),
('yuding-22','溧陽唐興寺觀薔薇花，同諸公餞陳明府','孟郊','唐','御定全唐诗','yuding','','[]','忽驚紅琉璃，千豔萬豔開。佛火不燒物，淨香空徘徊。',48,'御定全唐詩/json/379.json','["忽驚紅琉璃，千豔萬豔開。佛火不燒物，淨香空徘徊。", "花下印文字，林間詠觴杯。群官餞宰官，此地車馬來。"]'),
('yuding-23','送柳淳','孟郊','唐','御定全唐诗','yuding','','[]','青山臨黃河，下有長安道。世上名利人，相逢不知老。',24,'御定全唐詩/json/379.json','["青山臨黃河，下有長安道。世上名利人，相逢不知老。"]'),
('yuding-24','送殷秀才南游','孟郊','唐','御定全唐诗','yuding','','[]','詩句臨離袂，酒花熏別顏。水程千裏外，岸泊幾宵間。',48,'御定全唐詩/json/379.json','["詩句臨離袂，酒花熏別顏。水程千裏外，岸泊幾宵間。", "風葉亂辭木，雪猿清叫山。南中多古事，詠遍始應還。"]'),
('yuding-25','送青陽上人游越','孟郊','唐','御定全唐诗','yuding','','[]','秋風吹白髮，微官自蕭索。江僧何用歎，溪縣饒寂寞。',60,'御定全唐詩/json/379.json','["秋風吹白髮，微官自蕭索。江僧何用歎，溪縣饒寂寞。", "楚思物皆清，越山勝非薄。時看鏡中月，獨向衣上落。", "多謝入冥鴻，笑予在籠鶴。"]'),
('yuding-26','奉同朝賢送新羅使','孟郊','唐','御定全唐诗','yuding','','[]','淼淼望遠國，一萍秋海中。恩傳日月外，夢在波濤東。',108,'御定全唐詩/json/379.json','["淼淼望遠國，一萍秋海中。恩傳日月外，夢在波濤東。", "浪興豁胸臆，泛程舟虛空。既茲吟仗信，亦以難私躬。", "實怪賞不足，異鮮悅多叢。安危所系重，征役誰能窮。", "彼俗媚文史，聖朝富才雄。送行數百首，各以鏗奇工。", "冗隸竊抽韻，孤屬思將同。"]'),
('yuding-27','留弟郢不得送之江南','孟郊','唐','御定全唐诗','yuding','','[]','剛有下水船，白日留不得。老人獨自歸，苦淚滿眼黑。',24,'御定全唐詩/json/379.json','["剛有下水船，白日留不得。老人獨自歸，苦淚滿眼黑。"]'),
('yuding-28','送陸暢歸湖州，因憑題故人皎然塔、陸羽墳','孟郊','唐','御定全唐诗','yuding','','[]','淼淼霅寺前，白蘋多清風。昔游詩會滿，今遊詩會空。',156,'御定全唐詩/json/379.json','["淼淼霅寺前，白蘋多清風。昔游詩會滿，今遊詩會空。", "孤吟玉淒惻，遠思景蒙籠。杼山磚塔禪，竟陵廣宵翁。", "饒彼草木聲，仿佛聞餘聰。因君寄數句，遍為書其叢。", "追吟當時說，來者實不窮。江調難再得，京塵徒滿躬。", "送君溪鴛鴦，彩色雙飛東。東多高靜鄉，芳宅冬亦崇。", "手自擷甘旨，供養歡沖融。待我遂前心，收拾使有終。", "不然洛岸亭，歸死為大同。"]'),
('yuding-29','送淡公','孟郊','唐','御定全唐诗','yuding','','[]','燕本冰雪骨，越淡蓮花風。五言雙寶刀，聯響高飛鴻。',528,'御定全唐詩/json/379.json','["燕本冰雪骨，越淡蓮花風。五言雙寶刀，聯響高飛鴻。", "翰苑錢舍人，詩韻鏗雷公。識本未識淡，仰詠嗟無窮。", "清恨生物表，郎玉傾夢中。常于冷竹坐，相語道意沖。", "嵩洛興不薄，稽江事難同。明年若不來，我作黃蒿翁。", "何以兀其心，為君學虛空。", "坐愛青草上，意含滄海濱。渺渺獨見水，悠悠不問人。", "鏡浪洗手綠，剡花入心春。雖然防外觸，無奈饒衣新。", "行當譯文字，慰此吟殷勤。", "銅鬥飲江酒，手拍銅鬥歌。儂是拍浪兒，飲則拜浪婆。", "腳踏小船頭，獨速舞短蓑。笑伊漁陽操，空恃文章多。", "閑倚青竹竿，白日奈我何。", "短蓑不怕雨，白鷺相爭飛。短楫畫菰蒲，鬥作豪橫歸。", "笑伊水健兒，浪戰求光輝。不如竹枝弓，射鴨無是非。", "射鴨複射鴨，鴨驚菰蒲頭。鴛鴦亦零落，彩色難相求。", "儂是清浪兒，每踏清浪遊。笑伊鄉貢郎，踏土稱風流。", "如何丱角翁，至死不裹頭。", "師得天文章，所以相知懷。數年伊雒同，一旦江湖乖。", "江湖有故莊，小女啼喈喈。我憂未相識，乳養難和諧。", "幸以片佛衣，誘之令看齋。齋中百福言，催促西歸來。", "伊洛氣味薄，江湖文章多。坐緣江湖岸，意識鮮明波。", "銅鬥短蓑行，新章其奈何。茲焉激切句，非是等閒歌。", "制之附驛回，勿使餘風訛。都城第一寺，昭成屹嵯峨。", "為師書廣壁，仰詠時經過。徘徊相思心，老淚雙滂沱。", "江南邑中寺，平地生勝山。開元吳語僧，律韻高且閑。"]'),
('yuding-30','送魏端公入朝','孟郊','唐','御定全唐诗','yuding','','[]','東洛尚淹玩，西京足芳妍。大賓威儀肅，上客冠劍鮮。',72,'御定全唐詩/json/379.json','["東洛尚淹玩，西京足芳妍。大賓威儀肅，上客冠劍鮮。", "豈惟空戀闕，亦以將朝天。局促塵末吏，幽老病中弦。", "徒懷青雲價，忽至白髮年。何當補風教，為薦三百篇。"]'),
('yuding-31','送盧郎中汀','孟郊','唐','御定全唐诗','yuding','','[]','洛水春渡闊，別離心悠悠。一生空吟詩，不覺成白頭。',108,'御定全唐詩/json/379.json','["洛水春渡闊，別離心悠悠。一生空吟詩，不覺成白頭。", "向事每計較，與山實綢繆。太華天上開，其下車轍流。", "縣街無塵土，過客多淹留。坐飲孤驛酒，行思獨山遊。", "逸關嵐氣明，照渭空漪浮。玉珂擺新歡，聲與鸞鳳儔。", "朝謁大家事，唯餘去無由。"]'),
('yuding-32','送鄭僕射出節山南','孟郊','唐','御定全唐诗','yuding','','[]','國老出為將，紅旗入青山。再招門下生，結束餘病孱。',96,'御定全唐詩/json/379.json','["國老出為將，紅旗入青山。再招門下生，結束餘病孱。", "自笑騎馬醜，強從驅馳間。顧顧磨天路，嫋嫋鏡下顏。", "文魄既飛越，宦情唯等閒。羨他白麵少，多是清朝班。", "惜命非所報，慎行誠獨艱。悠悠去住心，兩說何能刪。"]'),
('yuding-33','別妻家','孟郊','唐','御定全唐诗','yuding','','[]','芙蓉濕曉露，秋別南浦中。鴛鴦卷新贈，遙戀東床空。',72,'御定全唐詩/json/379.json','["芙蓉濕曉露，秋別南浦中。鴛鴦卷新贈，遙戀東床空。", "碧水不息浪，清溪易生風。參差坐成阻，飄颻去無窮。", "孤雲目雖斷，明月心相通。私情詎銷鑠，積芳在春叢。"]'),
('yuding-34','贈姚怤別','孟郊','唐','御定全唐诗','yuding','','[]','美人廢琴瑟，不是無巧彈。聞君郢中唱，始覺知音難。',60,'御定全唐詩/json/379.json','["美人廢琴瑟，不是無巧彈。聞君郢中唱，始覺知音難。", "驚蓬無還根，馳水多分瀾。倦客厭出門，疲馬思解鞍。", "何以寫此心，贈君握中丹。"]'),
('yuding-35','贈竟陵盧使君虔別','孟郊','唐','御定全唐诗','yuding','','[]','赤日千里火，火中行子心。孰不苦焦灼，所行為貧侵。',72,'御定全唐詩/json/379.json','["赤日千里火，火中行子心。孰不苦焦灼，所行為貧侵。", "山木豈無涼，猛獸蹲清陰。歸人憶平坦，別路多嶇嶔。", "賴得竟陵守，時聞建安吟。贈別折楚芳，楚芳搖衣襟。"]'),
('yuding-36','與韓愈、李翱、張籍話別','孟郊','唐','御定全唐诗','yuding','','[]','朱弦奏離別，華燈少光輝。物色豈有異，人心顧將違。',96,'御定全唐詩/json/379.json','["朱弦奏離別，華燈少光輝。物色豈有異，人心顧將違。", "客程殊未已，歲華忽然微。秋桐故葉下，寒露新雁飛。", "遠遊起重恨，送人念先歸。夜集類饑鳥，晨光失相依。", "馬跡繞川水，雁書還閨闈。常恐親朋阻，獨行知慮非。"]'),
('yuding-37','監察十五叔東齋招李益端公會別','孟郊','唐','御定全唐诗','yuding','','[]','欲知惜別離，瀉水還清池。此地有君子，芳蘭步葳蕤。',48,'御定全唐詩/json/379.json','["欲知惜別離，瀉水還清池。此地有君子，芳蘭步葳蕤。", "手掇雜英佩，意搖春夜思。莫作繞山雲，迴圈無定期。"]'),
('yuding-38','汴州留別韓愈','孟郊','唐','御定全唐诗','yuding','','[]','不飲濁水瀾，空滯此汴河。坐見繞岸水，盡為還海波。',72,'御定全唐詩/json/379.json','["不飲濁水瀾，空滯此汴河。坐見繞岸水，盡為還海波。", "四時不在家，弊服斷線多。遠客獨憔悴，春英落婆娑。", "汴水饒曲流，野桑無直柯。但為君子心，歎息終靡他。"]'),
('yuding-39','贈別殷山人說易後歸幽墅','孟郊','唐','御定全唐诗','yuding','','[]','夫子說天地，若與靈龜言。幽幽人不知，一一予所敦。',84,'御定全唐詩/json/379.json','["夫子說天地，若與靈龜言。幽幽人不知，一一予所敦。", "秋月吐白夜，涼風韻清源。旁通忽已遠，神感寂不喧。", "一悟袪萬結，夕懷傾朝煩。旅輈無停波，別馬嘶去轅。", "殷勤荒草士，會有知己論。"]'),
('yuding-40','壽安西渡奉別鄭相公','孟郊','唐','御定全唐诗','yuding','','[]','洛河向西道，石波橫磷磷。清風送君子，車遠無還塵。',288,'御定全唐詩/json/379.json','["洛河向西道，石波橫磷磷。清風送君子，車遠無還塵。", "春別亦蕭索，況茲冰霜晨。零落景易入，鬱抑抱難申。", "百宵華燈宴，一旦星散人。歲去弦吐箭，憂來蠶抽綸。", "綿綿無窮事，各各馳繞身。徘徊黃縹緲，倏忽春霜賓。", "相為物表物，永謝區中姻。日嗟來教士，仰望無由親。", "東都清風減，君子西歸朝。獨抱歲晏恨，泗吟不成謠。", "貴遊意多味，賤別情易消。回雁憶前叫，浪鳧念後漂。", "悠悠孤飛景，聳聳銜霜條。昧趣多滯澀，懶朋寡新僚。", "病深理方悟，悔至心自燒。寂靜道何在，憂勤學空饒。", "乃知減聞見，始遂情逍遙。文字徒營織，聲華諒疑驕。", "顧慚耕稼士，樸略氣韻調。善士有餘食，佳畦冬生苗。", "養人在養身，此旨清如韶。願貢高古言，敢望錫類招。"]'),
('yuding-0','宇文秀才齋中海柳詠','孟郊','唐','御定全唐诗','yuding','','[]','玉縷青葳蕤，結為芳樹姿。忽驚明月鉤，鉤出珊瑚枝。',60,'御定全唐詩/json/380.json','["玉縷青葳蕤，結為芳樹姿。忽驚明月鉤，鉤出珊瑚枝。", "灼灼不死花，濛濛長生絲。飲柏泛仙味，詠蘭擬古詞。", "霜風清颼颼，與君長相思。"]'),
('yuding-1','搖柳','孟郊','唐','御定全唐诗','yuding','','[]','弱弱本易驚，看看勢難定。因風似醉舞，盡日不能正。',36,'御定全唐詩/json/380.json','["弱弱本易驚，看看勢難定。因風似醉舞，盡日不能正。", "時邀詠花女，笑輟春妝鏡。"]'),
('yuding-2','曉鶴','孟郊','唐','御定全唐诗','yuding','','[]','曉鶴彈古舌，婆羅門叫音。應吹天上律，不使塵中尋。',72,'御定全唐詩/json/380.json','["曉鶴彈古舌，婆羅門叫音。應吹天上律，不使塵中尋。", "虛空夢皆斷，歆唏安能禁。如開孤月口，似說明星心。", "既非人間韻，枉作人間禽。不如相將去，碧落窠巢深。"]'),
('yuding-3','和薔薇花歌','孟郊','唐','御定全唐诗','yuding','','[]','仙機劄劄織鳳凰，花開七十有二行。天霞落地攢紅光，',24,'御定全唐詩/json/380.json','["仙機劄劄織鳳凰，花開七十有二行。天霞落地攢紅光，"]'),
('yuding-4','邀人賞薔薇','孟郊','唐','御定全唐诗','yuding','','[]','蜀色庶可比，楚叢亦應無。醉紅不自力，狂豔如索扶。',48,'御定全唐詩/json/380.json','["蜀色庶可比，楚叢亦應無。醉紅不自力，狂豔如索扶。", "麗蕊惜未掃，宛枝長更紆。何人是花侯，詩老強相呼。"]'),
('yuding-5','和宣州錢判官使院廳前石楠樹','孟郊','唐','御定全唐诗','yuding','','[]','大樸既一剖，眾材爭萬殊。懿茲南海華，來與北壤俱。',216,'御定全唐詩/json/380.json','["大樸既一剖，眾材爭萬殊。懿茲南海華，來與北壤俱。", "生長如自惜，雪霜無凋渝。籠籠抱靈秀，簇簇抽芳膚。", "寒日吐丹豔，赬子流細珠。鴛鴦花數重，翡翠葉四鋪。", "雨洗新妝色，一枝如一姝。聳異敷庭際，傾妍來坐隅。", "散彩飾機案，餘輝盈盤盂。高意因造化，常情逐榮枯。", "主公方寸中，陶植在須臾。養此奉君子，賞覿日為娛。", "始覺石楠詠，價傾賦兩都。棠頌庶可比，桂詞難以逾。", "因謝丘墟木，空采落泥塗。時來開佳姿，道去臥枯株。", "爭芳無由緣，受氣如鬱紆。抽肝在郢匠，歎息何踟躕。"]'),
('yuding-6','酬鄭毗躑躅詠','孟郊','唐','御定全唐诗','yuding','','[]','不似人手致，豈關地勢偏。孤光嫋餘翠，獨影舞多妍。',48,'御定全唐詩/json/380.json','["不似人手致，豈關地勢偏。孤光嫋餘翠，獨影舞多妍。", "迸火燒閑地，紅星墮青天。忽驚物表物，嘉客為留連。"]'),
('yuding-7','品松','孟郊','唐','御定全唐诗','yuding','','[]','追悲謝靈運，不得殊常封。縱然孔與顏，亦莫及此松。',144,'御定全唐詩/json/380.json','["追悲謝靈運，不得殊常封。縱然孔與顏，亦莫及此松。", "此松天格高，聳異千萬重。抓拏巨靈手，擘裂少室峰。", "擘裂風雨獰，抓拏指爪傭。道入難抱心，學生易墮蹤。", "時時數點仙，嫋嫋一線龍。霏微嵐浪際，遊戲顥興濃。", "品松徒高高，雌鳴詎嗈嗈。賞異尚可貴，賞潛誰能容。", "名華非典實，翦棄徒纖茸。刻削大雅文，所以不敢慵。"]'),
('yuding-8','答李員外小榼味','孟郊','唐','御定全唐诗','yuding','','[]','一拳芙蓉水，傾玉何泠泠。仙情夙已高，詩味今更馨。',48,'御定全唐詩/json/380.json','["一拳芙蓉水，傾玉何泠泠。仙情夙已高，詩味今更馨。", "試啜月入骨，再銜愁盡醒。荷君道古誠，使我善飛翎。"]'),
('yuding-9','井上枸杞架','孟郊','唐','御定全唐诗','yuding','','[]','深鎖銀泉甃，高葉架雲空。不與凡木並，自將仙蓋同。',60,'御定全唐詩/json/380.json','["深鎖銀泉甃，高葉架雲空。不與凡木並，自將仙蓋同。", "影疏千點月，聲細萬條風。迸子鄰溝外，飄香客位中。", "花杯承此飲，椿歲小無窮。"]'),
('yuding-10','蜘蛛諷','孟郊','唐','御定全唐诗','yuding','','[]','萬類皆有性，各各稟天和。蠶身與汝身，汝身何太訛。',72,'御定全唐詩/json/380.json','["萬類皆有性，各各稟天和。蠶身與汝身，汝身何太訛。", "蠶身不為己，汝身不為佗。蠶絲為衣裳，汝絲為網羅。", "濟物幾無功，害物日已多。百蟲雖切恨，其將奈爾何。"]'),
('yuding-11','蚊','孟郊','唐','御定全唐诗','yuding','','[]','五月中夜息，饑蚊尚營營。但將膏血求，豈覺性命輕。',48,'御定全唐詩/json/380.json','["五月中夜息，饑蚊尚營營。但將膏血求，豈覺性命輕。", "顧己寧自愧，飲人以偷生。願為天下幮，一使夜景清。"]'),
('yuding-12','燭蛾','孟郊','唐','御定全唐诗','yuding','','[]','燈前雙舞蛾，厭生何太切。想爾飛來心，惡明不惡滅。',36,'御定全唐詩/json/380.json','["燈前雙舞蛾，厭生何太切。想爾飛來心，惡明不惡滅。", "天若百尺高，應去掩明月。"]'),
('yuding-13','和錢侍郎甘露','孟郊','唐','御定全唐诗','yuding','','[]','玄天何以言，瑞露青松繁。忽見垂書跡，還驚湧澧源。',108,'御定全唐詩/json/380.json','["玄天何以言，瑞露青松繁。忽見垂書跡，還驚湧澧源。", "春枝晨嫋嫋，香味曉翻翻。子禮忽來獻，臣心固易敦。", "清風惜不動，薄霧肯蒙昏。嘉晝色更晶，仁慈久乃存。", "一方難獨佔，天下恐爭論。側聽飛中使，重榮華德門。", "從公樂萬壽，餘慶及兒孫。"]'),
('yuding-14','和令狐侍郎、郭郎中題項羽廟','孟郊','唐','御定全唐诗','yuding','','[]','碧草淩古廟，清塵鎖秋窗。當時獨宰割，猛志誰能降。',48,'御定全唐詩/json/380.json','["碧草淩古廟，清塵鎖秋窗。當時獨宰割，猛志誰能降。", "鼓氣雷作敵，劍光電為雙。新悲徒自起，舊恨空浮江。"]'),
('yuding-15','讀張碧集','孟郊','唐','御定全唐诗','yuding','','[]','天寶太白歿，六義已消歇。大哉國風本，喪而王澤竭。',72,'御定全唐詩/json/380.json','["天寶太白歿，六義已消歇。大哉國風本，喪而王澤竭。", "先生今複生，斯文信難缺。下筆證興亡，陳詞備風骨。", "高秋數奏琴，澄潭一輪月。誰作采詩官，忍之不揮發。"]'),
('yuding-16','聽琴','孟郊','唐','御定全唐诗','yuding','','[]','颯颯微雨收，翻翻橡葉鳴。月沉亂峰西，寥落三四星。',108,'御定全唐詩/json/380.json','["颯颯微雨收，翻翻橡葉鳴。月沉亂峰西，寥落三四星。", "前溪忽調琴，隔林寒琤琤。聞彈正弄聲，不敢枕上聽。", "回燭整頭簪，漱泉立中庭。定步屐齒深，貌禪目冥冥。", "微風吹衣襟，亦認宮征聲。學道三十年，未免憂死生。", "聞彈一夜中，會盡天地情。"]'),
('yuding-17','聞夜啼贈劉正元','孟郊','唐','御定全唐诗','yuding','','[]','寄泣須寄黃河泉，此中怨聲流徹天。',32,'御定全唐詩/json/380.json','["寄泣須寄黃河泉，此中怨聲流徹天。", "愁人獨有夜燈見，一紙鄉書淚滴穿。"]'),
('yuding-18','喜雨','孟郊','唐','御定全唐诗','yuding','','[]','朝見一片雲，暮成千里雨。淒清濕高枝，散漫沾荒土。',24,'御定全唐詩/json/380.json','["朝見一片雲，暮成千里雨。淒清濕高枝，散漫沾荒土。"]'),
('yuding-19','終南山下作','孟郊','唐','御定全唐诗','yuding','','[]','見此原野秀，始知造化偏。山村不假陰，流水自雨田。',48,'御定全唐詩/json/380.json','["見此原野秀，始知造化偏。山村不假陰，流水自雨田。", "家家梯碧峰，門門鎖青煙。因思蛻骨人，化作飛桂仙。"]'),
('yuding-20','觀種樹','孟郊','唐','御定全唐诗','yuding','','[]','種樹皆待春，春至難久留。君看朝夕花，誰免離別愁。',48,'御定全唐詩/json/380.json','["種樹皆待春，春至難久留。君看朝夕花，誰免離別愁。", "心意已零落，種之仍未休。胡為好奇者，無事自買憂。"]'),
('yuding-21','春雨後','孟郊','唐','御定全唐诗','yuding','','[]','昨夜一霎雨，天意蘇群物。何物最先知，虛庭草爭出。',24,'御定全唐詩/json/380.json','["昨夜一霎雨，天意蘇群物。何物最先知，虛庭草爭出。"]'),
('yuding-22','答友人贈炭','孟郊','唐','御定全唐诗','yuding','','[]','青山白屋有仁人，贈炭價重雙烏銀。驅卻坐上千重寒，',24,'御定全唐詩/json/380.json','["青山白屋有仁人，贈炭價重雙烏銀。驅卻坐上千重寒，"]'),
('yuding-23','爛柯石','孟郊','唐','御定全唐诗','yuding','','[]','仙界一日內，人間千載窮。雙棋未遍局，萬物皆為空。',48,'御定全唐詩/json/380.json','["仙界一日內，人間千載窮。雙棋未遍局，萬物皆為空。", "樵客返歸路，斧柯爛從風。唯餘石橋在，猶自淩丹虹。"]'),
('yuding-24','尋言上人','孟郊','唐','御定全唐诗','yuding','','[]','萬里莓苔地，不見驅馳蹤。唯開文字窗，時寫日月容。',48,'御定全唐詩/json/380.json','["萬里莓苔地，不見驅馳蹤。唯開文字窗，時寫日月容。", "竹韻漫蕭屑，草花徒蒙茸。披霜入眾木，獨自識青松。"]'),
('yuding-25','噴玉布','孟郊','唐','御定全唐诗','yuding','','[]','去塵咫尺步，山笑康樂岩。天開紫石屏，泉縷明月簾。',108,'御定全唐詩/json/380.json','["去塵咫尺步，山笑康樂岩。天開紫石屏，泉縷明月簾。", "仙凝刻削跡，靈綻雲霞纖。悅聞若有待，瞥見終無厭。", "俗玩詎能近，道嬉方可淹。踏著不死機，欲歸多浮嫌。", "古醉今忽醒，今求古仍潛。古今相共失，語默兩難恬。", "贈君噴玉布，一濯高嶄嶄。"]'),
('yuding-26','姑蔑城','孟郊','唐','御定全唐诗','yuding','','[]','勁越既成土，強吳亦為墟。皇風一已被，茲邑信平居。',48,'御定全唐詩/json/380.json','["勁越既成土，強吳亦為墟。皇風一已被，茲邑信平居。", "撫俗觀舊跡，行春布新書。興亡意何在，綿歎空躊躕。"]'),
('yuding-27','崢嶸嶺','孟郊','唐','御定全唐诗','yuding','','[]','疏鑿順高下，結構橫煙霞。坐嘯郡齋肅，玩奇石路斜。',48,'御定全唐詩/json/380.json','["疏鑿順高下，結構橫煙霞。坐嘯郡齋肅，玩奇石路斜。", "古樹浮綠氣，高門結朱華。始見崢嶸狀，仰止逾可嘉。"]'),
('yuding-28','尋裴處士','孟郊','唐','御定全唐诗','yuding','','[]','涉水更登陸，所向皆清真。寒草不藏徑，靈峰知有人。',72,'御定全唐詩/json/380.json','["涉水更登陸，所向皆清真。寒草不藏徑，靈峰知有人。", "悠哉煉金客，獨與煙霞親。曾是欲輕舉，誰言空隱淪。", "遠心寄白月，華髮回青春。對此欽勝事，胡為勞我身。"]'),
('yuding-29','子慶詩','孟郊','唐','御定全唐诗','yuding','','[]','王家事已奇，孟氏慶無涯。獻子還生子，羲之又有之。',72,'御定全唐詩/json/380.json','["王家事已奇，孟氏慶無涯。獻子還生子，羲之又有之。", "鳳兮且莫歎，鯉也會聞詩。小小豫章甲，纖纖玉樹姿。", "人來唯仰乳，母抱未知慈。我欲揀其養，放麛者是誰。"]'),
('yuding-30','憩淮上觀公法堂','孟郊','唐','御定全唐诗','yuding','','[]','動覺日月短，靜知時歲長。自悲道路人，暫宿空閒堂。',108,'御定全唐詩/json/380.json','["動覺日月短，靜知時歲長。自悲道路人，暫宿空閒堂。", "孤燭讓清晝，紗巾斂輝光。高僧積素行，事外無剛強。", "我有岩下桂，願為爐中香。不惜青翠姿，為君揚芬芳。", "淮水色不汙，汴流徒渾黃。且將琉璃意，淨綴芙蓉章。", "明日還獨行，羈愁來舊腸。"]'),
('yuding-31','江邑春霖奉贈陳侍禦','孟郊','唐','御定全唐诗','yuding','','[]','江上花木凍，雨中零落春。應由放忠直，在此成漂淪。',120,'御定全唐詩/json/380.json','["江上花木凍，雨中零落春。應由放忠直，在此成漂淪。", "嘉豔皆損汙，好音難殷勤。天涯多遠恨，雪涕盈芳辰。", "坐哭青草上，臥吟幽水濱。興言念風俗，得意唯波鱗。", "枕席病流濕，簷楹若飛津。始知吳楚水，不及京洛塵。", "風浦蕩歸棹，泥陂陷征輪。兩途日無遂，相贈唯沾巾。"]'),
('yuding-32','溧陽秋霽','孟郊','唐','御定全唐诗','yuding','','[]','晚雨曉猶在，蕭寥激前階。星星滿衰鬢，耿耿入秋懷。',72,'御定全唐詩/json/380.json','["晚雨曉猶在，蕭寥激前階。星星滿衰鬢，耿耿入秋懷。", "舊識半零落，前心驟相乖。飽泉亦恐醉，惕宦肅如齋。", "上客處華池，下寮宅枯崖。叩高占生物，齟齬回難諧。"]'),
('yuding-33','列仙文：方諸青童君','孟郊','唐','御定全唐诗','yuding','','[]','大霞霏晨暉，元氣無常形。玄轡飛霄外，八景乘高清。',60,'御定全唐詩/json/380.json','["大霞霏晨暉，元氣無常形。玄轡飛霄外，八景乘高清。", "手把玉皇袂，攜我晨中生。玄庭自嘉會，金書拆華名。", "賢女密所妍，相期洛水輧。"]'),
('yuding-34','列仙文：清虛真人','孟郊','唐','御定全唐诗','yuding','','[]','欻駕空清虛，徘徊西華館。瓊輪暨晨抄，虎騎逐煙散。',84,'御定全唐詩/json/380.json','["欻駕空清虛，徘徊西華館。瓊輪暨晨抄，虎騎逐煙散。", "惠風振丹旌，明燭朗八煥。解襟墉房內，神鈴鳴璀璨。", "棲景若林柯，九弦空中彈。遺我積世憂，釋此千載歎。", "怡眄無極已，終夜複待旦。"]'),
('yuding-35','列仙文：金母飛空歌','孟郊','唐','御定全唐诗','yuding','','[]','駕我八景輿，欻然入玉清。龍群拂霄上，虎旗攝朱兵。',108,'御定全唐詩/json/380.json','["駕我八景輿，欻然入玉清。龍群拂霄上，虎旗攝朱兵。", "逍遙三弦際，萬流無暫停。哀此去留會，劫盡天地傾。", "當尋無中景，不死亦不生。體彼自然道，寂觀合大冥。", "南嶽挺直幹，玉英曜穎精。有任靡期事，無心自虛靈。", "嘉會絳河內，相與樂朱英。"]'),
('yuding-36','列仙文：安度明','孟郊','唐','御定全唐诗','yuding','','[]','丹霞煥上清，八風鼓太和。回我神霄輦，遂造嶺玉阿。',84,'御定全唐詩/json/380.json','["丹霞煥上清，八風鼓太和。回我神霄輦，遂造嶺玉阿。", "咄嗟天地外，九圍皆我家。上采白日精，下飲黃月華。", "靈觀空無中，鵬路無間邪。顧見魏賢安，濁氣傷汝和。", "勤研玄中思，道成更相過。"]'),
('yuding-37','夏日謁智遠禪師','孟郊','唐','御定全唐诗','yuding','','[]','吾師當幾祖，說法雲無空。禪心三界外，宴坐天地中。',96,'御定全唐詩/json/380.json','["吾師當幾祖，說法雲無空。禪心三界外，宴坐天地中。", "院靜鬼神去，身與草木同。因知護王國，滿缽盛毒龍。", "抖擻塵埃衣，謁師見真宗。何必千萬劫，瞬息去樊籠。", "盛夏火為日，一堂十月風。不得為弟子，名姓掛儒宮。"]'),
('yuding-38','訪嵩陽道士不遇','孟郊','唐','御定全唐诗','yuding','','[]','先生五兵游，文焰藏金鼎。日下鶴過時，人間空落影。',48,'御定全唐詩/json/380.json','["先生五兵游，文焰藏金鼎。日下鶴過時，人間空落影。", "常言一粒藥，不墮生死境。何當列禦寇，去問仙人請。"]'),
('yuding-39','聽藍溪僧為元居士說維摩經','孟郊','唐','御定全唐诗','yuding','','[]','古樹少枝葉，真僧亦相依。山木自曲直，道人無是非。',60,'御定全唐詩/json/380.json','["古樹少枝葉，真僧亦相依。山木自曲直，道人無是非。", "手持維摩偈，心向居士歸。空景忽開霽，雪花猶在衣。", "洗然水溪晝，寒物生光輝。"]'),
('yuding-40','借車','孟郊','唐','御定全唐诗','yuding','','[]','借車載傢俱，傢俱少於車。借者莫彈指，貧窮何足嗟。',36,'御定全唐詩/json/380.json','["借車載傢俱，傢俱少於車。借者莫彈指，貧窮何足嗟。", "百年徒役走，萬事盡隨花。"]'),
('yuding-41','喜符郎詩有天縱','孟郊','唐','御定全唐诗','yuding','','[]','念符不由級，屹得文章階。白玉抽一毫，綠瑉已難排。',72,'御定全唐詩/json/380.json','["念符不由級，屹得文章階。白玉抽一毫，綠瑉已難排。", "偷筆作文章，乞墨潛磨揩。海鯨始生尾，試擺蓬壺渦。", "幸當禁止之，勿使恣狂懷。自悲無子嗟，喜妒雙喈喈。"]'),
('yuding-42','憑周況先輩于朝賢乞茶','孟郊','唐','御定全唐诗','yuding','','[]','道意勿乏味，心緒病無悰。蒙茗玉花盡，越甌荷葉空。',72,'御定全唐詩/json/380.json','["道意勿乏味，心緒病無悰。蒙茗玉花盡，越甌荷葉空。", "錦水有鮮色，蜀山饒芳叢。雲根才翦綠，印縫已霏紅。", "曾向貴人得，最將詩叟同。幸為乞寄來，救此病劣躬。"]'),
('yuding-43','上昭成閣不得，于從侄僧悟空院歎嗟','孟郊','唐','御定全唐诗','yuding','','[]','欲上千級閣，問天三四言。未尺數十登，心目風浪翻。',132,'御定全唐詩/json/380.json','["欲上千級閣，問天三四言。未尺數十登，心目風浪翻。", "手手把驚魄，腳腳踏墜魂。卻流至舊手，傍掣猶欲奔。", "老病但自悲，古蠹木萬痕。老力安可誇，秋海萍一根。", "孤叟何所歸，晝眼如黃昏。常恐失好步，入彼市井門。", "結僧為親情，策竹為子孫。此誠徒切切，此意空存存。", "一寸地上語，高天何由聞。"]'),
('yuding-44','魏博田興尚書聽嫂命不立非夫人詩','孟郊','唐','御定全唐诗','yuding','','[]','君子耽古禮，如饞魚吞鉤。昨聞敬嫂言，掣心東北流。',48,'御定全唐詩/json/380.json','["君子耽古禮，如饞魚吞鉤。昨聞敬嫂言，掣心東北流。", "魏博田尚書，與禮相綢繆。善詞聞天下，一日一再周。"]'),
('yuding-45','讀經','孟郊','唐','御定全唐诗','yuding','','[]','垂老抱佛腳，教妻讀黃經。經黃名小品，一紙千明星。',192,'御定全唐詩/json/380.json','["垂老抱佛腳，教妻讀黃經。經黃名小品，一紙千明星。", "曾讀大般若，細感肸蚃聽。當時把齋中，方寸抱萬靈。", "忽複入長安，蹴踏日月寧。老方卻歸來，收拾可丁丁。", "拂拭塵幾案，開函就孤亭。儒書難借索，僧簽饒芳馨。", "驛驛不開手，鏗鏗聞異鈴。得善如焚香，去惡如脫腥。", "安得顏子耳，曾未如此聽。聽之何有言，德教貴有形。", "何言中國外，有國如海萍。海萍國教異，天聲各泠泠。", "安排未定時，心火競熒熒。將如庶幾者，聲盡形元冥。"]'),
('yuding-46','謝李輈再到','孟郊','唐','御定全唐诗','yuding','','[]','等閒拜日晚，夫妻猶相瘡。況是賢人冤，何必哭飛揚。',108,'御定全唐詩/json/380.json','["等閒拜日晚，夫妻猶相瘡。況是賢人冤，何必哭飛揚。", "昨夜夢得劍，為君藏中腸。會將當風烹，血染布衣裳。", "勞君又叩門，詞句失尋常。我不忍出廳，血字濕土牆。", "血字耿不滅，我心懼惶惶。會有鏗鏘夫，見之目生光。", "生光非等閒，君其且安詳。"]'),
('yuding-47','忽不貧，喜盧仝書船歸洛','孟郊','唐','御定全唐诗','yuding','','[]','貧孟忽不貧，請問孟何如。盧仝歸洛船，崔嵬但載書。',192,'御定全唐詩/json/380.json','["貧孟忽不貧，請問孟何如。盧仝歸洛船，崔嵬但載書。", "江潮清翻翻，淮潮碧徐徐。夜信為朝信，朝信良卷舒。", "江淮君子水，相送仁有餘。我去官色衫，肩經入君廬。", "喃喃肩經郎，言語傾琪琚。琪琚鏗好詞，鳥鵲躍庭除。", "書船平安歸，喜報鄉里閭。我願拾遺柴，巢經於空虛。", "下免塵土侵，上為雲霞居。日月更相鎖，道義分明儲。", "不願空岧嶢，但願實工夫。實空二理微，分別相起予。", "經書荒蕪多，為君勉勉鋤。勉勉不敢專，傳之方在諸。"]'),
('yuding-0','吊國殤','孟郊','唐','御定全唐诗','yuding','','[]','徒言人最靈，白骨亂縱橫。如何當春死，不及群草生。',60,'御定全唐詩/json/381.json','["徒言人最靈，白骨亂縱橫。如何當春死，不及群草生。", "堯舜宰乾坤，器農不器兵。秦漢盜山嶽，鑄殺不鑄耕。", "天地莫生金，生金人競爭。"]'),
('yuding-1','吊比干墓','孟郊','唐','御定全唐诗','yuding','','[]','殷辛帝天下，厭為天下尊。幹剛既一斷，賢愚無二門。',96,'御定全唐詩/json/381.json','["殷辛帝天下，厭為天下尊。幹剛既一斷，賢愚無二門。", "佞是福身本，忠是喪己源。餓虎不食子，人無骨肉恩。", "日影不入地，下埋冤死魂。有骨不為土，應作直木根。", "今來過此鄉，下馬吊此墳。靜念君臣間，有道誰敢論。"]'),
('yuding-2','吊元魯山','孟郊','唐','御定全唐诗','yuding','','[]','搏鷙有餘飽，魯山長饑空。豪人飫鮮肥，魯山飯蒿蓬。',540,'御定全唐詩/json/381.json','["搏鷙有餘飽，魯山長饑空。豪人飫鮮肥，魯山飯蒿蓬。", "食名皆霸官，食力乃堯農。君子恥新態，魯山與古終。", "天璞本平一，人巧生異同。魯山不自剖，全璞竟沒躬。", "自剖多是非，流濫將何歸。奔競立詭節，淩侮爭怪輝。", "五常坐銷鑠，萬類隨衰微。以茲見魯山，道蹇無所依。", "君子不自蹇，魯山蹇有因。苟含天地秀，皆是天地身。", "天地蹇既甚，魯山道莫伸。天地氣不足，魯山食更貧。", "始知補元化，竟須得賢人。", "賢人多自霾，道理與俗乖。細功不敢言，遠韻方始諧。", "萬物飽為飽，萬人懷為懷。一聲苟失所，眾憾來相排。", "所以元魯山，饑衰難與偕。", "遠階無近級，造次不可升。賢人潔腸胃，寒日空澄凝。", "血誓竟訛謬，膏明易煎蒸。以之驅魯山，疏跡去莫乘。", "言從魯山宦，盡化堯時心。豺狼恥狂噬，齒牙閉霜金。", "競來辟田土，相與耕嶔岑。當宵無關鎖，竟歲饒歌吟。", "善教複天術，美詞非俗箴。精微自然事，視聽不可尋。", "因書魯山績，庶合簫韶音。", "簫韶太平樂，魯山不虛作。千古若有知，百年幸如昨。", "誰能嗣教化，以此洗浮薄。君臣貴深遇，天地有靈橐。", "力運既艱難，德符方合漠。名位苟虛曠，聲明自銷鑠。", "禮法雖相救，貞濃易糟粕。哀哀元魯山，畢竟誰能度。", "當今富教化，元後得賢相。冰心鏡衰古，霜議清遐障。", "幽埋盡洸洗，滯旅免流浪。唯餘魯山名，未獲旌廉讓。", "二三貞苦士，刷視聳危望。發秋青山夜，目斷丹闕亮。"]'),
('yuding-3','哭李觀','孟郊','唐','御定全唐诗','yuding','','[]','志士不得老，多為直氣傷。阮公終日哭，壽命固難長。',204,'御定全唐詩/json/381.json','["志士不得老，多為直氣傷。阮公終日哭，壽命固難長。", "顏子既殂謝，孔門無輝光。文星落奇曜，寶劍摧修鋩。", "常作金應石，忽為宮別商。為爾吊琴瑟，斷弦難再張。", "偏轂不可轉，只翼不可翔。清塵無吹噓，委地難飛揚。", "此義古所重，此風今則亡。自聞喪元賓，一日八九狂。", "沉痛此丈夫，驚呼彼穹蒼。我有出俗韻，勞君疾惡腸。", "知音既已矣，微言誰能彰。旅葬無高墳，栽松不成行。", "哀歌動寒日，贈淚沾晨霜。神理本窅窅，今來更茫茫。", "何以蕩悲懷，萬事付一觴。"]'),
('yuding-4','李少府廳吊李元賓遺字','孟郊','唐','御定全唐诗','yuding','','[]','零落三四字，忽成千萬年。那知冥寞客，不有補亡篇。',72,'御定全唐詩/json/381.json','["零落三四字，忽成千萬年。那知冥寞客，不有補亡篇。", "斜月吊空壁，旅人難獨眠。一生能幾時，百慮來相煎。", "戚戚故交淚，幽幽長夜泉。已矣難重言，一言一潸然。"]'),
('yuding-5','悼吳興湯衡評事','孟郊','唐','御定全唐诗','yuding','','[]','君生霅水清，君歿霅水渾。空令骨肉情，哭得白日昏。',72,'御定全唐詩/json/381.json','["君生霅水清，君歿霅水渾。空令骨肉情，哭得白日昏。", "大夜不復曉，古松長閉門。琴弦綠水絕，詩句青山存。", "昔為芳春顏，今為荒草根。獨問冥冥理，先儒未曾言。"]'),
('yuding-6','哀孟雲卿嵩陽荒居','孟郊','唐','御定全唐诗','yuding','','[]','戚戚抱幽獨，宴宴沉荒居。不聞新歡笑，但睹舊詩書。',108,'御定全唐詩/json/381.json','["戚戚抱幽獨，宴宴沉荒居。不聞新歡笑，但睹舊詩書。", "藝檗意彌苦，耕山食無餘。定交昔何在，至戚今或疏。", "薄俗易銷歇，淳風難久舒。秋蕪上空堂，寒槿落枯渠。", "薙草恐傷蕙，攝衣自理鋤。殘芳亦可餌，遺秀誰忍除。", "徘徊未能去，為爾涕漣如。"]'),
('yuding-7','哭盧貞國','孟郊','唐','御定全唐诗','yuding','','[]','一別難與期，存亡易寒燠。下馬入君門，聲悲不成哭。',60,'御定全唐詩/json/381.json','["一別難與期，存亡易寒燠。下馬入君門，聲悲不成哭。", "自能富才藝，當冀深榮祿。皇天負我賢，遺恨至兩目。", "平生歎無子，家家親相囑。"]'),
('yuding-8','傷舊游','孟郊','唐','御定全唐诗','yuding','','[]','去春會處今春歸，花數不減人數稀。',32,'御定全唐詩/json/381.json','["去春會處今春歸，花數不減人數稀。", "朝笑片時暮成泣，東風一向還西輝。"]'),
('yuding-9','吊房十五次卿少府','孟郊','唐','御定全唐诗','yuding','','[]','日高方得起，獨賞些些春。可惜宛轉鶯，好音與他人。',96,'御定全唐詩/json/381.json','["日高方得起，獨賞些些春。可惜宛轉鶯，好音與他人。", "昔年此氣味，還走曲江濱。逢著韓退之，結交方殷勤。", "蜀客骨目高，聰辯劍戟新。如何昨日歡，今日見無因。", "英奇一謝世，視聽一為塵。誰言老淚短，淚短沾衣巾。"]'),
('yuding-10','逢江南故晝上人會中鄭方回','孟郊','唐','御定全唐诗','yuding','','[]','相逢失意中，萬感因語至。追思東林日，掩抑北邙淚。',84,'御定全唐詩/json/381.json','["相逢失意中，萬感因語至。追思東林日，掩抑北邙淚。", "筐篋有遺文，江山舊清氣。塵生逍遙注，墨故飛動字。", "荒毀碧澗居，虛無青松位。珠沉百泉暗，月死群象閉。", "永謝平生言，知音豈容易。"]'),
('yuding-11','哭秘書包大監','孟郊','唐','御定全唐诗','yuding','','[]','哲人臥病日，賤子泣玉年。常恐寶鏡破，明月難再圓。',60,'御定全唐詩/json/381.json','["哲人臥病日，賤子泣玉年。常恐寶鏡破，明月難再圓。", "文字未改素，聲容忽歸玄。始知知音稀，千載一絕弦。", "舊館有遺琴，清風那複傳。"]'),
('yuding-12','悼幼子','孟郊','唐','御定全唐诗','yuding','','[]','一閉黃蒿門，不聞白日事。生氣散成風，枯骸化為地。',48,'御定全唐詩/json/381.json','["一閉黃蒿門，不聞白日事。生氣散成風，枯骸化為地。", "負我十年恩，欠爾千行淚。灑之北原上，不待秋風至。"]'),
('yuding-13','悼亡','孟郊','唐','御定全唐诗','yuding','','[]','山頭明月夜增輝，增輝不照重泉下。泉下雙龍無再期，',24,'御定全唐詩/json/381.json','["山頭明月夜增輝，增輝不照重泉下。泉下雙龍無再期，"]'),
('yuding-14','吊李元賓墳','孟郊','唐','御定全唐诗','yuding','','[]','曉上荒涼原，吊彼寂寥魂。眼咽此時淚，耳淒在日言。',36,'御定全唐詩/json/381.json','["曉上荒涼原，吊彼寂寥魂。眼咽此時淚，耳淒在日言。", "冥冥千萬年，墳鎖孤松根。"]'),
('yuding-15','覽崔爽遺文，因紓幽懷','孟郊','唐','御定全唐诗','yuding','','[]','墮淚數首文，悲結千里墳。蒼旻且留我，白日空遺君。',72,'御定全唐詩/json/381.json','["墮淚數首文，悲結千里墳。蒼旻且留我，白日空遺君。", "仙鶴未巢月，衰鳳先墜雲。清風獨起時，舊語如再聞。", "瑤草罷葳蕤，桂花休氛氳。萬物與我心，相感吳江濆。"]'),
('yuding-16','峽哀','孟郊','唐','御定全唐诗','yuding','','[]','昔多相與笑，今誰相與哀。峽哀哭幽魂，噭噭風吹來。',516,'御定全唐詩/json/381.json','["昔多相與笑，今誰相與哀。峽哀哭幽魂，噭噭風吹來。", "墮魄抱空月，出沒難自裁。齏粉一閃間，春濤百丈雷。", "峽水聲不平，碧沲牽清洄。沙棱箭箭急，波齒齗齗開。", "呀彼無底吮，待此不測災。谷號相噴激，石怒爭旋回。", "古醉有複鄉，今縲多為能。字孤徒仿佛，銜雪猶驚猜。", "薄俗少直腸，交結須橫財。黃金買相吊，幽泣無餘漼。", "我有古心意，為君空摧頹。", "上天下天水，出地入地舟。石劍相劈斫，石波怒蛟虯。", "花木疊宿春，風飆凝古秋。幽怪窟穴語，飛聞肸蚃流。", "沉哀日已深，銜訴將何求。", "三峽一線天，三峽萬繩泉。上仄碎日月，下掣狂漪漣。", "破魂一兩點，凝幽數百年。峽暉不停午，峽險多饑涎。", "樹根鎖枯棺，孤骨嫋嫋懸。樹枝哭霜棲，哀韻杳杳鮮。", "逐客零落腸，到此湯火煎。性命如紡績，道路隨索緣。", "奠淚吊波靈，波靈將閃然。", "峽亂鳴清磬，產石為鮮鱗。噴為腥雨涎，吹作黑井身。", "怪光閃眾異，餓劍唯待人。老腸未曾飽，古齒嶄岩嗔。", "嚼齒三峽泉，三峽聲齗齗。", "峽螭老解語，百丈潭底聞。毒波為計校，飲血養子孫。", "既非皋陶吏，空食沉獄魂。潛怪何幽幽，魄說徒云云。", "峽聽哀哭泉，峽吊鰥寡猿。峽聲非人聲，劍水相劈翻。", "斯誰士諸謝，奏此沉苦言。", "讒人峽虯心，渴罪呀然潯。所食無直腸，所語饒梟音。", "石齒嚼百泉，石風號千琴。幽哀莫能遠，分雪何由尋。"]'),
('yuding-17','杏殤','孟郊','唐','御定全唐诗','yuding','','[]','凍手莫弄珠，弄珠珠易飛。驚霜莫翦春，翦春無光輝。',444,'御定全唐詩/json/381.json','["凍手莫弄珠，弄珠珠易飛。驚霜莫翦春，翦春無光輝。", "零落小花乳，斕斑昔嬰衣。拾之不盈把，日暮空悲歸。", "地上空拾星，枝上不見花。哀哀孤老人，戚戚無子家。", "豈若沒水鳧，不如拾巢鴉。浪鷇破便飛，風雛嫋相誇。", "芳嬰不復生，向物空悲嗟。", "應是一線淚，入此春木心。枝枝不成花，片片落翦金。", "春壽何可長，霜哀亦已深。常時洗芳泉，此日洗淚襟。", "兒生月不明，兒死月始光。兒月兩相奪，兒命果不長。", "如何此英英，亦為吊蒼蒼。甘為墮地塵，不為末世芳。", "踏地恐土痛，損彼芳樹根。此誠天不知，翦棄我子孫。", "垂枝有千落，芳命無一存。誰謂生人家，春色不入門。", "冽冽霜殺春，枝枝疑纖刀。木心既零落，山竅空呼號。", "班班落地英，點點如明膏。始知天地間，萬物皆不牢。", "哭此不成春，淚痕三四斑。失芳蝶既狂，失子老亦孱。", "且無生生力，自有死死顏。靈鳳不銜訴，誰為扣天關。", "此兒自見災，花發多不諧。窮老收碎心，永夜抱破懷。", "聲死更何言，意死不必喈。病叟無子孫，獨立猶束柴。", "霜似敗紅芳，剪啄十數雙。參差呻細風，噞喁沸淺江。", "泣凝不可消，恨壯難自降。空遺舊日影，怨彼小書窗。"]'),
('yuding-18','吊江南老家人春梅','孟郊','唐','御定全唐诗','yuding','','[]','念爾筋力盡，違我衣食恩。奈何粗獷兒，生鞭見死痕。',48,'御定全唐詩/json/381.json','["念爾筋力盡，違我衣食恩。奈何粗獷兒，生鞭見死痕。", "舊使常以禮，新怨將誰吞。胡為乎泥中，消歇教義源。"]'),
('yuding-19','哭李丹員外，並寄杜中丞','孟郊','唐','御定全唐诗','yuding','','[]','生死方知交態存，忍將齰齖報幽魂。',32,'御定全唐詩/json/381.json','["生死方知交態存，忍將齰齖報幽魂。", "十年同在平原客，更遣何人哭寢門。"]'),
('yuding-20','哭劉言史','孟郊','唐','御定全唐诗','yuding','','[]','詩人業孤峭，餓死良已多。相悲與相笑，累累其奈何。',96,'御定全唐詩/json/381.json','["詩人業孤峭，餓死良已多。相悲與相笑，累累其奈何。", "精異劉言史，詩腸傾珠河。取次抱置之，飛過東溟波。", "可惜大國謠，飄為四夷歌。常於眾中會，顏色兩切磋。", "今日果成死，葬襄之洛河。洛岸遠相吊，灑淚雙滂沱。"]'),
('yuding-21','吊盧殷','孟郊','唐','御定全唐诗','yuding','','[]','詩人多清峭，餓死抱空山。白雲既無主，飛出意等閒。',552,'御定全唐詩/json/381.json','["詩人多清峭，餓死抱空山。白雲既無主，飛出意等閒。", "久病床席屍，護喪童僕孱。故書窮鼠齧，狼藉一室間。", "君歸新鬼鄉，我面古玉顏。羞見入地時，無人叫追攀。", "百泉空相吊，日久哀潺潺。", "唧唧複唧唧，千古一月色。新新複新新，千古一花春。", "邙風噫孟郊，嵩秋葬盧殷。北邙前後客，相吊為埃塵。", "北邙棘針草，淚根生苦辛。煙火不自暖，筋力早已貧。", "幽薦一杯泣，瀉之清洛濱。添為斷腸聲，愁殺長別人。", "棘針風相號，破碎諸苦哀。苦哀不可聞，掩耳亦入來。", "哭弦多煎聲，恨涕有餘摧。噫貧氣已焚，噫死心更灰。", "夢世浮閃閃，淚波深洄洄。薤歌一以去，蒿閉不復開。", "登封草木深，登封道路微。日月不與光，莓苔空生衣。", "可憐無子翁，蚍蜉緣病肌。攣臥歲時長，漣漣但幽噫。", "幽噫虎豹聞，此外相訪稀。至親唯有詩，抱心死有歸。", "河南韓先生，後君作因依。磨一片嵌岩，書千古光輝。", "賢人無計校，生苦死徒誇。他名潤子孫，君名潤泥沙。", "可惜千首文，閃如一朝花。零落難苦言，起坐空驚嗟。", "耳聞陋巷生，眼見魯山君。餓死始有名，餓名高氛氳。", "戇叟老壯氣，感之為憂雲。所憂唯一泣，古今相紛紛。", "平生與君說，逮此俱云云。", "初識漆鬢髮，爭為新文章。夜踏明月橋，店飲吾曹床。", "醉啜二杯釀，名鬱一縣香。寺中摘梅花，園裏翦浮芳。", "高嗜綠蔬羹，意輕肥膩羊。吟哦無滓韻，言語多古腸。", "白首忽然至，盛年如偷將。清濁俱莫追，何須罵滄浪。"]'),
('yuding-0','寄遠曲','張籍','唐','御定全唐诗','yuding','','[]','美人來去春江暖，江頭無人湘水滿。浣沙石上水禽棲，',24,'御定全唐詩/json/382.json','["美人來去春江暖，江頭無人湘水滿。浣沙石上水禽棲，"]'),
('yuding-1','行路難','張籍','唐','御定全唐诗','yuding','','[]','湘東行人長歎息，十年離家歸未得。弊裘羸馬苦難行，',40,'御定全唐詩/json/382.json','["湘東行人長歎息，十年離家歸未得。弊裘羸馬苦難行，", "龍蟠泥中未有雲，不能生彼升天翼。"]'),
('yuding-2','征婦怨','張籍','唐','御定全唐诗','yuding','','[]','九月匈奴殺邊將，漢軍全沒遼水上。萬里無人收白骨，',40,'御定全唐詩/json/382.json','["九月匈奴殺邊將，漢軍全沒遼水上。萬里無人收白骨，", "夫死戰場子在腹，妾身雖存如晝燭。"]'),
('yuding-3','白紵歌','張籍','唐','御定全唐诗','yuding','','[]','皎皎白紵白且鮮，將作春衣稱少年。裁縫長短不能定，',40,'御定全唐詩/json/382.json','["皎皎白紵白且鮮，將作春衣稱少年。裁縫長短不能定，", "衣裳著時寒食下，還把玉鞭鞭白馬。"]'),
('yuding-4','野老歌','張籍','唐','御定全唐诗','yuding','','[]','老農家貧在山住，耕種山田三四畝。苗疏稅多不得食，',40,'御定全唐詩/json/382.json','["老農家貧在山住，耕種山田三四畝。苗疏稅多不得食，", "西江賈客珠百斛，船中養犬長食肉。"]'),
('yuding-5','寄衣曲','張籍','唐','御定全唐诗','yuding','','[]','織素縫衣獨苦辛，遠因回使寄征人。官家亦自寄衣去，',40,'御定全唐詩/json/382.json','["織素縫衣獨苦辛，遠因回使寄征人。官家亦自寄衣去，", "殷勤為看初著時，征夫身上宜不宜。"]'),
('yuding-6','送遠曲','張籍','唐','御定全唐诗','yuding','','[]','戲馬台南山簇簇，山邊飲酒歌別曲。行人醉後起登車，',40,'御定全唐詩/json/382.json','["戲馬台南山簇簇，山邊飲酒歌別曲。行人醉後起登車，", "願君到處自題名，他日知君從此去。"]'),
('yuding-7','築城詞','張籍','唐','御定全唐诗','yuding','','[]','築城處，千人萬人齊把杵。重重土堅試行錐，',44,'御定全唐詩/json/382.json','["築城處，千人萬人齊把杵。重重土堅試行錐，", "力盡不得拋杵聲，杵聲未盡人皆死。家家養男當門戶，"]'),
('yuding-8','猛虎行','張籍','唐','御定全唐诗','yuding','','[]','南山北山樹冥冥，猛虎白日繞林行。向晚一身當道食，',48,'御定全唐詩/json/382.json','["南山北山樹冥冥，猛虎白日繞林行。向晚一身當道食，", "穀中近窟有山村，長向村家取黃犢。五陵年少不敢射，"]'),
('yuding-9','別離曲','張籍','唐','御定全唐诗','yuding','','[]','行人結束出門去，幾時更踏門前路。憶昔君初納采時，',48,'御定全唐詩/json/382.json','["行人結束出門去，幾時更踏門前路。憶昔君初納采時，", "男兒生身自有役，那得誤我少年時。不如逐君征戰死，"]'),
('yuding-10','牧童詞','張籍','唐','御定全唐诗','yuding','','[]','遠牧牛，繞村四面禾黍稠。陂中饑烏啄牛背，',44,'御定全唐詩/json/382.json','["遠牧牛，繞村四面禾黍稠。陂中饑烏啄牛背，", "隔堤吹葉應同伴，還鼓長鞭三四聲。牛牛食草莫相觸，"]'),
('yuding-11','沙堤行，呈裴相公','張籍','唐','御定全唐诗','yuding','','[]','長安大道沙為堤，早風無塵雨無泥。宮中玉漏下三刻，',48,'御定全唐詩/json/382.json','["長安大道沙為堤，早風無塵雨無泥。宮中玉漏下三刻，", "街官閭吏相傳呼，當前十裏惟空衢。白麻詔下移相印，"]'),
('yuding-12','求仙行','張籍','唐','御定全唐诗','yuding','','[]','漢皇欲作飛仙子，年年采藥東海裏。蓬萊無路海無邊，',48,'御定全唐詩/json/382.json','["漢皇欲作飛仙子，年年采藥東海裏。蓬萊無路海無邊，", "九皇真人終不下，空向離宮祠太乙。丹田有氣凝素華，"]'),
('yuding-13','古釵歎','張籍','唐','御定全唐诗','yuding','','[]','古釵墮井無顏色，百尺泥中今複得。鳳凰宛轉有古儀，',48,'御定全唐詩/json/382.json','["古釵墮井無顏色，百尺泥中今複得。鳳凰宛轉有古儀，", "蘭膏已盡股半折，雕文刻樣無年月。雖離井底入匣中，"]'),
('yuding-14','各東西','張籍','唐','御定全唐诗','yuding','','[]','遊人別，一東複一西。出門相背兩不返，惟信車輪與馬蹄。',66,'御定全唐詩/json/382.json','["遊人別，一東複一西。出門相背兩不返，惟信車輪與馬蹄。", "道路悠悠不知處，山高海闊誰辛苦。遠遊不定難寄書，", "我今與子非一身，安得死生不相棄。"]'),
('yuding-15','節婦吟，寄東平李司空師道','張籍','唐','御定全唐诗','yuding','','[]','君知妾有夫，贈妾雙明珠。感君纏綿意，系在紅羅襦。',48,'御定全唐詩/json/382.json','["君知妾有夫，贈妾雙明珠。感君纏綿意，系在紅羅襦。", "妾家高樓連苑起，良人執戟明光裏。知君用心如日月，"]'),
('yuding-16','宴客詞','張籍','唐','御定全唐诗','yuding','','[]','上客不用顧金羈，主人有酒君莫違。請君看取園中花，',48,'御定全唐詩/json/382.json','["上客不用顧金羈，主人有酒君莫違。請君看取園中花，", "人人齊醉起舞時，誰覺翻衣與倒幘。明朝花盡人已去，"]'),
('yuding-17','永嘉行','張籍','唐','御定全唐诗','yuding','','[]','黃頭鮮卑入洛陽，胡兒執戟升明堂。晉家天子作降虜，',48,'御定全唐詩/json/382.json','["黃頭鮮卑入洛陽，胡兒執戟升明堂。晉家天子作降虜，", "婦人出門隨亂兵，夫死眼前不敢哭。九州諸侯自顧土，"]'),
('yuding-18','採蓮曲','張籍','唐','御定全唐诗','yuding','','[]','秋江岸邊蓮子多，採蓮女兒憑船歌。青房圓實齊戢戢，',48,'御定全唐詩/json/382.json','["秋江岸邊蓮子多，採蓮女兒憑船歌。青房圓實齊戢戢，", "白練束腰袖半卷，不插玉釵妝梳淺。船中未滿度前洲，"]'),
('yuding-19','傷歌行','張籍','唐','御定全唐诗','yuding','','[]','黃門詔下促收捕，京兆尹系禦史府。出門無複部曲隨，',64,'御定全唐詩/json/382.json','["黃門詔下促收捕，京兆尹系禦史府。出門無複部曲隨，", "身著青衫騎惡馬，中門之外無送者。郵夫防吏急喧驅，", "高堂舞榭鎖管弦，美人遙望西南天。"]'),
('yuding-20','吳宮怨','張籍','唐','御定全唐诗','yuding','','[]','吳宮四面秋江水，江清露白芙蓉死。吳王醉後欲更衣，',64,'御定全唐詩/json/382.json','["吳宮四面秋江水，江清露白芙蓉死。吳王醉後欲更衣，", "君心與妾既不同，徒向君前作歌舞。茱萸滿宮紅實垂，", "白日在天光在地，君今那得長相棄。"]'),
('yuding-21','北邙行','張籍','唐','御定全唐诗','yuding','','[]','洛陽北門北邙道，喪車轔轔入秋草。車前齊唱薤露歌，',64,'御定全唐詩/json/382.json','["洛陽北門北邙道，喪車轔轔入秋草。車前齊唱薤露歌，", "千金立碑高百尺，終作誰家柱下石。山頭松柏半無主，", "人居朝市未解愁，請君暫向北邙遊。"]'),
('yuding-22','關山月','張籍','唐','御定全唐诗','yuding','','[]','秋月朗朗關山上，山中行人馬蹄響。關山秋來雨雪多，',64,'御定全唐詩/json/382.json','["秋月朗朗關山上，山中行人馬蹄響。關山秋來雨雪多，", "軍中探騎暮出城，伏兵暗處低旌戟。溪水連天霜草平，", "可憐萬國關山道，年年戰骨多秋草。"]'),
('yuding-23','隴頭行','張籍','唐','御定全唐诗','yuding','','[]','隴頭路斷人不行，胡騎夜入涼州城。漢兵處處格鬥死，',48,'御定全唐詩/json/382.json','["隴頭路斷人不行，胡騎夜入涼州城。漢兵處處格鬥死，", "去年中國養子孫，今著氈裘學胡語。誰能更使李輕車，"]'),
('yuding-24','楚妃歎','張籍','唐','御定全唐诗','yuding','','[]','湘雲初起江沉沉，君王遙在雲夢林。江南雨多旌旗暗，',48,'御定全唐詩/json/382.json','["湘雲初起江沉沉，君王遙在雲夢林。江南雨多旌旗暗，", "楚兵滿地能逐禽，誰用一身騁筋力。西江若翻雲夢中，"]'),
('yuding-25','春日行','張籍','唐','御定全唐诗','yuding','','[]','春日融融池上暖，竹牙出土蘭心短。草堂晨起酒半醒，',48,'御定全唐詩/json/382.json','["春日融融池上暖，竹牙出土蘭心短。草堂晨起酒半醒，", "樹樹殷勤盡繞行，攀枝未遍春日暝。不用積金著青天，"]'),
('yuding-26','秋夜長','張籍','唐','御定全唐诗','yuding','','[]','秋天如水夜未央，天漢東西月色光。愁人不寐畏枕席，',40,'御定全唐詩/json/382.json','["秋天如水夜未央，天漢東西月色光。愁人不寐畏枕席，", "白露滿田風嫋嫋，千聲萬聲鶡鳥鳴。"]'),
('yuding-27','白鼉鳴','張籍','唐','御定全唐诗','yuding','','[]','天欲雨，有東風，南溪白鼉鳴窟中。六月人家井無水，',24,'御定全唐詩/json/382.json','["天欲雨，有東風，南溪白鼉鳴窟中。六月人家井無水，"]'),
('yuding-28','洛陽行','張籍','唐','御定全唐诗','yuding','','[]','洛陽宮闕當中州，城上峨峨十二樓。翠華西去幾時返，',64,'御定全唐詩/json/382.json','["洛陽宮闕當中州，城上峨峨十二樓。翠華西去幾時返，", "六街朝暮鼓冬冬，禁兵持戟守空宮。百官月月拜章表，", "陌上老翁雙淚垂，共說武皇巡幸時。"]'),
('yuding-29','春江曲','張籍','唐','御定全唐诗','yuding','','[]','春江無雲潮水平，蒲心出水鳧雛鳴。長幹夫婿愛遠行，',48,'御定全唐詩/json/382.json','["春江無雲潮水平，蒲心出水鳧雛鳴。長幹夫婿愛遠行，", "春來未到父母家，舟小風多渡不得。欲辭舅姑先問人，"]'),
('yuding-30','送遠曲','張籍','唐','御定全唐诗','yuding','','[]','吳門向西流水長，水長柳暗煙茫茫。行人送客各惆悵，',64,'御定全唐詩/json/382.json','["吳門向西流水長，水長柳暗煙茫茫。行人送客各惆悵，", "行人告我掛帆去，此去何時返故鄉。殷勤振衣兩相囑，", "行人行處求知親，送君去去徒酸辛。"]'),
('yuding-31','塞下曲','張籍','唐','御定全唐诗','yuding','','[]','邊州八月修城堡，候騎先燒磧中草。胡風吹沙度隴飛，',48,'御定全唐詩/json/382.json','["邊州八月修城堡，候騎先燒磧中草。胡風吹沙度隴飛，", "天寒山路石斷裂，白日不銷帳上雪。烏孫國亂多降胡，"]'),
('yuding-32','董逃行','張籍','唐','御定全唐诗','yuding','','[]','洛陽城頭火曈曈，亂兵燒我天子宮。宮城南面有深山，',44,'御定全唐詩/json/382.json','["洛陽城頭火曈曈，亂兵燒我天子宮。宮城南面有深山，", "聞道官軍猶掠人，舊裏如今歸未得。董逃行，"]'),
('yuding-33','少年行','張籍','唐','御定全唐诗','yuding','','[]','少年從獵出長楊，禁中新拜羽林郎。獨對輦前射雙虎，',64,'御定全唐詩/json/382.json','["少年從獵出長楊，禁中新拜羽林郎。獨對輦前射雙虎，", "百里報仇夜出城，平明還在娼樓醉。遙聞虜到平陵下，", "不為六郡良家子，百戰始取邊城功。"]'),
('yuding-34','白頭吟','張籍','唐','御定全唐诗','yuding','','[]','請君膝上琴，彈我白頭吟。憶昔君前嬌笑語，',68,'御定全唐詩/json/382.json','["請君膝上琴，彈我白頭吟。憶昔君前嬌笑語，", "春天百草秋始衰，棄我不待白頭時。羅襦玉珥色未暗，", "人心回互自無窮，眼前好惡那能定。君恩已去若再返，"]'),
('yuding-35','將軍行','張籍','唐','御定全唐诗','yuding','','[]','彈箏峽東有胡塵，天子擇日拜將軍。蓬萊殿前賜六纛，',72,'御定全唐詩/json/382.json','["彈箏峽東有胡塵，天子擇日拜將軍。蓬萊殿前賜六纛，", "戰車彭彭旌旗動，三十六軍齊上隴。隴頭戰勝夜亦行，", "邊人親戚曾戰沒，今逐官軍收舊骨。磧西行見萬里空，"]'),
('yuding-36','賈客樂','張籍','唐','御定全唐诗','yuding','','[]','金陵向西賈客多，船中生長樂風波。欲發移船近江口，',72,'御定全唐詩/json/382.json','["金陵向西賈客多，船中生長樂風波。欲發移船近江口，", "金多眾中為上客，夜夜算緡眠獨遲。秋江初月猩猩語，", "年年逐利西複東，姓名不在縣籍中。農夫稅多長辛苦，"]'),
('yuding-37','羈旅行','張籍','唐','御定全唐诗','yuding','','[]','遠客出門行路難，停車斂策在門端。荒城無人霜滿路，',72,'御定全唐詩/json/382.json','["遠客出門行路難，停車斂策在門端。荒城無人霜滿路，", "行尋田頭暝未息，雙轂長轅礙荊棘。緣岡入澗投田家，", "舊山已別行已遠，身計未成難複返。長安陌上相識稀，"]'),
('yuding-38','車遙遙','張籍','唐','御定全唐诗','yuding','','[]','征人遙遙出古城，雙輪齊動駟馬鳴。山川無處不歸路，',64,'御定全唐詩/json/382.json','["征人遙遙出古城，雙輪齊動駟馬鳴。山川無處不歸路，", "驚麏遊兔在我傍，獨唱鄉歌對僮僕。君家大宅鳳城隅，", "門前舊轍久已平，無由複得君消息。"]'),
('yuding-39','妾薄命','張籍','唐','御定全唐诗','yuding','','[]','薄命婦，良家子，無事從軍去萬里。漢家天子平四夷，',48,'御定全唐詩/json/382.json','["薄命婦，良家子，無事從軍去萬里。漢家天子平四夷，", "與君一日為夫婦，千年萬歲亦相守。君愛龍城征戰功，"]'),
('yuding-40','朱鷺','張籍','唐','御定全唐诗','yuding','','[]','翩翩兮朱鷺，來泛春塘棲綠樹。羽毛如翦色如染，',38,'御定全唐詩/json/382.json','["翩翩兮朱鷺，來泛春塘棲綠樹。羽毛如翦色如染，", "誰知豪家網爾軀，不如飲啄江海隅。"]'),
('yuding-41','遠別離','張籍','唐','御定全唐诗','yuding','','[]','蓮葉團團杏花拆，長江鯉魚鬐鬣赤。念君少年棄親戚，',40,'御定全唐詩/json/382.json','["蓮葉團團杏花拆，長江鯉魚鬐鬣赤。念君少年棄親戚，", "幾時斷得城南陌，勿使居人有行役。"]'),
('yuding-42','楚宮行','張籍','唐','御定全唐诗','yuding','','[]','章華宮中九月時，桂花半落紅橘垂。江頭騎火照輦道，',72,'御定全唐詩/json/382.json','["章華宮中九月時，桂花半落紅橘垂。江頭騎火照輦道，", "千門萬戶開相當，燭籠左右列成行。下輦更衣入洞房，", "玉酒湛湛盈華觴，絲竹次第鳴中堂。巴姬起舞向君王，"]'),
('yuding-43','江南行','張籍','唐','御定全唐诗','yuding','','[]','江南人家多橘樹，吳姬舟上織白苧。土地卑濕饒蟲蛇，',64,'御定全唐詩/json/382.json','["江南人家多橘樹，吳姬舟上織白苧。土地卑濕饒蟲蛇，", "清莎覆城竹為屋，無井家家飲潮水。長幹午日沽春酒，", "江南風土歡樂多，悠悠處處盡經過。"]'),
('yuding-44','烏夜啼引','張籍','唐','御定全唐诗','yuding','','[]','秦烏啼啞啞，夜啼長安吏人家。吏人得罪囚在獄，',44,'御定全唐詩/json/382.json','["秦烏啼啞啞，夜啼長安吏人家。吏人得罪囚在獄，", "下床心喜不重寐，未明上堂賀舅姑。少婦語啼烏，"]'),
('yuding-45','促促詞','張籍','唐','御定全唐诗','yuding','','[]','促促複促促，家貧夫婦歡不足。今年為人送租船，',56,'御定全唐詩/json/382.json','["促促複促促，家貧夫婦歡不足。今年為人送租船，", "家家桑麻滿地黑，念君一身空努力。", "願教牛蹄團團羊角直，君身常在應不得。"]'),
('yuding-46','宛轉行','張籍','唐','御定全唐诗','yuding','','[]','華屋重翠幄，綺席雕象床。遠漏微更疏，薄衾中夜涼。',60,'御定全唐詩/json/382.json','["華屋重翠幄，綺席雕象床。遠漏微更疏，薄衾中夜涼。", "爐氣暗裴徊，寒燈背斜光。妍姿結宵態，寢臂幽夢長。", "宛轉複宛轉，憶君更未央。"]'),
('yuding-47','短歌行','張籍','唐','御定全唐诗','yuding','','[]','青天蕩蕩高且虛，上有白日無根株。流光暫出還入地，',40,'御定全唐詩/json/382.json','["青天蕩蕩高且虛，上有白日無根株。流光暫出還入地，", "玉卮盛酒置君前，再拜願君千萬年。"]'),
('yuding-48','山頭鹿','張籍','唐','御定全唐诗','yuding','','[]','山頭鹿，角芟芟，尾促促。貧兒多租輸不足，',36,'御定全唐詩/json/382.json','["山頭鹿，角芟芟，尾促促。貧兒多租輸不足，", "縣家唯憂少軍食，誰能令爾無死傷。"]'),
('yuding-49','湘江曲','張籍','唐','御定全唐诗','yuding','','[]','湘水無潮秋水闊，湘中月落行人發。送人發，送人歸，',24,'御定全唐詩/json/382.json','["湘水無潮秋水闊，湘中月落行人發。送人發，送人歸，"]'),
('yuding-50','楚妃怨','張籍','唐','御定全唐诗','yuding','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'御定全唐詩/json/382.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀瓶秋水冷。"]'),
('yuding-51','離宮怨','張籍','唐','御定全唐诗','yuding','','[]','高堂別館連湘渚，長向春光開萬戶。',32,'御定全唐詩/json/382.json','["高堂別館連湘渚，長向春光開萬戶。", "荊王去去不復來，宮中美人自歌舞。"]'),
('yuding-52','成都曲','張籍','唐','御定全唐诗','yuding','','[]','錦江近西煙水綠，新雨山頭荔枝熟。',32,'御定全唐詩/json/382.json','["錦江近西煙水綠，新雨山頭荔枝熟。", "萬里橋邊多酒家，遊人愛向誰家宿。"]'),
('yuding-53','寒塘曲','張籍','唐','御定全唐诗','yuding','','[]','寒塘沉沉柳葉疏，水暗人語驚棲鳧。',32,'御定全唐詩/json/382.json','["寒塘沉沉柳葉疏，水暗人語驚棲鳧。", "舟中少年醉不起，持燭照水射遊魚。"]'),
('yuding-54','春別曲','張籍','唐','御定全唐诗','yuding','','[]','長江春水綠堪染，蓮葉出水大如錢。',32,'御定全唐詩/json/382.json','["長江春水綠堪染，蓮葉出水大如錢。", "江頭橘樹君自種，那不長系木蘭船。"]'),
('yuding-55','春堤曲','張籍','唐','御定全唐诗','yuding','','[]','野塘鵁鶄飛樹頭，綠蒲紫菱蓋碧流。',32,'御定全唐詩/json/382.json','["野塘鵁鶄飛樹頭，綠蒲紫菱蓋碧流。", "狂客誰家愛雲水，日日獨來城下游。"]'),
('yuding-56','烏棲曲','張籍','唐','御定全唐诗','yuding','','[]','西山作宮潮滿池，宮鳥曉鳴茱萸枝。',32,'御定全唐詩/json/382.json','["西山作宮潮滿池，宮鳥曉鳴茱萸枝。", "吳姬採蓮自唱曲，君王昨夜舟中宿。"]'),
('yuding-57','雀飛多','張籍','唐','御定全唐诗','yuding','','[]','雀飛多，觸網羅，網羅高樹顛。汝飛蓬蒿下，',20,'御定全唐詩/json/382.json','["雀飛多，觸網羅，網羅高樹顛。汝飛蓬蒿下，"]'),
('yuding-58','泗水行','張籍','唐','御定全唐诗','yuding','','[]','泗水流急石纂纂，鯉魚上下紅尾短。春冰銷散日華滿，',24,'御定全唐詩/json/382.json','["泗水流急石纂纂，鯉魚上下紅尾短。春冰銷散日華滿，"]'),
('yuding-59','廢居行','張籍','唐','御定全唐诗','yuding','','[]','胡馬崩騰滿阡陌，都人避亂唯空宅。宅邊青桑垂宛宛，',48,'御定全唐詩/json/382.json','["胡馬崩騰滿阡陌，都人避亂唯空宅。宅邊青桑垂宛宛，", "去時禾黍埋地中，饑兵掘土翻重重。鴟梟養子庭樹上，"]'),
('yuding-60','寄菖蒲','張籍','唐','御定全唐诗','yuding','','[]','石上生菖蒲，一寸十二節。仙人勸我食，令我頭青面如雪。',50,'御定全唐詩/json/382.json','["石上生菖蒲，一寸十二節。仙人勸我食，令我頭青面如雪。", "逢人寄君一絳囊，書中不得傳此方。君能來作棲霞侶，"]'),
('yuding-61','江村行','張籍','唐','御定全唐诗','yuding','','[]','南塘水深蘆筍齊，下田種稻不作畦。耕場磷磷在水底，',64,'御定全唐詩/json/382.json','["南塘水深蘆筍齊，下田種稻不作畦。耕場磷磷在水底，", "水淹手足盡有瘡，山虻繞身飛颺颺。桑林椹黑蠶再眠，", "一年耕種長苦辛，田熟家家將賽神。"]'),
('yuding-62','樵客吟','張籍','唐','御定全唐诗','yuding','','[]','上山采樵選枯樹，深處樵多出辛苦。秋來野火燒櫟林，',74,'御定全唐詩/json/382.json','["上山采樵選枯樹，深處樵多出辛苦。秋來野火燒櫟林，", "日西待伴同下山，竹擔彎彎向身曲。共知路傍多虎窟，", "采樵客，莫采松與柏。松柏生枝直且堅，與君作屋成家宅。"]'),
('yuding-63','湖南曲','張籍','唐','御定全唐诗','yuding','','[]','瀟湘多別離，風起芙蓉洲。江上人已遠，夕陽滿中流。',36,'御定全唐詩/json/382.json','["瀟湘多別離，風起芙蓉洲。江上人已遠，夕陽滿中流。", "鴛鴦東南飛，飛上青山頭。"]'),
('yuding-64','春水曲','張籍','唐','御定全唐诗','yuding','','[]','鴨鴨，觜唼唼。青蒲生，春水狹。蕩漾木蘭船，',21,'御定全唐詩/json/382.json','["鴨鴨，觜唼唼。青蒲生，春水狹。蕩漾木蘭船，"]'),
('yuding-65','雲童行','張籍','唐','御定全唐诗','yuding','','[]','雲童童，白龍之尾垂江中。今年天旱不作雨，',20,'御定全唐詩/json/382.json','["雲童童，白龍之尾垂江中。今年天旱不作雨，"]'),
('yuding-66','新桃行','張籍','唐','御定全唐诗','yuding','','[]','桃生葉婆娑，枝葉四向多。高未出牆顛，蒿莧相淩摩。',96,'御定全唐詩/json/382.json','["桃生葉婆娑，枝葉四向多。高未出牆顛，蒿莧相淩摩。", "植之三年餘，今年初試花。秋來已成實，其陰良已嘉。", "青蟬不來鳴，安得迅羽過。常惡牽絲蟲，蒙冪成網羅。", "顧托戲兒童，勿折吾柔柯。明年結其實，磊磊充汝家。"]'),
('yuding-67','憶遠曲','張籍','唐','御定全唐诗','yuding','','[]','水上山沉沉，征途複繞林。途荒人行少，馬跡猶可尋。',48,'御定全唐詩/json/382.json','["水上山沉沉，征途複繞林。途荒人行少，馬跡猶可尋。", "雪中獨立樹，海口失侶禽。離憂如長線，千里縈我心。"]'),
('yuding-68','長塘湖','張籍','唐','御定全唐诗','yuding','','[]','長塘湖，一斛水中半斛魚。大魚如柳葉，小魚如針鋒，',24,'御定全唐詩/json/382.json','["長塘湖，一斛水中半斛魚。大魚如柳葉，小魚如針鋒，"]'),
('yuding-69','廢瑟詞','張籍','唐','御定全唐诗','yuding','','[]','古瑟在匣誰複識，玉柱顛倒朱絲黑。千年曲譜不分明，',40,'御定全唐詩/json/382.json','["古瑟在匣誰複識，玉柱顛倒朱絲黑。千年曲譜不分明，", "幾時天下復古樂，此瑟還奏雲門曲。"]'),
('yuding-0','野居','張籍','唐','御定全唐诗','yuding','','[]','貧賤易為適，荒郊亦安居。端坐無餘思，彌樂古人書。',96,'御定全唐詩/json/383.json','["貧賤易為適，荒郊亦安居。端坐無餘思，彌樂古人書。", "秋田多良苗，野水多遊魚。我無耒與網，安得充廩廚。", "寒天白日短，簷下暖我軀。四肢暫寬柔，中腸郁不舒。", "多病減志氣，為客足憂虞。況複苦時節，覽景獨踟躕。"]'),
('yuding-1','西州','張籍','唐','御定全唐诗','yuding','','[]','羌胡據西州，近甸無邊城。山東收稅租，養我防塞兵。',108,'御定全唐詩/json/383.json','["羌胡據西州，近甸無邊城。山東收稅租，養我防塞兵。", "胡騎來無時，居人常震驚。嗟我五陵間，農者罷耘耕。", "邊頭多殺傷，士卒難全形。郡縣發丁役，丈夫各征行。", "生男不能養，懼身有姓名。良馬不念秣，烈士不苟營。", "所願除國難，再逢天下平。"]'),
('yuding-2','雜怨','張籍','唐','御定全唐诗','yuding','','[]','切切重切切，秋風桂枝折。人當少年嫁，我當少年別。',60,'御定全唐詩/json/383.json','["切切重切切，秋風桂枝折。人當少年嫁，我當少年別。", "念君非征行，年年長遠途。妾身甘獨歿，高堂有舅姑。", "山川豈遙遠，行人自不返。"]'),
('yuding-3','惜花','張籍','唐','御定全唐诗','yuding','','[]','春潭足芳樹，水清不如素。幽人愛華景，一一空山暮。',48,'御定全唐詩/json/383.json','["春潭足芳樹，水清不如素。幽人愛華景，一一空山暮。", "月出潭氣白，遊魚暗沖石。夜深春思多，酒醒山寂寂。"]'),
('yuding-4','三原李氏園宴集','張籍','唐','御定全唐诗','yuding','','[]','暮春天早熱，邑居苦囂煩。言從君子樂，樂彼李氏園。',120,'御定全唐詩/json/383.json','["暮春天早熱，邑居苦囂煩。言從君子樂，樂彼李氏園。", "園中有草堂，池引涇水泉。開戶西北望，遠見嵯峨山。", "借問主人翁，北州佐戎軒。僕夫守舊宅，為客侍華筵。", "高懷有餘興，竹樹芳且鮮。傾我所持觴，盡日共留連。", "疏拙不偶俗，常喜形體閑。況來幽棲地，能不重歎言。"]'),
('yuding-5','沈千運舊居','張籍','唐','御定全唐诗','yuding','','[]','汝北君子宅，我來見頹墉。亂離子孫盡，地屬鄰里翁。',132,'御定全唐詩/json/383.json','["汝北君子宅，我來見頹墉。亂離子孫盡，地屬鄰里翁。", "土木被丘墟，溪路不連通。舊井蔓草合，牛羊墜其中。", "君辭天子書，放意任體躬。一生不自力，家與逆旅同。", "高議切星辰，餘聲激喑聾。方將旌舊閭，百世可封崇。", "嗟其未積年，已為荒林叢。時豈無知音，不能崇此風。", "浩蕩竟無睹，我將安所從。"]'),
('yuding-6','贈別孟郊','張籍','唐','御定全唐诗','yuding','','[]','歷歷天上星，沉沉水中萍。幸當清秋夜，流影及微形。',120,'御定全唐詩/json/383.json','["歷歷天上星，沉沉水中萍。幸當清秋夜，流影及微形。", "君生衰俗間，立身如禮經。純誠發新文，獨有金石聲。", "才名振京國，歸省東南行。停車楚城下，顧我不念程。", "寶鏡曾墜水，不磨豈自明。苦節居貧賤，所知賴友生。", "歡會方別離，戚戚憂慮並。安得在一方，終老無送迎。"]'),
('yuding-7','臥疾','張籍','唐','御定全唐诗','yuding','','[]','身病多思慮，亦讀神農經。空堂留燈燭，四壁青熒熒。',120,'御定全唐詩/json/383.json','["身病多思慮，亦讀神農經。空堂留燈燭，四壁青熒熒。", "羈旅隨人歡，貧賤還自輕。今來問良醫，乃知病所生。", "僮僕各憂愁，杵臼無停聲。見我形憔悴，勸藥語丁寧。", "春雨枕席冷，窗前新禽鳴。開門起無力，遙愛雞犬行。", "服藥察耳目，漸如醉者醒。顧非達性命，猶為憂患生。"]'),
('yuding-8','別段生','張籍','唐','御定全唐诗','yuding','','[]','與子骨肉親，願言長相隨。況離父母傍，從我學書詩。',144,'御定全唐詩/json/383.json','["與子骨肉親，願言長相隨。況離父母傍，從我學書詩。", "同在道路間，講論亦未虧。為文於我前，日夕生光儀。", "行役多疾疚，賴此相扶持。貧賤事難拘，今日有別離。", "我去秦城中，子留汴水湄。離情兩飄斷，不異風中絲。", "幼年獨為客，舉動難得宜。努力自修勵，常如見我時。", "送我登山岡，再拜問還期。還期在新年，勿怨歡會遲。"]'),
('yuding-9','哭于鵠','張籍','唐','御定全唐诗','yuding','','[]','青山無逸人，忽覺大國貧。良玉沉幽泉，名為天下珍。',120,'御定全唐詩/json/383.json','["青山無逸人，忽覺大國貧。良玉沉幽泉，名為天下珍。", "野性疏時俗，再拜乃從軍。氣高終不合，去如鏡上塵。", "我初有章句，相合者唯君。今來吊嗣子，對隴燒新文。", "耕者廢其耜，爨者絕其薪。苟無新衣裳，曷用光我身。", "奠酒徒拜手，哀懷安能陳。徒保金石韻，千載人所聞。"]'),
('yuding-10','南歸','張籍','唐','御定全唐诗','yuding','','[]','促促念道路，四支不常寧。行車未及家，天外非盡程。',120,'御定全唐詩/json/383.json','["促促念道路，四支不常寧。行車未及家，天外非盡程。", "骨肉待我歡，鄉里望我榮。豈知東與西，憔悴竟無成。", "人言苦夜長，窮者不念明。懼離其寢寐，百憂傷性靈。", "世道多險薄，相勸畢中誠。遠遊無知音，不如商賈行。", "達人有常志，愚夫勞所營。舊山行去遠，言歸樂此生。"]'),
('yuding-11','惜花','張籍','唐','御定全唐诗','yuding','','[]','濛濛庭樹花，墜地無顏色。日暮東風起，飄揚玉階側。',48,'御定全唐詩/json/383.json','["濛濛庭樹花，墜地無顏色。日暮東風起，飄揚玉階側。", "殘蕊在猶稀，青條聳複直。為君結芳實，令君勿歎息。"]'),
('yuding-12','奉和舍人叔直省時思琴','張籍','唐','御定全唐诗','yuding','','[]','藹藹紫薇直，秋意深無窮。滴瀝仙閣漏，肅穆禁池風。',72,'御定全唐詩/json/383.json','["藹藹紫薇直，秋意深無窮。滴瀝仙閣漏，肅穆禁池風。", "竹月泛涼影，萱露澹幽叢。地清物態勝，宵閑琴思通。", "時屬雅音際，迥凝虛抱中。達人掌樞近，常與隱默同。"]'),
('yuding-13','離婦','張籍','唐','御定全唐诗','yuding','','[]','十載來夫家，閨門無瑕疵。薄命不生子，古制有分離。',204,'御定全唐詩/json/383.json','["十載來夫家，閨門無瑕疵。薄命不生子，古制有分離。", "托身言同穴，今日事乖違。念君終棄捐，誰能強在茲。", "堂上謝姑嫜，長跪請離辭。姑嫜見我往，將決複沉疑。", "與我古時釧，留我嫁時衣。高堂拊我身，哭我于路陲。", "昔日初為婦，當君貧賤時。晝夜常紡織，不得事蛾眉。", "辛勤積黃金，濟君寒與饑。洛陽買大宅，邯鄲買侍兒。", "夫婿乘龍馬，出入有光儀。將為富家婦，永為子孫資。", "誰謂出君門，一身上車歸。有子未必榮，無子坐生悲。", "為人莫作女，作女實難為。"]'),
('yuding-14','懷別','張籍','唐','御定全唐诗','yuding','','[]','僕人驅行軒，低昂出我門。離堂無留客，席上唯琴樽。',96,'御定全唐詩/json/383.json','["僕人驅行軒，低昂出我門。離堂無留客，席上唯琴樽。", "古道隨水曲，悠悠繞荒村。遠程未奄息，別念在朝昏。", "端居愁歲永，獨此留清景。豈無經過人，尋歎門巷靜。", "君如天上雨，我如屋下井。無因同波流，願作形與影。"]'),
('yuding-15','學仙','張籍','唐','御定全唐诗','yuding','','[]','樓觀開朱門，樹木連房廊。中有學仙人，少年休谷糧。',228,'御定全唐詩/json/383.json','["樓觀開朱門，樹木連房廊。中有學仙人，少年休谷糧。", "高冠如芙蓉，霞月披衣裳。六時朝上清，佩玉紛鏘鏘。", "自言天老書，秘覆雲錦囊。百年度一人，妄泄有災殃。", "每佔有仙相，然後傳此方。先生坐中堂，弟子跪四廂。", "金刀截身發，結誓焚靈香。弟子得其訣，清齋入空房。", "守神保元氣，動息隨天罡。爐燒丹砂盡，晝夜候火光。", "藥成既服食，計日乘鸞凰。虛空無靈應，終歲安所望。", "勤勞不能成，疑慮積心腸。虛羸生疾疹，壽命多夭傷。", "身歿懼人見，夜埋山谷傍。求道慕靈異，不如守尋常。", "先王知其非，戒之在國章。"]'),
('yuding-16','夜懷','張籍','唐','御定全唐诗','yuding','','[]','窮居積遠念，轉轉迷所歸。幽蕙零落色，暗螢參差飛。',48,'御定全唐詩/json/383.json','["窮居積遠念，轉轉迷所歸。幽蕙零落色，暗螢參差飛。", "病生秋風簟，淚墮月明衣。無愁坐寂寞，重使奏清徽。"]'),
('yuding-17','城南','張籍','唐','御定全唐诗','yuding','','[]','漾漾南澗水，來作曲池流。言尋參差島，曉榜輕盈舟。',144,'御定全唐詩/json/383.json','["漾漾南澗水，來作曲池流。言尋參差島，曉榜輕盈舟。", "萬繞不再止，千尋盡孤幽。藻澀訝人重，萍分指魚遊。", "繁苗毯下垂，密箭翻回輈。曝鱉亂自墜，陰藤斜相鉤。", "臥蔣黑米吐，翻芰紫角稠。橋低競俯僂，亭近閑夷猶。", "目為逐勝朗，手因掇芳柔。漸喜遊來極，忽疑歸無由。", "氣狀雖可覽，纖微諒難搜。未聽主人賞，徒愛清華秋。"]'),
('yuding-18','懷友','張籍','唐','御定全唐诗','yuding','','[]','人生有行役，誰能如草木。別離感中懷，乃為我桎梏。',120,'御定全唐詩/json/383.json','["人生有行役，誰能如草木。別離感中懷，乃為我桎梏。", "百年受命短，光景良不足。念我別離者，願懷日月促。", "平地施道路，車馬往不復。空知為良田，秋望禾黍熟。", "端居無儔侶，日夜禱耳目。立身難自覺，常恐憂與辱。", "窮賤無閒暇，疾痛多嗜欲。我思攜手人，逍遙任心腹。"]'),
('yuding-19','寄別者','張籍','唐','御定全唐诗','yuding','','[]','寒天正飛雪，行人心切切。同為萬里客，中路忽離別。',84,'御定全唐詩/json/383.json','["寒天正飛雪，行人心切切。同為萬里客，中路忽離別。", "別君汾水東，望君汾水西。積雪無平岡，空山無人蹊。", "羸馬時倚轅，行行未遑食。下車勸僮僕，相顧莫歎息。", "詎知佳期隔，離念終無極。"]'),
('yuding-20','獻從兄','張籍','唐','御定全唐诗','yuding','','[]','悠悠旱天雲，不遠如飛塵。賢達失其所，沉飄同眾人。',120,'御定全唐詩/json/383.json','["悠悠旱天雲，不遠如飛塵。賢達失其所，沉飄同眾人。", "擢秀登王畿，出為良使賓。名高滿朝野，幼賤誰不聞。", "一朝遇讒邪，流竄八九春。詔書近遷移，組綬未及身。", "冬井無寒冰，玉潤難為焚。虛懷日迢遙，榮辱常保純。", "我念出遊時，勿吟康樂文。願言靈溪期，聊欲相依因。"]'),
('yuding-21','寄韓愈','張籍','唐','御定全唐诗','yuding','','[]','野館非我室，新居未能安。讀書避塵雜，方覺此地閑。',132,'御定全唐詩/json/383.json','["野館非我室，新居未能安。讀書避塵雜，方覺此地閑。", "過郭多園墟，桑果相接連。獨遊竟寂寞，如寄空雲山。", "夏景常晝毒，密林無鳴蟬。臨溪一盥濯，清去肢體煩。", "出林望曾城，君子在其間。戎府草章記，阻我此遊盤。", "憶昔西潭時，並持釣魚竿。共忻得魴鯉，烹鱠於我前。", "幾朝還複來，歎息時獨言。"]'),
('yuding-22','贈姚怤','張籍','唐','御定全唐诗','yuding','','[]','漏天日無光，澤土松不長。君今職下位，志氣安得揚。',120,'御定全唐詩/json/383.json','["漏天日無光，澤土松不長。君今職下位，志氣安得揚。", "白髮文思壯，才為國賢良。無人識高韻，薦于天子傍。", "況我愚朴姿，強趨利名場。遠同幹貴人，身舉固難彰。", "昔逢汴水濱，今會習池陽。豈無再來期，顧恐非此方。", "願為石中泉，不為瓦上霜。離別勿複道，所貴不相忘。"]'),
('yuding-23','病中寄白學士拾遺','張籍','唐','御定全唐诗','yuding','','[]','秋亭病客眠，庭樹滿枝蟬。涼風繞砌起，斜影入床前。',96,'御定全唐詩/json/383.json','["秋亭病客眠，庭樹滿枝蟬。涼風繞砌起，斜影入床前。", "梨晚漸紅墜，菊寒無黃鮮。倦遊寂寞日，感歎蹉跎年。", "塵歡久消委，華念獨迎延。自寓城闕下，識君弟事焉。", "君為天子識，我方沉病纏。無因會同語，悄悄中懷煎。"]'),
('yuding-24','雨中寄元宗簡','張籍','唐','御定全唐诗','yuding','','[]','秋堂羸病起，盥漱風雨朝。竹影冷疏澀，榆葉暗飄蕭。',60,'御定全唐詩/json/383.json','["秋堂羸病起，盥漱風雨朝。竹影冷疏澀，榆葉暗飄蕭。", "街徑多墜果，牆隅有蛻蜩。延瞻游步阻，獨坐閑思饒。", "君居應如此，恨言相去遙。"]'),
('yuding-25','野寺後池寄友','張籍','唐','御定全唐诗','yuding','','[]','佛寺連野水，池幽夏景清。繁木蔭芙蕖，時有水禽鳴。',72,'御定全唐詩/json/383.json','["佛寺連野水，池幽夏景清。繁木蔭芙蕖，時有水禽鳴。", "通溪岸暫斷，分渚流複縈。伴僧鐘磬罷，月來池上明。", "友人竟不至，東北見高城。獨遊自寂寞，況此恨盈盈。"]'),
('yuding-26','董公詩','張籍','唐','御定全唐诗','yuding','','[]','誰主東諸侯，元臣隴西公。旌節居汴水，四方皆承風。',360,'御定全唐詩/json/383.json','["誰主東諸侯，元臣隴西公。旌節居汴水，四方皆承風。", "在朝四十年，天下誦其功。相我明天子，政成如太宗。", "東方有艱難，公乃出臨戎。單車入危城，慈惠安群凶。", "公謂其黨言，汝材甚驍雄。為我帳下士，出入衛我躬。", "汝息為我子，汝親我為翁。眾皆相顧泣，無不和且恭。", "其父教子義，其妻勉夫忠。不自以為資，奉上但顒顒。", "公衣無文采，公食少肥濃。所憂在萬人，人實我寧空。", "輕刑寬其政，薄賦弛租庸。四郡三十城，不知歲饑凶。", "天子臨朝喜，元老留在東。今聞揚盛德，就安我大邦。", "百辟賀明主，皇風恩賜重。朝廷有大事，就決其所從。", "海內既無虞，君臣方肅雍。端居任僚屬，宴語常從容。", "翩翩者蒼烏，來巢于林叢。甘瓜生場圃，一蒂實連中。", "田有嘉穀隴，異畝穗亦同。賢人佐聖人，德與神明通。", "感應我淳化，生瑞我地中。昔者此州人，但矜馬與弓。", "今公施德禮，自然威武崇。公其共百年，受祿將無窮。"]'),
('yuding-27','祭退之','張籍','唐','御定全唐诗','yuding','','[]','嗚呼吏部公，其道誠巍昂。生為大賢姿，天使光我唐。',576,'御定全唐詩/json/383.json','["嗚呼吏部公，其道誠巍昂。生為大賢姿，天使光我唐。", "德義動鬼神，鑒用不可詳。獨得雄直氣，發為古文章。", "學無不該貫，吏治得其方。三次論諍退，其志亦剛強。", "再使平山東，不言所謀臧。薦待皆寒羸，但取其才良。", "親朋有孤稚，婚姻有辦營。如彼天有鬥，人可為信常。", "如彼歲有春，物宜得華昌。哀哉未申施，中年遽殂喪。", "朝野良共哀，矧於知舊腸。籍在江湖間，獨以道自將。", "學詩為眾體，久乃溢笈囊。略無相知人，黯如霧中行。", "北遊偶逢公，盛語相稱明。名因天下聞，傳者入歌聲。", "公領試士司，首薦到上京。一來遂登科，不見苦貢場。", "觀我性樸直，乃言及平生。由茲類朋黨，骨肉無以當。", "坐令其子拜，常呼幼時名。追招不隔日，繼踐公之堂。", "出則連轡馳，寢則對榻床。搜窮古今書，事事相酌量。", "有花必同尋，有月必同望。為文先見草，釀熟偕共觴。", "新果及異鮭，無不相待嘗。到今三十年，曾不少異更。", "公文為時師，我亦有微聲。而後之學者，或號為韓張。", "我官麟台中，公為大司成。念此委末秩，不能力自揚。", "特狀為博士，始獲升朝行。未幾享其資，遂忝南宮郎。", "是事賴拯扶，如屋有棟樑。去夏公請告，養疾城南莊。", "籍時官休罷，兩月同遊翔。黃子陂岸曲，地曠氣色清。", "新池四平漲，中有蒲荇香。北台臨稻疇，茂柳多陰涼。", "板亭坐垂釣，煩苦稍已平。共愛池上佳，聯句舒遐情。", "偶有賈秀才，來茲亦同並。移船入南溪，東西縱篙撐。", "劃波激船舷，前後飛鷗鶬。回入潭瀨下，網截鯉與魴。"]'),
('yuding-0','薊北旅思','張籍','唐','御定全唐诗','yuding','','[]','日日望鄉國，空歌白苧詞。長因送人處，憶得別家時。',48,'御定全唐詩/json/384.json','["日日望鄉國，空歌白苧詞。長因送人處，憶得別家時。", "失意還獨語，多愁只自知。客亭門外柳，折盡向南枝。"]'),
('yuding-1','江南春','張籍','唐','御定全唐诗','yuding','','[]','江南楊柳春，日暖地無塵。渡口過新雨，夜來生白蘋。',48,'御定全唐詩/json/384.json','["江南楊柳春，日暖地無塵。渡口過新雨，夜來生白蘋。", "晴沙鳴乳燕，芳樹醉遊人。向晚青山下，誰家祭水神。"]'),
('yuding-2','西樓望月','張籍','唐','御定全唐诗','yuding','','[]','城西樓上月，複是雪晴時。寒夜共來望，思鄉獨下遲。',48,'御定全唐詩/json/384.json','["城西樓上月，複是雪晴時。寒夜共來望，思鄉獨下遲。", "幽光落水塹，淨色在霜枝。明日千里去，此中還別離。"]'),
('yuding-3','別鶴','張籍','唐','御定全唐诗','yuding','','[]','雙鶴出雲溪，分飛各自迷。空巢在松頂，折羽落紅泥。',48,'御定全唐詩/json/384.json','["雙鶴出雲溪，分飛各自迷。空巢在松頂，折羽落紅泥。", "尋水終不飲，逢林亦未棲。別離應易老，萬里雨淒淒。"]'),
('yuding-4','江陵孝女','張籍','唐','御定全唐诗','yuding','','[]','孝女獨垂發，少年唯一身。無家空托墓，主祭不從人。',48,'御定全唐詩/json/384.json','["孝女獨垂發，少年唯一身。無家空托墓，主祭不從人。", "相吊有行客，起廬無舊鄰。江頭聞哭處，寂寂楚花春。"]'),
('yuding-5','山中古祠','張籍','唐','御定全唐诗','yuding','','[]','春草空祠墓，荒林唯鳥飛。記年碑石在，經亂祭人稀。',48,'御定全唐詩/json/384.json','["春草空祠墓，荒林唯鳥飛。記年碑石在，經亂祭人稀。", "野鼠緣朱帳，陰塵蓋畫衣。近門潭水黑，時見宿龍歸。"]'),
('yuding-6','漁陽將','張籍','唐','御定全唐诗','yuding','','[]','塞深沙草白，都護領燕兵。放火燒奚帳，分旗築漢城。',48,'御定全唐詩/json/384.json','["塞深沙草白，都護領燕兵。放火燒奚帳，分旗築漢城。", "下營看嶺勢，尋雪覺人行。更向桑幹北，擒生問磧名。"]'),
('yuding-7','聽夜泉','張籍','唐','御定全唐诗','yuding','','[]','細泉深處落，夜久漸聞聲。獨起出門聽，欲尋當澗行。',48,'御定全唐詩/json/384.json','["細泉深處落，夜久漸聞聲。獨起出門聽，欲尋當澗行。", "還疑隔林遠，複畏有風生。月下長來此，無人亦到明。"]'),
('yuding-8','送南遷客','張籍','唐','御定全唐诗','yuding','','[]','去去遠遷客，瘴中衰病身。青山無限路，白首不歸人。',48,'御定全唐詩/json/384.json','["去去遠遷客，瘴中衰病身。青山無限路，白首不歸人。", "海國戰騎象，蠻州市用銀。一家分幾處，誰見日南春。"]'),
('yuding-9','薊北春懷','張籍','唐','御定全唐诗','yuding','','[]','渺渺水雲外，別來音信稀。因逢過江使，卻寄在家衣。',48,'御定全唐詩/json/384.json','["渺渺水雲外，別來音信稀。因逢過江使，卻寄在家衣。", "問路更愁遠，逢人空說歸。今朝薊城北，又見塞鴻飛。"]'),
('yuding-10','思遠人','張籍','唐','御定全唐诗','yuding','','[]','野橋春水清，橋上送君行。去去人應老，年年草自生。',48,'御定全唐詩/json/384.json','["野橋春水清，橋上送君行。去去人應老，年年草自生。", "出門看遠道，無信向邊城。楊柳別離處，秋蟬今複鳴。"]'),
('yuding-11','贈同溪客','張籍','唐','御定全唐诗','yuding','','[]','幽居得相近，煙景每寥寥。共伐臨溪樹，因為過水橋。',48,'御定全唐詩/json/384.json','["幽居得相近，煙景每寥寥。共伐臨溪樹，因為過水橋。", "自教青鶴舞，分采紫芝苗。更愛南峰住，尋君路恐遙。"]'),
('yuding-12','望行人','張籍','唐','御定全唐诗','yuding','','[]','秋風窗下起，旅雁向南飛。日日出門望，家家行客歸。',48,'御定全唐詩/json/384.json','["秋風窗下起，旅雁向南飛。日日出門望，家家行客歸。", "無因見邊使，空待寄寒衣。獨倚青樓暮，煙深鳥雀稀。"]'),
('yuding-13','送宮人入道','張籍','唐','御定全唐诗','yuding','','[]','舊寵昭陽裏，尋仙此最稀。名初出宮籍，身未稱霞衣。',48,'御定全唐詩/json/384.json','["舊寵昭陽裏，尋仙此最稀。名初出宮籍，身未稱霞衣。", "已別歌舞貴，長隨鸞鶴飛。中官看入洞，空駕玉輪歸。"]'),
('yuding-14','送越客','張籍','唐','御定全唐诗','yuding','','[]','見說孤帆去，東南到會稽。春雲剡溪口，殘月鏡湖西。',48,'御定全唐詩/json/384.json','["見說孤帆去，東南到會稽。春雲剡溪口，殘月鏡湖西。", "水鶴沙邊立，山鼯竹裏啼。謝家曾住處，煙洞入應迷。"]'),
('yuding-15','贈辟谷者','張籍','唐','御定全唐诗','yuding','','[]','學得餐霞法，逢人與小還。身輕曾試鶴，力弱未離山。',48,'御定全唐詩/json/384.json','["學得餐霞法，逢人與小還。身輕曾試鶴，力弱未離山。", "無食犬猶在，不耕牛自閑。朝朝空漱水，叩齒草堂間。"]'),
('yuding-16','思江南舊游','張籍','唐','御定全唐诗','yuding','','[]','江皋三月時，花發石楠枝。歸客應無數，春山自不知。',48,'御定全唐詩/json/384.json','["江皋三月時，花發石楠枝。歸客應無數，春山自不知。", "獨行愁道遠，回信畏家移。楊柳東西渡，茫茫欲問誰。"]'),
('yuding-17','夜到漁家','張籍','唐','御定全唐诗','yuding','','[]','漁家在江口，潮水入柴扉。行客欲投宿，主人猶未歸。',48,'御定全唐詩/json/384.json','["漁家在江口，潮水入柴扉。行客欲投宿，主人猶未歸。", "竹深村路遠，月出釣船稀。遙見尋沙岸，春風動草衣。"]'),
('yuding-18','送遠使','張籍','唐','御定全唐诗','yuding','','[]','揚旌過隴頭，隴水向西流。塞路依山遠，戍城逢笛秋。',48,'御定全唐詩/json/384.json','["揚旌過隴頭，隴水向西流。塞路依山遠，戍城逢笛秋。", "寒沙陰漫漫，疲馬去悠悠。為問征行將，誰封定遠侯。"]'),
('yuding-19','不食姑','張籍','唐','御定全唐诗','yuding','','[]','幾年山裏住，已作綠毛身。護氣常稀語，存思自見神。',48,'御定全唐詩/json/384.json','["幾年山裏住，已作綠毛身。護氣常稀語，存思自見神。", "養龜同不食，留藥任生塵。要問西王母，仙中第幾人。"]'),
('yuding-20','古苑杏花','張籍','唐','御定全唐诗','yuding','','[]','廢苑杏花在，行人愁到時。獨開新塹底，半露舊燒枝。',48,'御定全唐詩/json/384.json','["廢苑杏花在，行人愁到時。獨開新塹底，半露舊燒枝。", "晚色連荒轍，低陰覆折碑。茫茫古陵下，春盡又誰知。"]'),
('yuding-21','送流人','張籍','唐','御定全唐诗','yuding','','[]','獨向長城北，黃雲暗塞天。流名屬邊將，舊業作公田。',48,'御定全唐詩/json/384.json','["獨向長城北，黃雲暗塞天。流名屬邊將，舊業作公田。", "擁雪添軍壘，收冰當井泉。知君住應老，須記別鄉年。"]'),
('yuding-22','宿臨江驛','張籍','唐','御定全唐诗','yuding','','[]','楚驛南渡口，夜深來客稀。月明見潮上，江靜覺鷗飛。',48,'御定全唐詩/json/384.json','["楚驛南渡口，夜深來客稀。月明見潮上，江靜覺鷗飛。", "旅宿今已遠，此行殊未歸。離家久無信，又聽搗寒衣。"]'),
('yuding-23','送蠻客','張籍','唐','御定全唐诗','yuding','','[]','借問炎州客，天南幾日行。江連惡溪路，山繞夜郎城。',48,'御定全唐詩/json/384.json','["借問炎州客，天南幾日行。江連惡溪路，山繞夜郎城。", "柳葉瘴雲濕，桂叢蠻鳥聲。知君卻回日，記得海花名。"]'),
('yuding-24','襄國別友','張籍','唐','御定全唐诗','yuding','','[]','曉色荒城下，相看秋草時。獨遊無定計，不欲道來期。',48,'御定全唐詩/json/384.json','["曉色荒城下，相看秋草時。獨遊無定計，不欲道來期。", "別處去家遠，愁中驅馬遲。歸人渡煙水，遙映野棠枝。"]'),
('yuding-25','送遠客','張籍','唐','御定全唐诗','yuding','','[]','南原相送處，秋水草還生。同作憶鄉客，如今分路行。',48,'御定全唐詩/json/384.json','["南原相送處，秋水草還生。同作憶鄉客，如今分路行。", "因誰寄歸信，漸遠問前程。明日重陽節，無人上古城。"]'),
('yuding-26','山中贈日南僧','張籍','唐','御定全唐诗','yuding','','[]','獨向雙峰老，松門閉兩崖。翻經上蕉葉，掛衲落藤花。',48,'御定全唐詩/json/384.json','["獨向雙峰老，松門閉兩崖。翻經上蕉葉，掛衲落藤花。", "甃石新開井，穿林自種茶。時逢海南客，蠻語問誰家。"]'),
('yuding-27','征西將','張籍','唐','御定全唐诗','yuding','','[]','黃沙北風起，半夜又翻營。戰馬雪中宿，探人冰上行。',48,'御定全唐詩/json/384.json','["黃沙北風起，半夜又翻營。戰馬雪中宿，探人冰上行。", "深山旗未展，陰磧鼓無聲。幾道征西將，同收碎葉城。"]'),
('yuding-28','寄友人','張籍','唐','御定全唐诗','yuding','','[]','憶在江南日，同游三月時。採茶尋遠澗，鬥鴨向春池。',48,'御定全唐詩/json/384.json','["憶在江南日，同游三月時。採茶尋遠澗，鬥鴨向春池。", "送客沙頭宿，招僧竹裏棋。如今各千里，無計得相隨。"]'),
('yuding-29','送防秋將','張籍','唐','御定全唐诗','yuding','','[]','白首征西將，猶能射戟支。元戎選部曲，軍吏換旌旗。',48,'御定全唐詩/json/384.json','["白首征西將，猶能射戟支。元戎選部曲，軍吏換旌旗。", "逐虜招降遠，開邊舊壘移。重收隴外地，應似漢家時。"]'),
('yuding-30','律僧','張籍','唐','御定全唐诗','yuding','','[]','苦行長不出，清羸最少年。持齋唯一食，講律豈曾眠。',48,'御定全唐詩/json/384.json','["苦行長不出，清羸最少年。持齋唯一食，講律豈曾眠。", "避草每移徑，濾蟲還入泉。從來天竺法，到此幾人傳。"]'),
('yuding-31','山中秋夜','張籍','唐','御定全唐诗','yuding','','[]','寂寂山景靜，幽人歸去遲。橫琴當月下，壓酒及花時。',48,'御定全唐詩/json/384.json','["寂寂山景靜，幽人歸去遲。橫琴當月下，壓酒及花時。", "冷露濕茆屋，暗泉沖竹籬。西峰采藥伴，此夕恨無期。"]'),
('yuding-32','送南客','張籍','唐','御定全唐诗','yuding','','[]','行路雨修修，青山盡海頭。天涯人去遠，嶺北水空流。',48,'御定全唐詩/json/384.json','["行路雨修修，青山盡海頭。天涯人去遠，嶺北水空流。", "夜市連銅柱，巢居屬象州。來時舊相識，誰向日南遊。"]'),
('yuding-33','宿江店','張籍','唐','御定全唐诗','yuding','','[]','野店臨西浦，門前有橘花。停燈待賈客，賣酒與漁家。',48,'御定全唐詩/json/384.json','["野店臨西浦，門前有橘花。停燈待賈客，賣酒與漁家。", "夜靜江水白，路回山月斜。閑尋泊船處，潮落見平沙。"]'),
('yuding-34','嶺表逢故人','張籍','唐','御定全唐诗','yuding','','[]','過嶺萬餘裏，旅遊經此稀。相逢去家遠，共說幾時歸。',48,'御定全唐詩/json/384.json','["過嶺萬餘裏，旅遊經此稀。相逢去家遠，共說幾時歸。", "海上見花發，瘴中唯鳥飛。炎州望鄉伴，自識北人衣。"]'),
('yuding-35','出塞','張籍','唐','御定全唐诗','yuding','','[]','秋塞雪初下，將軍遠出師。分營長記火，放馬不收旗。',48,'御定全唐詩/json/384.json','["秋塞雪初下，將軍遠出師。分營長記火，放馬不收旗。", "月冷邊帳濕，沙昏夜探遲。征人皆白首，誰見滅胡時。"]'),
('yuding-36','寄紫閣隱者','張籍','唐','御定全唐诗','yuding','','[]','紫閣氣沉沉，先生住處深。有人時得見，無路可相尋。',48,'御定全唐詩/json/384.json','["紫閣氣沉沉，先生住處深。有人時得見，無路可相尋。", "夜鹿伴茅屋，秋猿守栗林。唯應采靈藥，更不別營心。"]'),
('yuding-37','夜宿黑灶溪','張籍','唐','御定全唐诗','yuding','','[]','夜到碧溪裏，無人秋月明。逢幽更移宿，取伴亦探行。',48,'御定全唐詩/json/384.json','["夜到碧溪裏，無人秋月明。逢幽更移宿，取伴亦探行。", "花下紅泉色，雲西乳鶴聲。明朝記歸處，石上自書名。"]'),
('yuding-38','古樹','張籍','唐','御定全唐诗','yuding','','[]','古樹枝柯少，枯來複幾春。露根堪系馬，空腹定藏人。',48,'御定全唐詩/json/384.json','["古樹枝柯少，枯來複幾春。露根堪系馬，空腹定藏人。", "蠹節莓苔老，燒痕霹靂新。若當江浦上，行客祭為神。"]'),
('yuding-39','送徐先生歸蜀','張籍','唐','御定全唐诗','yuding','','[]','日暮遠歸處，雲間仙觀鐘。唯持青玉牒，獨立碧雞峰。',48,'御定全唐詩/json/384.json','["日暮遠歸處，雲間仙觀鐘。唯持青玉牒，獨立碧雞峰。", "陰澗長收乳，寒泉舊養龍。幾時因賣藥，得向海邊逢。"]'),
('yuding-40','隱者','張籍','唐','御定全唐诗','yuding','','[]','先生已得道，市井亦容身。救病自行藥，得錢多與人。',48,'御定全唐詩/json/384.json','["先生已得道，市井亦容身。救病自行藥，得錢多與人。", "問年長不定，傳法又非真。每見鄰家說，時聞使鬼神。"]'),
('yuding-41','送友人歸山','張籍','唐','御定全唐诗','yuding','','[]','出山成北首，重去結茅廬。移石修廢井，掃龕盛舊書。',48,'御定全唐詩/json/384.json','["出山成北首，重去結茅廬。移石修廢井，掃龕盛舊書。", "開田留杏樹，分洞與僧居。長在幽峰裏，樵人見亦疏。"]'),
('yuding-42','霅溪西亭晚望','張籍','唐','御定全唐诗','yuding','','[]','霅水碧悠悠，西亭柳岸頭。夕陰生遠岫，斜照逐回流。',48,'御定全唐詩/json/384.json','["霅水碧悠悠，西亭柳岸頭。夕陰生遠岫，斜照逐回流。", "此地動歸思，逢人方倦遊。吳興耆舊盡，空見白蘋洲。"]'),
('yuding-43','哭山中友人','張籍','唐','御定全唐诗','yuding','','[]','入雲遙便哭，山友隔今生。繞墓招魂魄，鐫岩記姓名。',48,'御定全唐詩/json/384.json','["入雲遙便哭，山友隔今生。繞墓招魂魄，鐫岩記姓名。", "犬因無主善，鶴為見人鳴。長說能屍解，多應別路行。"]'),
('yuding-44','答僧拄杖','張籍','唐','御定全唐诗','yuding','','[]','靈藤為拄杖，白淨色如銀。得自高僧手，將扶病客身。',48,'御定全唐詩/json/384.json','["靈藤為拄杖，白淨色如銀。得自高僧手，將扶病客身。", "春遊不騎馬，夜會亦呈人。持此歸山去，深宜戴角巾。"]'),
('yuding-45','靈都觀李道士','張籍','唐','御定全唐诗','yuding','','[]','仙觀雨來靜，繞房瓊草春。素書天上字，花洞古時人。',48,'御定全唐詩/json/384.json','["仙觀雨來靜，繞房瓊草春。素書天上字，花洞古時人。", "泥灶煮靈液，掃壇朝玉真。幾回游閬苑，青節亦隨身。"]'),
('yuding-46','送韋評事歸華陰','張籍','唐','御定全唐诗','yuding','','[]','三峰西面住，出見世人稀。老大誰相識，恓惶又獨歸。',48,'御定全唐詩/json/384.json','["三峰西面住，出見世人稀。老大誰相識，恓惶又獨歸。", "掃窗秋菌落，開篋夜蛾飛。若向雲中伴，還應著褐衣。"]'),
('yuding-47','送閩僧','張籍','唐','御定全唐诗','yuding','','[]','幾夏京城住，今朝獨遠歸。修行四分律，護淨七條衣。',48,'御定全唐詩/json/384.json','["幾夏京城住，今朝獨遠歸。修行四分律，護淨七條衣。", "溪寺黃橙熟，沙田紫芋肥。九龍潭上路，同去客應稀。"]'),
('yuding-48','送海南客歸舊島','張籍','唐','御定全唐诗','yuding','','[]','海上去應遠，蠻家雲島孤。竹船來桂浦，山市賣魚須。',48,'御定全唐詩/json/384.json','["海上去應遠，蠻家雲島孤。竹船來桂浦，山市賣魚須。", "入國自獻寶，逢人多贈珠。卻歸春洞口，斬象祭天吳。"]'),
('yuding-49','登咸陽北寺樓','張籍','唐','御定全唐诗','yuding','','[]','高秋原上寺，下馬一登臨。渭水西來直，秦山南向深。',48,'御定全唐詩/json/384.json','["高秋原上寺，下馬一登臨。渭水西來直，秦山南向深。", "舊宮人不住，荒碣路難尋。日暮涼風起，蕭條多遠心。"]'),
('yuding-50','送新羅使','張籍','唐','御定全唐诗','yuding','','[]','萬里為朝使，離家今幾年。應知舊行路，卻上遠歸船。',48,'御定全唐詩/json/384.json','["萬里為朝使，離家今幾年。應知舊行路，卻上遠歸船。", "夜泊避蛟窟，朝炊求島泉。悠悠到鄉國，遠望海西天。"]'),
('yuding-51','宿廣德寺寄從舅','張籍','唐','御定全唐诗','yuding','','[]','古寺客堂空，開簾四面風。移床動棲鶴，停燭聚飛蟲。',48,'御定全唐詩/json/384.json','["古寺客堂空，開簾四面風。移床動棲鶴，停燭聚飛蟲。", "閑臥逐涼處，遠愁生靜中。林西微月色，思與寧家同。"]'),
('yuding-52','宿邯鄲館寄馬磁州','張籍','唐','御定全唐诗','yuding','','[]','孤客到空館，夜寒愁臥遲。雖沽主人酒，不似在家時。',48,'御定全唐詩/json/384.json','["孤客到空館，夜寒愁臥遲。雖沽主人酒，不似在家時。", "幾宿得歡笑，如今成別離。明朝行更遠，回望隔山陂。"]'),
('yuding-53','舟行寄李湖州','張籍','唐','御定全唐诗','yuding','','[]','客愁無次第，川路重辛勤。藻密行舟澀，灣多轉楫頻。',48,'御定全唐詩/json/384.json','["客愁無次第，川路重辛勤。藻密行舟澀，灣多轉楫頻。", "薄游空感惠，失計自憐貧。賴有汀洲句，時時慰遠人。"]'),
('yuding-54','送閑師歸江南','張籍','唐','御定全唐诗','yuding','','[]','遍住江南寺，隨緣到上京。多生修律業，外學得詩名。',48,'御定全唐詩/json/384.json','["遍住江南寺，隨緣到上京。多生修律業，外學得詩名。", "講殿偏追入，齋家別請行。青楓鄉路遠，幾日盡歸程。"]'),
('yuding-55','遊襄陽山寺','張籍','唐','御定全唐诗','yuding','','[]','秋色江邊路，煙霞若有期。寺貧無利施，僧老足慈悲。',48,'御定全唐詩/json/384.json','["秋色江邊路，煙霞若有期。寺貧無利施，僧老足慈悲。", "薜荔侵禪窟，蝦蟆占浴池。閒遊殊未遍，即是下山時。"]'),
('yuding-56','登城寄王秘書建','張籍','唐','御定全唐诗','yuding','','[]','聞君鶴嶺住，西望日依依。遠客偏相憶，登城獨不歸。',48,'御定全唐詩/json/384.json','["聞君鶴嶺住，西望日依依。遠客偏相憶，登城獨不歸。", "十年為道侶，幾處共柴扉。今日煙霞外，人間得見稀。"]'),
('yuding-57','送從弟戴玄往蘇州','張籍','唐','御定全唐诗','yuding','','[]','楊柳閶門路，悠悠水岸斜。乘舟向山寺，著屐到漁家。',48,'御定全唐詩/json/384.json','["楊柳閶門路，悠悠水岸斜。乘舟向山寺，著屐到漁家。", "夜月紅柑樹，秋風白藕花。江天詩景好，回日莫令賒。"]'),
('yuding-58','送朱慶餘及第歸越','張籍','唐','御定全唐诗','yuding','','[]','東南歸路遠，幾日到鄉中。有寺山皆遍，無家水不通。',48,'御定全唐詩/json/384.json','["東南歸路遠，幾日到鄉中。有寺山皆遍，無家水不通。", "湖聲蓮葉雨，野氣稻花風。州縣知名久，爭邀與客同。"]'),
('yuding-59','過賈島野居','張籍','唐','御定全唐诗','yuding','','[]','青門坊外住，行坐見南山。此地去人遠，知君終日閑。',48,'御定全唐詩/json/384.json','["青門坊外住，行坐見南山。此地去人遠，知君終日閑。", "蛙聲籬落下，草色戶庭間。好是經過處，唯愁暮獨還。"]'),
('yuding-60','酬韓庶子','張籍','唐','御定全唐诗','yuding','','[]','西街幽僻處，正與懶相宜。尋寺獨行遠，借書常送遲。',48,'御定全唐詩/json/384.json','["西街幽僻處，正與懶相宜。尋寺獨行遠，借書常送遲。", "家貧無易事，身病足閒時。寂寞誰相問，只應君自知。"]'),
('yuding-61','贈姚合少府','張籍','唐','御定全唐诗','yuding','','[]','病來辭赤縣，案上有丹經。為客燒茶灶，教兒掃竹亭。',48,'御定全唐詩/json/384.json','["病來辭赤縣，案上有丹經。為客燒茶灶，教兒掃竹亭。", "詩成添舊卷，酒盡臥空瓶。闕下今遺逸，誰瞻隱士星。"]'),
('yuding-62','送僧遊五台兼謁李司空','張籍','唐','御定全唐诗','yuding','','[]','遠去見雙節，因行上五台。化樓侵曉出，雪路向春開。',48,'御定全唐詩/json/384.json','["遠去見雙節，因行上五台。化樓侵曉出，雪路向春開。", "邊寺連峰去，胡兒聽法來。定知巡禮後，解夏始應回。"]'),
('yuding-63','送鄭秀才歸甯','張籍','唐','御定全唐诗','yuding','','[]','桂楫彩為衣，行當令節歸。夕潮迷浦遠，晝雨見人稀。',48,'御定全唐詩/json/384.json','["桂楫彩為衣，行當令節歸。夕潮迷浦遠，晝雨見人稀。", "野芰到時熟，江鷗泊處飛。離琴一奏罷，山雨靄餘暉。"]'),
('yuding-64','送李評事游越','張籍','唐','御定全唐诗','yuding','','[]','未習風塵事，初為吳越遊。露沾湖草晚，日照海山秋。',48,'御定全唐詩/json/384.json','["未習風塵事，初為吳越遊。露沾湖草晚，日照海山秋。", "梅市門何在，蘭亭水尚流。西陵待潮處，知汝不勝愁。"]'),
('yuding-65','夏日閒居','張籍','唐','御定全唐诗','yuding','','[]','無事門多閉，偏知夏日長。早蟬聲寂寞，新竹氣清涼。',48,'御定全唐詩/json/384.json','["無事門多閉，偏知夏日長。早蟬聲寂寞，新竹氣清涼。", "閑對臨書案，看移曬藥床。自憐歸未得，猶寄在班行。"]'),
('yuding-66','閒居','張籍','唐','御定全唐诗','yuding','','[]','東城南陌塵，紫幰與朱輪。盡說無多事，能閑有幾人。',48,'御定全唐詩/json/384.json','["東城南陌塵，紫幰與朱輪。盡說無多事，能閑有幾人。", "唯教推甲子，不信守庚申。誰見衡門裏，終朝自在貧。"]'),
('yuding-67','寄昭應王中丞','張籍','唐','御定全唐诗','yuding','','[]','借得街西宅，開門渭水頭。長貧唯要健，漸老不禁愁。',48,'御定全唐詩/json/384.json','["借得街西宅，開門渭水頭。長貧唯要健，漸老不禁愁。", "獨憑藤書案，空懸竹酒鉤。春風石甕寺，作意共君遊。"]'),
('yuding-68','酬孫洛陽','張籍','唐','御定全唐诗','yuding','','[]','家貧相遠住，齋館入時稀。獨坐看書卷，閑行著褐衣。',48,'御定全唐詩/json/384.json','["家貧相遠住，齋館入時稀。獨坐看書卷，閑行著褐衣。", "早蟬庭筍老，新雨徑莎肥。各離爭名地，無人見是非。"]'),
('yuding-69','送人任濟陰','張籍','唐','御定全唐诗','yuding','','[]','黃綬在腰下，知君非旅行。將書報舊裏，留褐與諸生。',48,'御定全唐詩/json/384.json','["黃綬在腰下，知君非旅行。將書報舊裏，留褐與諸生。", "贈別盡沽酒，惜歡多出城。春風濟水上，候吏聽車聲。"]'),
('yuding-70','晚春過崔駙馬東園','張籍','唐','御定全唐诗','yuding','','[]','閑園多好風，不意在街東。早早詩名遠，長長酒性同。',48,'御定全唐詩/json/384.json','["閑園多好風，不意在街東。早早詩名遠，長長酒性同。", "竹香新雨後，鶯語落花中。莫遣經過少，年光漸覺空。"]'),
('yuding-71','夏日閒居','張籍','唐','御定全唐诗','yuding','','[]','多病逢迎少，閒居又一年。藥看辰日合，茶過卯時煎。',48,'御定全唐詩/json/384.json','["多病逢迎少，閒居又一年。藥看辰日合，茶過卯時煎。", "草長晴來地，蟲飛晚後天。此時幽夢遠，不覺到山邊。"]'),
('yuding-72','晚秋閒居','張籍','唐','御定全唐诗','yuding','','[]','獨坐高秋晚，蕭條足遠思。家貧常畏客，身老轉憐兒。',48,'御定全唐詩/json/384.json','["獨坐高秋晚，蕭條足遠思。家貧常畏客，身老轉憐兒。", "萬種盡閒事，一生能幾時。從來疏懶性，應只有僧知。"]'),
('yuding-73','和陸司業習靜寄所知','張籍','唐','御定全唐诗','yuding','','[]','幽室獨焚香，清晨下未央。山開登竹閣，僧到出茶床。',48,'御定全唐詩/json/384.json','["幽室獨焚香，清晨下未央。山開登竹閣，僧到出茶床。", "收拾新琴譜，封題舊藥方。逍遙無別事，不似在班行。"]'),
('yuding-74','酬韓祭酒雨中見寄','張籍','唐','御定全唐诗','yuding','','[]','雨中愁不出，陰黑盡連宵。屋濕唯添漏，泥深未放朝。',48,'御定全唐詩/json/384.json','["雨中愁不出，陰黑盡連宵。屋濕唯添漏，泥深未放朝。", "無芻憐馬瘦，少食信兒嬌。聞道韓夫子，還同此寂寥。"]'),
('yuding-75','和裴僕射移官言志','張籍','唐','御定全唐诗','yuding','','[]','身在勤勞地，常思放曠時。功成歸聖主，位重委群司。',48,'御定全唐詩/json/384.json','["身在勤勞地，常思放曠時。功成歸聖主，位重委群司。", "看壘台邊石，閑吟篋裏詩。蒼生正瞻望，難與故山期。"]'),
('yuding-76','酬白二十二舍人早春曲江見招','張籍','唐','御定全唐诗','yuding','','[]','曲江冰欲盡，風日已恬和。柳色看猶淺，泉聲覺漸多。',48,'御定全唐詩/json/384.json','["曲江冰欲盡，風日已恬和。柳色看猶淺，泉聲覺漸多。", "紫蒲生濕岸，青鴨戲新波。仙掖高情客，相招共一過。"]'),
('yuding-77','和裴僕射朝回寄韓吏部','張籍','唐','御定全唐诗','yuding','','[]','獨愛南關裏，山晴竹杪風。從容朝早退，蕭灑客常通。',48,'御定全唐詩/json/384.json','["獨愛南關裏，山晴竹杪風。從容朝早退，蕭灑客常通。", "案曲新亭上，移花遠寺中。唯應有吏部，詩酒每相同。"]'),
('yuding-78','春日李舍人宅見兩省諸公唱和，因書情即事','張籍','唐','御定全唐诗','yuding','','[]','又見帝城裏，東風天氣和。官閒人事少，年長道情多。',48,'御定全唐詩/json/384.json','["又見帝城裏，東風天氣和。官閒人事少，年長道情多。", "紫掖發章句，青闈更詠歌。誰知餘寂寞，終日斷經過。"]'),
('yuding-79','和李僕射秋日病中作','張籍','唐','御定全唐诗','yuding','','[]','由來病根淺，易見藥功成。曉日杵臼靜，涼風衣服輕。',48,'御定全唐詩/json/384.json','["由來病根淺，易見藥功成。曉日杵臼靜，涼風衣服輕。", "猶疑少氣力，漸覺有心情。獨倚紅藤杖，時時階上行。"]'),
('yuding-80','早春病中','張籍','唐','御定全唐诗','yuding','','[]','羸病及年初，心情不自如。多申請假牒，只送賀官書。',48,'御定全唐詩/json/384.json','["羸病及年初，心情不自如。多申請假牒，只送賀官書。", "幽徑獨行步，白頭長懶梳。更憐晴日色，漸漸暖貧居。"]'),
('yuding-81','送嚴大夫之桂州','張籍','唐','御定全唐诗','yuding','','[]','旌旆過湘潭，幽奇得遍探。莎城百越北，行路九疑南。',48,'御定全唐詩/json/384.json','["旌旆過湘潭，幽奇得遍探。莎城百越北，行路九疑南。", "有地多生桂，無時不養蠶。聽歌疑似曲，風俗自相諳。"]'),
('yuding-82','詠懷','張籍','唐','御定全唐诗','yuding','','[]','老去多悲事，非唯見二毛。眼昏書字大，耳重覺聲高。',48,'御定全唐詩/json/384.json','["老去多悲事，非唯見二毛。眼昏書字大，耳重覺聲高。", "望月偏增思，尋山易發勞。都無作官意，賴得在閑曹。"]'),
('yuding-83','使至藍溪驛，寄太常王丞','張籍','唐','御定全唐诗','yuding','','[]','獨上七盤去，峰巒轉轉稠。雲中迷象鼻，雨裏下箏頭。',48,'御定全唐詩/json/384.json','["獨上七盤去，峰巒轉轉稠。雲中迷象鼻，雨裏下箏頭。", "水沒荒橋路，鴉啼古驛樓。君今在城闕，肯見此中愁。"]'),
('yuding-84','留別江陵王少府','張籍','唐','御定全唐诗','yuding','','[]','迢迢山上路，病客獨行遲。況此分手處，當君失意時。',48,'御定全唐詩/json/384.json','["迢迢山上路，病客獨行遲。況此分手處，當君失意時。", "寒林遠路驛，晚燒過荒陂。別後空回首，相逢未有期。"]'),
('yuding-85','贈海東僧','張籍','唐','御定全唐诗','yuding','','[]','別家行萬里，自說過扶餘。學得中州語，能為外國書。',48,'御定全唐詩/json/384.json','["別家行萬里，自說過扶餘。學得中州語，能為外國書。", "與醫收海藻，持咒取龍魚。更問同來伴，天臺幾處居。"]');
